-- Poems batch 194
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1061c743-cd00-4851-a93e-cd57f963081a','謝人遺酥','陳宓','宋','宋诗','song-poetry','','[]','廣寒春雪不能融，留得仙娥素手巾。',64,'全唐诗/poet.song.185000.json','["廣寒春雪不能融，留得仙娥素手巾。", "白玉加香差可比，冰清乏潤遠難同。", "休將姹女涂丹臉，宜爲儒生沃寸衷。", "多謝王公情不薄，筠籃特爲故人東。"]'),
('671d7a52-bd38-423a-8376-390f8ded7499','謾題','陳宓','宋','宋诗','song-poetry','','[]','胸襟但貯五千卷，意慮曾無分寸私。',32,'全唐诗/poet.song.185000.json','["胸襟但貯五千卷，意慮曾無分寸私。", "歎老嗟卑真淺士，古人心事有誰知。"]'),
('9e91c8ce-d528-4e37-bc90-04f4e3e9cfc8','中秋桐城觀舉子','陳宓','宋','宋诗','song-poetry','','[]','風前散袂能忘扇，月下題詩不用燈。',32,'全唐诗/poet.song.185000.json','["風前散袂能忘扇，月下題詩不用燈。", "萬士清宵鏖棘廡，一年秋色滿桐城。"]'),
('147b0586-2c9f-4a76-9c86-be0916d065ed','到九座','陳宓','宋','宋诗','song-poetry','','[]','想像精藍九疊前，青鞋今得踏雲烟。',64,'全唐诗/poet.song.185000.json','["想像精藍九疊前，青鞋今得踏雲烟。", "霜邊澗水多成玉，嶺上人家半是仙。", "伏蟒千年無動意，老松何日不幽禪。", "可憐倚馬思歸客，有底區中未了緣。"]'),
('c8a282cb-d0ac-48ed-9c2b-742cc5cd306a','暮宿化成庵','陳宓','宋','宋诗','song-poetry','','[]','雨近祇從簷角起，雲濃不蔽月華明。',64,'全唐诗/poet.song.185000.json','["雨近祇從簷角起，雲濃不蔽月華明。", "佛燈一點冰同冷，酒盞三行茗漾清。", "僮僕倦羸聞鼻息，友朋笑語愜衷情。", "齋厨夜半無留火，不待晨鷄接淅行。"]'),
('a189929a-106c-4d9d-812e-69b3a46c3957','建陽道','陳宓','宋','宋诗','song-poetry','','[]','五月平疇不得犁，青秧老處坼於龜。',32,'全唐诗/poet.song.185000.json','["五月平疇不得犁，青秧老處坼於龜。", "乾坤惠愛無遺物，仰乳嬰兒可使饑。"]'),
('30953114-e493-41a6-9add-cde2d30a342c','和晦庵壁間韵','陳宓','宋','宋诗','song-poetry','','[]','著壁驪珠五月寒，行人到此泣闌干。',32,'全唐诗/poet.song.185000.json','["著壁驪珠五月寒，行人到此泣闌干。", "亭前好景慵回首，恐跨征鞍不得看。"]'),
('d4f26ee7-a978-408d-92e4-deec60e58628','閏月五日題武夷  其一','陳宓','宋','宋诗','song-poetry','','[]','武夷精舍果何如，名字流傳動八區。',32,'全唐诗/poet.song.185000.json','["武夷精舍果何如，名字流傳動八區。", "大隠山前溪五曲，一間茅屋與誰居。"]'),
('d58f7ec2-b903-485c-aa13-f5c854d01e43','閏月五日題武夷  其二','陳宓','宋','宋诗','song-poetry','','[]','不見山居二十年，蒼髯玉面故依然。',32,'全唐诗/poet.song.185000.json','["不見山居二十年，蒼髯玉面故依然。", "它年我定先君老，準擬虛名共久傳。"]'),
('f3b5f792-5cda-4de6-85c4-98c3ca81a546','閏月五日題武夷  其三','陳宓','宋','宋诗','song-poetry','','[]','不知列岫何年有，應費神功妙剸裁。',32,'全唐诗/poet.song.185000.json','["不知列岫何年有，應費神功妙剸裁。", "怪怪奇奇人莫問，媧皇曾把補天來。"]'),
('8de6dbf1-92d7-4dee-91e0-beae8efa156c','碧潭奇觀','陳宓','宋','宋诗','song-poetry','','[]','賸得浮生十日閑，一逢勝處便凭欄。',64,'全唐诗/poet.song.185000.json','["賸得浮生十日閑，一逢勝處便凭欄。", "天開池沼供魚樂，雨洗峰巒與客看。", "活計祇須携蒻笠，謀身空嘆負儒冠。", "試聽磯上垂綸叟，不信人間有熱官。"]'),
('0cc1f3ac-788c-4309-a964-7e29c7971e1f','抵邑示景山','陳宓','宋','宋诗','song-poetry','','[]','四望坡陀百里平，群峰相顧最多情。',64,'全唐诗/poet.song.185000.json','["四望坡陀百里平，群峰相顧最多情。", "船從碧玉堆中度，人向黄雩陣裏行。", "訪道幾朝成夜飲，思君何日再晨征。", "暫時分袂休言別，遇有人來數寄聲。"]'),
('16dd6fcc-f7ed-4acf-acb4-932d2565ae1c','十七日窘雨邑中舟還','陳宓','宋','宋诗','song-poetry','','[]','行到青山欲盡頭，窮源未省作溪遊。',64,'全唐诗/poet.song.185000.json','["行到青山欲盡頭，窮源未省作溪遊。", "輕雲放日催人渡，積雨肥波送客舟。", "卧看玉簪迎兩岸，心隨繡領逐浮漚。", "眼前邂逅多堪賞，特地安排似此不。"]'),
('177cdd8c-e0ce-43dd-b1b9-ee2b0c32f8dd','十八日景山同舟作別','陳宓','宋','宋诗','song-poetry','','[]','濃陰猶辨石粼粼，百尺渾疑到底冰。',64,'全唐诗/poet.song.185000.json','["濃陰猶辨石粼粼，百尺渾疑到底冰。", "湍急宛乘銀騎出，身輕直向碧霄凌。", "風前別酒能禁幾，雨外征衣却慣曾。", "最是蕭蕭霜葉動，路回不見筍輿凭。"]'),
('b025fefd-f6b0-4326-bd33-b5d53eef65d3','將還家書寄社中','陳宓','宋','宋诗','song-poetry','','[]','縈紆一带本乎漫，碓碓依村自作灘。',64,'全唐诗/poet.song.185000.json','["縈紆一带本乎漫，碓碓依村自作灘。", "卷却片帆舟轉急，斟殘斗酒雨猶寒。", "從教稚子嗔歸晚，祇爲良朋得會難。", "佳景無窮吟不盡，還家携與社中看。"]'),
('56bc52a2-af4b-4e6f-9f79-ff2a940e8437','和崇安壁間  其一','陳宓','宋','宋诗','song-poetry','','[]','人人盡道爲貧驅，出不高車食不魚。',32,'全唐诗/poet.song.185000.json','["人人盡道爲貧驅，出不高車食不魚。", "陋巷最貧誰氏子，藜羹瀹飯味詩書。"]'),
('bdd1debd-20cd-44b8-9ebf-bab82903c4b8','和崇安壁間  其二','陳宓','宋','宋诗','song-poetry','','[]','小閣崢嶸山四傍，清溪來作九霞觴。',32,'全唐诗/poet.song.185000.json','["小閣崢嶸山四傍，清溪來作九霞觴。", "我來細酌看山色，山色長佳爲不忙。"]'),
('51c2efad-ea11-4eac-b4e2-6a397330c308','和東海題雲松嶺書堂','陳宓','宋','宋诗','song-poetry','','[]','百尺長松带碧蘿，杜溪深鎖蔣洋坡。',64,'全唐诗/poet.song.185000.json','["百尺長松带碧蘿，杜溪深鎖蔣洋坡。", "一堂來作群山主，四牖分盛好景多。", "書卷不須扃戶讀，詩翁頻許杖藜過。", "一生心事何難足，更與前灣月半簑。"]'),
('eb4de0b4-9a91-41d9-a4c7-688d3586522d','道中即事','陳宓','宋','宋诗','song-poetry','','[]','春陰不辨夕陽斜，漫宿深村小隠家。',64,'全唐诗/poet.song.185000.json','["春陰不辨夕陽斜，漫宿深村小隠家。", "石濺流泉成急雨，露妝枯樹作新花。", "但欣麥隴千山秀，不恨芒鞋十里沙。", "悠遠山川還興盡，不知何日抵京華。"]'),
('4d465b08-1f16-4f50-b316-0259e5d994f7','竹間榴花','陳宓','宋','宋诗','song-poetry','','[]','五月林梢未著蟬，節根新換玉娟娟。',32,'全唐诗/poet.song.185000.json','["五月林梢未著蟬，節根新換玉娟娟。", "露華團翠濃堪滴，澆得殷紅不敢然。"]'),
('8b7ebbe8-d5a2-433e-a210-6aea8fbd656d','瓶梅','陳宓','宋','宋诗','song-poetry','','[]','爲怕凋零不忍栽，問云何處正初開。',51,'全唐诗/poet.song.185000.json','["爲怕凋零不忍栽，問云何處正初開。", "小窗盡日看春至，短帽無人徹夜陪。", "光景長如新月上，杖藜懶向小園隈。", "最憐。"]'),
('2492623d-45b9-4e2a-954b-c00052dfc5dc','題蒲巖次陳侍郎韵  其一','陳宓','宋','宋诗','song-poetry','','[]','纖巧難誇刻楮工，四時不改綠茸茸。',32,'全唐诗/poet.song.185000.json','["纖巧難誇刻楮工，四時不改綠茸茸。", "祇應松檜堪爲友，閲盡人間桃李風。"]'),
('ec9ba8bb-8bd8-48ea-b09c-723384ad9138','題蒲巖次陳侍郎韵  其二','陳宓','宋','宋诗','song-poetry','','[]','我亦年來養氣工，黄茅丹鼎欲生茸。',32,'全唐诗/poet.song.185000.json','["我亦年來養氣工，黄茅丹鼎欲生茸。", "蓬萊咫尺真堪玩，底恨三年弱水風。"]'),
('d083dff9-4a3f-4d67-91d2-9c90fe6f2b4d','中秋前偶題  其一','陳宓','宋','宋诗','song-poetry','','[]','百歲中秋幾月明，長先十日候陰晴。',32,'全唐诗/poet.song.185000.json','["百歲中秋幾月明，長先十日候陰晴。", "清風不覺傳三鼓，又恐冰輪碾女城。"]'),
('84507a19-60f9-41b2-b01c-d7389e124732','中秋前偶題  其二','陳宓','宋','宋诗','song-poetry','','[]','世事浮雲頻改換，月華千古祇清新。',32,'全唐诗/poet.song.185000.json','["世事浮雲頻改換，月華千古祇清新。", "炎風暑氣常侵客，縱有凄風亦可人。"]'),
('d7c8defa-1f51-4001-b561-d89e1b6eb496','中秋前偶題  其三','陳宓','宋','宋诗','song-poetry','','[]','雨過雲衣已半除，深淵絢爛剖驪珠。',32,'全唐诗/poet.song.185000.json','["雨過雲衣已半除，深淵絢爛剖驪珠。", "陰晴明日猶難料，未必中秋此夜如。"]'),
('0c7dda40-95a5-4596-bdba-ed2f54414348','初秋喜雨','陳宓','宋','宋诗','song-poetry','','[]','稚金無力拒炎光，挾雨呼風作晚凉。',32,'全唐诗/poet.song.185000.json','["稚金無力拒炎光，挾雨呼風作晚凉。", "玉漏城頭傳一箭，征人已覺十分長。"]'),
('5deea3c8-7f82-4504-908d-bfcb7a05f8e4','酷熱','陳宓','宋','宋诗','song-poetry','','[]','赤日當空雨汗流，行人小立盡咨愁。',64,'全唐诗/poet.song.185000.json','["赤日當空雨汗流，行人小立盡咨愁。", "誰知天使陽居夏，要作人間歲有秋。", "鱗介洪纖皆自遂，林泉澹泊可無求。", "須思一夜西風起，便到無衣遠客頭。"]'),
('3006e809-60cb-4b38-a910-fffa5e7d79f0','過盤龍寺','陳宓','宋','宋诗','song-poetry','','[]','刺眼烟光聚野堂，無風荷葉自生凉。',32,'全唐诗/poet.song.185000.json','["刺眼烟光聚野堂，無風荷葉自生凉。", "幽人到此心先解，不動邊頭白鷺行。"]'),
('647bcefa-8060-4fac-8ab0-5fa7f7f3eeac','寄山中老友','陳宓','宋','宋诗','song-poetry','','[]','功名直作千年計，志氣不隨雙鬢衰。',32,'全唐诗/poet.song.185000.json','["功名直作千年計，志氣不隨雙鬢衰。", "書卷盈懷長晏食，祇煩造物爲營炊。"]'),
('43096545-a25d-4a3f-956a-8f00fc6ff431','贈翁子西','陳宓','宋','宋诗','song-poetry','','[]','先生道古背今馳，羈丱詩書兩鬢絲。',64,'全唐诗/poet.song.185000.json','["先生道古背今馳，羈丱詩書兩鬢絲。", "進取不隨餘子後，文章曾作幾人師。", "未施天上經綸手，且放胸中玉珮詞。", "三復荔臺佳句法，千年風雅有誰追。"]'),
('c56fd063-c732-48e7-986c-c9f1a6daf5f6','望夕','陳宓','宋','宋诗','song-poetry','','[]','一點射窗明已足，三更當戶意慵看。',32,'全唐诗/poet.song.185000.json','["一點射窗明已足，三更當戶意慵看。", "竹籬茅舍心安處，不羨乘風到廣寒。"]'),
('e37a58a4-8f6a-4f41-86b3-2e24568e8dec','黄梅','陳宓','宋','宋诗','song-poetry','','[]','來禽青李不待熟，枝上作酸能晚黄。',64,'全唐诗/poet.song.185000.json','["來禽青李不待熟，枝上作酸能晚黄。", "期與虀鹽同事業，每因烟雨長風光。", "丹心祇有帝心識，苦口寧爲衆口嘗。", "擲棄道旁同敝帚，有人負鼎去干湯。"]'),
('fdcb3839-2788-411f-acc9-39ee4ef304bf','探春','陳宓','宋','宋诗','song-poetry','','[]','桃李無言自曉粧，青春幾日最韶光。',32,'全唐诗/poet.song.185000.json','["桃李無言自曉粧，青春幾日最韶光。", "遊人不用頻來看，趁取初開未減香。"]'),
('13363dc1-3714-43db-b326-c1ccd5d9ef0c','春日到小園  其一','陳宓','宋','宋诗','song-poetry','','[]','屹立虛亭跨野塘，蕭蕭爽爽似瀟湘。',32,'全唐诗/poet.song.185000.json','["屹立虛亭跨野塘，蕭蕭爽爽似瀟湘。", "從教密種千竿竹，不蔽山光與水光。"]'),
('b9a63186-4d97-4012-9bcf-9d507e5bc548','春日到小園  其二','陳宓','宋','宋诗','song-poetry','','[]','東郊無地不蒼蒼，日氣融和自有香。',32,'全唐诗/poet.song.185000.json','["東郊無地不蒼蒼，日氣融和自有香。", "最是遊人行樂處，不寒不暖晝偏長。"]'),
('2f82830c-b6e9-4f33-9adf-f8a7b3e3f969','和翁子雅','陳宓','宋','宋诗','song-poetry','','[]','積中順和發英華，咳唾珠璣擅百家。',64,'全唐诗/poet.song.185000.json','["積中順和發英華，咳唾珠璣擅百家。", "圓似廣場馳小彈，熟於夷路駕輕車。", "綺詞新濯蜀江錦，險韵難追河漢槎。", "怪見春歸不遊賞，由來筆下有奇葩。"]'),
('57df28bc-55c1-4ccd-9491-20f1653f1d32','早起','陳宓','宋','宋诗','song-poetry','','[]','市廛無計避風埃，反閉柴門懶自開。',32,'全唐诗/poet.song.185000.json','["市廛無計避風埃，反閉柴門懶自開。", "春夢恰同簷雨斷，俗氛已逐鳥聲來。"]'),
('b540a2da-27b7-4953-b377-2cd95f89fafb','和方丞詠梅','陳宓','宋','宋诗','song-poetry','','[]','從來天道尚栽培，妙手仍能頃刻開。',64,'全唐诗/poet.song.185000.json','["從來天道尚栽培，妙手仍能頃刻開。", "萬壑千崖收臘去，三花兩蘂喚春回。", "松筠早結同心友，桃李真堪後乘陪。", "調鼎工夫在朝夕，如何方向此中栽。"]'),
('b7422a80-e1b8-4582-8d11-498a4321bde9','釣臺','陳宓','宋','宋诗','song-poetry','','[]','雲臺貂冕成堆土，釣瀨羊裘照九秋。',32,'全唐诗/poet.song.185000.json','["雲臺貂冕成堆土，釣瀨羊裘照九秋。", "認得南柯不回首，清名萬古尚流溪。"]'),
('64e6d22c-76f2-4dcb-aeac-3fe32ab9d8c1','到三山','陳宓','宋','宋诗','song-poetry','','[]','違鄉數驛肆馳驅，正是年華欲換時。',64,'全唐诗/poet.song.185000.json','["違鄉數驛肆馳驅，正是年華欲換時。", "山色萬家開戶牖，水錦十里列旌旗。", "物情欣泰隨方見，世態暄凉祇自知。", "一別南臺茲六載，重來盡記道間奇。"]'),
('3a028f3e-110e-4a4b-b56f-2e04dbf6c5ea','過黄源嶺','陳宓','宋','宋诗','song-poetry','','[]','此是辭家第幾程，道由劍嶺出崢嶸。',64,'全唐诗/poet.song.185000.json','["此是辭家第幾程，道由劍嶺出崢嶸。", "上穿密靄聞天語，下領浮雲作雨行。", "千仞直從人面起，一塵不向馬蹄生。", "雖慚仁智粗知樂，憇聽疎松夾水聲。"]'),
('177c1040-b136-4791-85e4-297cf9a945a2','和翁子雅','陳宓','宋','宋诗','song-poetry','','[]','函丈論文僕屢更，夜深相對眼偏青。',32,'全唐诗/poet.song.185000.json','["函丈論文僕屢更，夜深相對眼偏青。", "曾無取次人敲戶，祇有慇懃月到庭。"]'),
('c2c298b7-5ff1-4150-b707-4b00ba23bb1e','題劍灘','陳宓','宋','宋诗','song-poetry','','[]','山在溪中水在山，人生何處鬼門關。',64,'全唐诗/poet.song.185000.json','["山在溪中水在山，人生何處鬼門關。", "數聲柔櫓風雷外，一葉輕舟劍戟間。", "爲問片時驚陷溺，何如竟日緩躋攀。", "信知行險非天命，垣道從來絕後艱。"]'),
('dd4ca85d-43ef-4f72-be96-a6015a28cfff','吉溪見桃花','陳宓','宋','宋诗','song-poetry','','[]','山中開落不逢人，我爲持盃一笑頻。',64,'全唐诗/poet.song.185000.json','["山中開落不逢人，我爲持盃一笑頻。", "最喜綠陰成子早，却嫌紅蘂折枝頻。", "已勾蛺蝶輕遮雨，更約溪風細護春。", "萬點武陵歸去日，應無一葉到囂塵。"]'),
('a7a52252-0539-4fb1-9155-61b0858f5725','南劍值雪','陳宓','宋','宋诗','song-poetry','','[]','一夜茅簷凍雨聲，曉來千岫照人明。',64,'全唐诗/poet.song.185000.json','["一夜茅簷凍雨聲，曉來千岫照人明。", "真同煮海鹽花瑞，不見因風柳絮輕。", "游子不愁衣短薄，農夫剩喜歲豐成。", "竹籬草舍猶堪賞，况映鐔津一水清。"]'),
('ac956903-9437-4c85-8e9e-91d54c99af36','題王孫口致爽亭賡陳左史韵  其一','陳宓','宋','宋诗','song-poetry','','[]','溪山一路送還迎，管領溪山有此亭。',32,'全唐诗/poet.song.185000.json','["溪山一路送還迎，管領溪山有此亭。", "我爲舉杯相勞勉，他年端不負山靈。"]'),
('9a147bba-d339-475e-ba2a-2b504003b29e','題王孫口致爽亭賡陳左史韵  其二','陳宓','宋','宋诗','song-poetry','','[]','誰結危亭碧玉堆，西山爽氣喚仍回。',32,'全唐诗/poet.song.185000.json','["誰結危亭碧玉堆，西山爽氣喚仍回。", "嵐光祇恐不堪著，更遣新詩勾引來。"]'),
('03a5faec-e632-43d9-b553-4daf8d553c77','題致爽亭','陳宓','宋','宋诗','song-poetry','','[]','山水圍中宅一區，小亭花柳足康娛。',64,'全唐诗/poet.song.185000.json','["山水圍中宅一區，小亭花柳足康娛。", "勾牽詩思千篇有，斗擻征塵一點無。", "秉燭風簷費遮邏，閉窗雲霧巧闚𨵦。", "憑誰起喚王摩詰，寫作淵明歸去圖。"]'),
('05763cc7-5932-4157-8e8d-93c673d5b0bb','分水嶺','陳宓','宋','宋诗','song-poetry','','[]','區域甌閩此嶺存，朝來飛雨暮行雲。',32,'全唐诗/poet.song.185000.json','["區域甌閩此嶺存，朝來飛雨暮行雲。", "方今天下車同軌，一水如何强別分。"]'),
('6d9263d6-df4f-44cd-8d49-4484447544c1','嶺上見梅','陳宓','宋','宋诗','song-poetry','','[]','桃溪蜂蝶醉紅裙，度嶺冰姿尚卧雲。',32,'全唐诗/poet.song.185000.json','["桃溪蜂蝶醉紅裙，度嶺冰姿尚卧雲。", "不獨山川限閩浙，由來天意亦區分。"]'),
('13e66751-c6c5-483d-942e-0ec6fcb30b93','鉛山聖泉','陳宓','宋','宋诗','song-poetry','','[]','山結深深碧玉龕，神龍保此一泓甘。',32,'全唐诗/poet.song.185000.json','["山結深深碧玉龕，神龍保此一泓甘。", "我來酒渴如虹飲，料得來生未解貪。"]'),
('c65af37f-a4be-4648-9a70-5ddf534c10c0','風雨過武夷山','陳宓','宋','宋诗','song-poetry','','[]','我與茲山是故人，十年相別意彌真。',32,'全唐诗/poet.song.185000.json','["我與茲山是故人，十年相別意彌真。", "如何咫尺迷風雨，剛道情親却不親。"]'),
('591cce2c-12e1-4de5-81e8-a818e83fd035','妙寂院訪梅','陳宓','宋','宋诗','song-poetry','','[]','山寒盡日少人知，調鼎風流却在茲。',64,'全唐诗/poet.song.185000.json','["山寒盡日少人知，調鼎風流却在茲。", "但得此君爲益友，不嫌青女妬妍姿。", "應愁我輩來何晚，豈共春風別有私。", "不忍折枝飛減玉，留看小雨弄黄時。"]'),
('6180283f-7b28-4254-a152-028a99138cda','和趙仲白  其一','陳宓','宋','宋诗','song-poetry','','[]','不踏人間桃李場，要看梅蘤带嚴霜。',64,'全唐诗/poet.song.185000.json','["不踏人間桃李場，要看梅蘤带嚴霜。", "敷成妙賦飄飄意，吐出新詩字字香。", "爽致青山期取友，高情春晝與俱長。", "蘇黄不作希佳士，被褐懷珠奪月光。"]'),
('83512476-7894-4695-b063-b42fe58a1e28','和趙仲白  其二','陳宓','宋','宋诗','song-poetry','','[]','寤寐曹劉不解忘，雙眸烱烱月中霜。',64,'全唐诗/poet.song.185000.json','["寤寐曹劉不解忘，雙眸烱烱月中霜。", "高吟出軸繭絲富，雅思縈春柳絮香。", "後進推排唯我拙，前人準擬覺君長。", "祇今天下多名士，深謝新篇擲夜光。"]'),
('c5f6653d-8ff9-4376-a120-fd0672da4563','三月芙蓉盛開二十餘花和友人韵  其一','陳宓','宋','宋诗','song-poetry','','[]','芳辰美景最難兼，桃李春風桂子蟾。',32,'全唐诗/poet.song.185000.json','["芳辰美景最難兼，桃李春風桂子蟾。", "百卉並生吾道泰，嘉祥敢恃我師謙。"]'),
('688a7059-4cd9-4df6-be77-3e45e753cc9b','三月芙蓉盛開二十餘花和友人韵  其二','陳宓','宋','宋诗','song-poetry','','[]','雲袖霞衣自等差，天風吹下玉皇家。',32,'全唐诗/poet.song.185000.json','["雲袖霞衣自等差，天風吹下玉皇家。", "似憐桃李無顔色，來伴姚黄魏紫花。"]'),
('4d55d27d-ff7b-4c67-b9d6-d9c3a65e548f','賀權郡雨應禱','陳宓','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山開霽雨回風，正直心期自感通。',64,'全唐诗/poet.song.185000.json','["衡山開霽雨回風，正直心期自感通。", "頓使霑濡千里足，都由精白寸誠中。", "誰知憂國丹心在，不與農夫喜色同。", "四海正須膏澤潤，豈容別駕最民功。"]'),
('57d9d48e-2e45-47a5-906f-cb5109543ff9','乙丑春旱至四月十六夜雨  其一','陳宓','宋','宋诗','song-poetry','','[]','說梅津潄不濡唇，秧稻堪驚陌上人。',32,'全唐诗/poet.song.185000.json','["說梅津潄不濡唇，秧稻堪驚陌上人。", "昨夜天公一翻手，蒼生百萬面生春。"]'),
('54167a0d-214a-43d0-9c84-34dd8273423e','乙丑春旱至四月十六夜雨  其二','陳宓','宋','宋诗','song-poetry','','[]','何處笙歌酒入唇，應慚忍渴望雲人。',32,'全唐诗/poet.song.185000.json','["何處笙歌酒入唇，應慚忍渴望雲人。", "朝來頓覺西山黑，農圃歡聲總是春。"]'),
('80962176-2e95-4598-a40f-31e1375125af','十六至十九日雨未已','陳宓','宋','宋诗','song-poetry','','[]','一夜蛟龍怒虎烋，卧聽簷溜不分交。',64,'全唐诗/poet.song.185000.json','["一夜蛟龍怒虎烋，卧聽簷溜不分交。", "拍天溪浦迷西極，萬里耕耘盡樂郊。", "蛙黽無舟乘野外，寒鴉不笠待林梢。", "要看杲杲東方白，魚自清波燕自巢。"]'),
('e1f8f267-28d8-4da1-b886-ab5e3a925bce','和潘舍人','陳宓','宋','宋诗','song-poetry','','[]','不能百里馬牛風，千日相思一日逢。',32,'全唐诗/poet.song.185000.json','["不能百里馬牛風，千日相思一日逢。", "四月仙舟發漳水，恍然笑語在芙蓉。"]'),
('c89d249c-b8e1-4a60-bcaa-f7af4e2963ed','上潘舍人  其一','陳宓','宋','宋诗','song-poetry','','[]','經行造次有新詩，吞吐珠璣不自奇。',64,'全唐诗/poet.song.185000.json','["經行造次有新詩，吞吐珠璣不自奇。", "寸管久期窺變豹，深叢今幸見孤羆。", "高情陶謝猶能及，聖處陰何詎得知。", "乞與金丹換凡骨，飛遨祇恐乏仙姿。"]'),
('ae8d9ebd-c23e-4d05-b8b7-07d009d2cd49','上潘舍人  其二','陳宓','宋','宋诗','song-poetry','','[]','淛水人如大雅詩，唯君出句最能奇。',64,'全唐诗/poet.song.185000.json','["淛水人如大雅詩，唯君出句最能奇。", "騰聲直欲驂鸞鶴，赤子猶思縛虎羆。", "覽卷幾年如舊識，忘年今日辱新知。", "漳濱尚許陪尊俎，想像梅花是玉姿。"]'),
('34022557-5c01-4c39-b103-3031f4640c2b','三賢堂和柯東海','陳宓','宋','宋诗','song-poetry','','[]','先後勳名百歲周，同堂耿耿夜光寒。',64,'全唐诗/poet.song.185000.json','["先後勳名百歲周，同堂耿耿夜光寒。", "片言已奪丹遼氣，萬世猶聞四諫官。", "殄虜機籌餘膽壯，佐時忠亮更胸蟠。", "不因品藻公輿論，得與前賢一樣看。"]'),
('a29d33e9-867b-4280-889a-2673153f2a0d','中夜','陳宓','宋','宋诗','song-poetry','','[]','功名有念心常醒，更鼓無聲夜更長。',32,'全唐诗/poet.song.185000.json','["功名有念心常醒，更鼓無聲夜更長。", "天運乾乾同轉磨，鬢毛能不幾時霜。"]'),
('5a605dd9-d07c-49ea-adeb-4cc58543ee12','荔子  其一','陳宓','宋','宋诗','song-poetry','','[]','不伴人間桃李群，炎曦與傅渥丹勻。',32,'全唐诗/poet.song.185000.json','["不伴人間桃李群，炎曦與傅渥丹勻。", "南州幾歲供懷橘，北闕何年可獻芹。"]'),
('e3ad6bce-cc38-4584-9b15-413987cd6100','荔子  其二','陳宓','宋','宋诗','song-poetry','','[]','天垂甘露絳紗囊，要作南方一味凉。',32,'全唐诗/poet.song.185000.json','["天垂甘露絳紗囊，要作南方一味凉。", "解□世間煩熱惱，華峰有藕未能强。"]'),
('9bd25250-c943-430d-a7be-3b88e437b7c2','讀先君新第落成詩有感因韵書示蒙孫  其一','陳宓','宋','宋诗','song-poetry','','[]','信矣賢愚共一初，都緣勤怠遂殊居。',64,'全唐诗/poet.song.185000.json','["信矣賢愚共一初，都緣勤怠遂殊居。", "淵源有本天同健，潢潦無根夕易除。", "何事不爲塵所染，平生須有善堪書。", "要從陋巷甘勤苦，始得聲名滿觀渠。"]'),
('d902f097-16a3-4e00-bfe3-3d9cf5756d42','讀先君新第落成詩有感因韵書示蒙孫  其二','陳宓','宋','宋诗','song-poetry','','[]','吾家清儉莫忘初，昔日儒酸白屋居。',64,'全唐诗/poet.song.185000.json','["吾家清儉莫忘初，昔日儒酸白屋居。", "世事直須防滿溢，天公偏是喜乘除。", "看來負郭三千頃，不似傳家一卷書。", "謙損却能豐萃致，試觀滄海受川渠。"]'),
('ec90d62c-1592-47ac-b562-f52f84fd80bf','謝東園主人惠蔡公草書','陳宓','宋','宋诗','song-poetry','','[]','開軒但覺快心眸，百載雲烟靄未收。',64,'全唐诗/poet.song.185000.json','["開軒但覺快心眸，百載雲烟靄未收。", "誰謂昔人成邁往，每於遺墨見風流。", "看中猛勢驤龍虎，藏處寒光射斗牛。", "白璧一雙猶莫報，受君此惠等山丘。"]'),
('66968c10-dee6-411c-80b3-2d005f7d12f7','上王侯重九前蠲不濟寺債','陳宓','宋','宋诗','song-poetry','','[]','史君救弊知原本，民頼浮屠産力寬。',64,'全唐诗/poet.song.185000.json','["史君救弊知原本，民頼浮屠産力寬。", "保障便爲今日計，功名留與百年看。", "喜聞白紙租都放，不飲黄花酒亦歡。", "晨起有人相賀語，禪齋得穩占蒲團。"]'),
('342fc134-fc29-4a7f-87bf-71fe7cf897e1','後堂木芙蓉','陳宓','宋','宋诗','song-poetry','','[]','紅葩翠竹與齊肩，爲問霜枝已幾年。',32,'全唐诗/poet.song.185000.json','["紅葩翠竹與齊肩，爲問霜枝已幾年。", "一色碧天紅爛熳，卧看疑在鑑湖舡。"]'),
('fa6df560-9cbb-4ecb-9255-c408033f1de7','四月中澣流惠亭見蓮  其一','陳宓','宋','宋诗','song-poetry','','[]','誰言紅艷占春多，風雨真成一擲梭。',32,'全唐诗/poet.song.185000.json','["誰言紅艷占春多，風雨真成一擲梭。", "何似水花秋更好，才逢四月已開荷。"]'),
('48f0908e-5f13-4eee-a1ac-d1ff9e7b934c','四月中澣流惠亭見蓮  其二','陳宓','宋','宋诗','song-poetry','','[]','疾雷不雨卷行雲，湖面清風篆玉文。',32,'全唐诗/poet.song.185000.json','["疾雷不雨卷行雲，湖面清風篆玉文。", "我自得間來卧看，狎人鷗鷺亦成群。"]'),
('ebfb661a-1386-4ddb-b11e-0f2be8264212','和方宗教鼓山韵  其一','陳宓','宋','宋诗','song-poetry','','[]','胸次崔嵬絕點埃，山光玉色兩佳哉。',64,'全唐诗/poet.song.185000.json','["胸次崔嵬絕點埃，山光玉色兩佳哉。", "官閑却得身棲宿，巖迥惟聞鶴去來。", "定處華鯨催石磬，眼前茗碗伴爐灰。", "高情一出樊籠外，逸駕飄飄未擬回。"]'),
('43bb48b1-ff42-46d5-a2e9-09c81d39dbf4','和方宗教鼓山韵  其二','陳宓','宋','宋诗','song-poetry','','[]','蓋世功名不染埃，清時嘗見賦康哉。',64,'全唐诗/poet.song.185000.json','["蓋世功名不染埃，清時嘗見賦康哉。", "靈源已作千年觀，聖相仍曾一日來。", "補練元功天上石，燮調和氣琯中灰。", "崖間嘗有數行墨，留與遊人抵暮回。"]'),
('ecfa81e8-3060-4bb0-893f-b600e8b585ab','題永石屏  其一','陳宓','宋','宋诗','song-poetry','','[]','琅玕三尺重南金，風韵仍同綠綺琴。',32,'全唐诗/poet.song.185000.json','["琅玕三尺重南金，風韵仍同綠綺琴。", "胸次便如斯壁立，千年不受一塵侵。"]'),
('4f1128b2-5a21-4d37-9ebf-3d48d35b636e','題永石屏  其二','陳宓','宋','宋诗','song-poetry','','[]','誰將一段楚天碧，磨向崖心萬仞餘。',32,'全唐诗/poet.song.185000.json','["誰將一段楚天碧，磨向崖心萬仞餘。", "橋柱不題司馬字，蘭亭留待右軍書。"]'),
('448557b6-2a63-49c4-9da7-306f2e7b61b6','大目寺牡丹','陳宓','宋','宋诗','song-poetry','','[]','行人那得不如狂，謫下僊真衣錦裳。',32,'全唐诗/poet.song.185000.json','["行人那得不如狂，謫下僊真衣錦裳。", "要識洛陽姚魏色，煩君千里到維揚。"]'),
('7f4996a7-98b8-4a21-8683-eb6355c4d023','丙寅五月三日陪真秘字留校理遊鼓山一別二年適同遊東觀緬思舊遊正以是日作詩以記之','陳宓','宋','宋诗','song-poetry','','[]','一時盛事擅南閩，驚世詞宗幕府賓。',64,'全唐诗/poet.song.185000.json','["一時盛事擅南閩，驚世詞宗幕府賓。", "今日恰同當日會，道山元是鼓山人。", "兩年君幾封囊上，百里予方束带新。", "岐路不同俱自勉，何年重此拂堅珉。"]'),
('ad4a3057-7a2b-41c6-a4d7-445250b57350','重九日登道山亭柱間有陳休齋題詞曰師相者先君也予既感時之用師而懷先君之去此已垂卅年慨然流涕歸而賦之','陳宓','宋','宋诗','song-poetry','','[]','道山亭上看秋光，萬里長安在夕陽。',64,'全唐诗/poet.song.185000.json','["道山亭上看秋光，萬里長安在夕陽。", "數點難收周顗淚，一冠莫效孟嘉狂。", "浮嵐盡作襟期爽，嫩蘂能令肺腑香。", "三十年前童稚日，不堪回首一凄凉。"]'),
('63b55248-e5ca-43c4-9abb-18f6c4db64b0','開禧丙寅春二十六日黄子功襲少任趙仲白同會轉庵中夜以夜永燭花偏分韵賦詩樂甚時太守有遊山之約不果','陳宓','宋','宋诗','song-poetry','','[]','有道襟懷鬢不華，笑譚物物總春花。',64,'全唐诗/poet.song.185000.json','["有道襟懷鬢不華，笑譚物物總春花。", "揮毫要使鍾張避，出句應知屈宋衙。", "今日相逢萍聚水，明朝各是客乘楂。", "坐中韶濩鏗鏘作，亦許狂吟雜俚哇。"]'),
('d88dddb4-d038-4e89-bb67-93cb271dcda9','上潘舍人德久  其一','陳宓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','慚愧西湖處士身，强縻珪組向南閩。',64,'全唐诗/poet.song.185000.json','["慚愧西湖處士身，强縻珪組向南閩。", "旌旗夾道渾閑物，句律橫空別有神。", "嚴瀨舊題追古昔，奚囊白首更清新。", "年來剩喜三迴見，一代于今有幾人。"]'),
('4c6b6107-9a4c-4313-ad60-2f4b9655574f','上潘舍人德久  其二','陳宓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','氣大詞雄擅百家，長江衮衮見浮楂。',64,'全唐诗/poet.song.185000.json','["氣大詞雄擅百家，長江衮衮見浮楂。", "襟懷有道顔長玉，談笑爲春物自花。", "飄逸大書追渴驥，聯翩行字更飛鴉。", "夜陪餘論清肝膽，不羨乘風七碗茶。"]'),
('1db509e8-c479-4237-ad39-169a34538788','雲臺寺梅坡  其一','陳宓','宋','宋诗','song-poetry','','[]','不是騷人親手栽，如何一一作詩謀。',32,'全唐诗/poet.song.185000.json','["不是騷人親手栽，如何一一作詩謀。", "世間那用香如許，應有仙真夜往來。"]'),
('7114324b-dc2f-427c-8c56-ee5e3c69100e','雲臺寺梅坡  其二','陳宓','宋','宋诗','song-poetry','','[]','樹杪風來玉佩輕，仙香飄作世間清。',32,'全唐诗/poet.song.185000.json','["樹杪風來玉佩輕，仙香飄作世間清。", "一枝不許來城市，祇伴高人避世情。"]'),
('7044643e-9790-4c94-936a-fa22b77d3d49','讀史','陳宓','宋','宋诗','song-poetry','','[]','一嘿盡知天下事，片言常得古人心。',32,'全唐诗/poet.song.185000.json','["一嘿盡知天下事，片言常得古人心。", "千年成敗興衰迹，祇向忠邪兩路尋。"]'),
('92ed0fc9-6511-40ca-88af-68d3bc29d95c','偶題','陳宓','宋','宋诗','song-poetry','','[]','紫瓊潤潔墨花香，獨坐小窗春晝長。',32,'全唐诗/poet.song.185000.json','["紫瓊潤潔墨花香，獨坐小窗春晝長。", "拈筆題詩隨意拙，近來不復省鍾王。"]'),
('7b0dee54-1e82-4b6b-a79d-44b2cdd16c2f','問梅  其一','陳宓','宋','宋诗','song-poetry','','[]','孤芳皎皎怕人知，欲近清香遠却宜。',32,'全唐诗/poet.song.185000.json','["孤芳皎皎怕人知，欲近清香遠却宜。", "認得清香端的處，等閑著眼莫相疑。"]'),
('acbd3e4e-305a-42c0-8bec-7af09b64fe40','問梅  其二','陳宓','宋','宋诗','song-poetry','','[]','眼前禁得一枝橫，不用千林綴玉英。',32,'全唐诗/poet.song.185000.json','["眼前禁得一枝橫，不用千林綴玉英。", "花謝花開渾不問，祇將佳處付詩情。"]'),
('4d1e0f5b-ff18-48d9-a877-3db53d52783d','丹桂','陳宓','宋','宋诗','song-poetry','','[]','自是仙家別樣粧，風來疑解舞霓裳。',32,'全唐诗/poet.song.185000.json','["自是仙家別樣粧，風來疑解舞霓裳。", "異香只許蟾宮采，不與秋光作伴黄。"]'),
('b7028c53-b8dd-432e-9f73-66fdb2a81439','雨晴見山','陳宓','宋','宋诗','song-poetry','','[]','經旬不見嶙峋面，雨施雲行到九州。',32,'全唐诗/poet.song.185000.json','["經旬不見嶙峋面，雨施雲行到九州。", "春政已成無一事，却扶紅日翠峰頭。"]'),
('06fb72ae-c3ab-4b7f-8f03-00787464c5c5','次仙谿陳侍郎韵寄題劉尚書二首 秀野','陳宓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','迂叟相望百載間，遺風誰道久凋闌。',64,'全唐诗/poet.song.185000.json','["迂叟相望百載間，遺風誰道久凋闌。", "欲期他日勳名盛，追作當年榜樣看。", "汗漫西湖開望哀，崔嵬方巘獻雲端。", "功名肯擅一丘樂，突兀須教天下歡。"]'),
('30e9be39-3be7-4814-8943-04f76259ec25','次仙谿陳侍郎韵寄題劉尚書二首 真止','陳宓','宋','宋诗','song-poetry','','[]','利祿由來酒樣醇，伊誰未醉解收身。',64,'全唐诗/poet.song.185000.json','["利祿由來酒樣醇，伊誰未醉解收身。", "須知澤畔獨醒客，不顧墦間飽飫人。", "晉代風流多逸士，陶公名節號忠臣。", "築堂景慕前賢行，飲水端能嚌道真。"]'),
('4aed4809-a8d4-491d-b0ad-9bd6a115f928','偶題','陳宓','宋','宋诗','song-poetry','','[]','忿慾喪軀真狂死，孝忠致命勝偷生。',32,'全唐诗/poet.song.185000.json','["忿慾喪軀真狂死，孝忠致命勝偷生。", "此心一片陽剛德，莫遣纖毫暫不明。"]'),
('b482f820-003c-4eea-90e1-12a5e03c80f6','山行','陳宓','宋','宋诗','song-poetry','','[]','禽聲戛玉琤如墮，蝶翅新粧粉欲飛。',32,'全唐诗/poet.song.185000.json','["禽聲戛玉琤如墮，蝶翅新粧粉欲飛。", "山靜物閑無一事，却嫌釣叟下魚磯。"]'),
('c388b40d-6229-4508-a465-207326ffd817','題妙寂寺','陳宓','宋','宋诗','song-poetry','','[]','老鵲呼簷人起早，華鯨催午日西遲。',32,'全唐诗/poet.song.185000.json','["老鵲呼簷人起早，華鯨催午日西遲。", "不因地迥稀塵事，那得冬陰似夏時。"]'),
('3c667ae6-3019-4c2e-8956-ebca2fd6af52','和寄喻景山','陳宓','宋','宋诗','song-poetry','','[]','朱門到老幾人還，贏得階庭著蘚班。',64,'全唐诗/poet.song.185000.json','["朱門到老幾人還，贏得階庭著蘚班。", "曾似高人無俗累，解將碧巘照朱顔。", "趣超今古沉酣外，句入雲烟縹緲間。", "白首紛紛自名利，天公最惜是清閑。"]'),
('10bd60a8-0c2d-4b1c-8b36-9f885631171b','飲井','陳宓','宋','宋诗','song-poetry','','[]','飲井之清天下少，夷齊比德復如何。',64,'全唐诗/poet.song.185000.json','["飲井之清天下少，夷齊比德復如何。", "寒冰入口侵牙頰，甘露霑腸逐病痾。", "十里溉田成旱雨，一泓濟渴勝天河。", "活人未遂平生志，酌此深知負愧多。"]'),
('3ae1e614-06b1-4288-9375-742c62813d6b','遊武夷  其一','陳宓','宋','宋诗','song-poetry','','[]','冰溪凜凜九回曲，玉壁巖巖兩面開。',32,'全唐诗/poet.song.185000.json','["冰溪凜凜九回曲，玉壁巖巖兩面開。", "舟逆急湍分寸上，奇峰細得看崔嵬。"]'),
('10fc5d11-7a10-41b2-a637-0f3ec172159a','遊武夷  其二','陳宓','宋','宋诗','song-poetry','','[]','幾段飛橋著翠烟，雲間有路想通天。',32,'全唐诗/poet.song.185000.json','["幾段飛橋著翠烟，雲間有路想通天。", "古來何事非陳迹，道是神仙不見仙。"]'),
('84f111db-02e6-47fd-879c-e48e3b42ad3b','遊武夷  其三','陳宓','宋','宋诗','song-poetry','','[]','武夷山上生春茶，武夷溪水清見沙。',32,'全唐诗/poet.song.185000.json','["武夷山上生春茶，武夷溪水清見沙。", "含溪嚼茶坐盤石，悵惆欲趁西飛霞。"]'),
('50ef0edc-b752-44c0-8c32-6386e41ee890','中春','陳宓','宋','宋诗','song-poetry','','[]','襲人天氣暄還冷，欲雨窗綃暗復明。',64,'全唐诗/poet.song.185000.json','["襲人天氣暄還冷，欲雨窗綃暗復明。", "山鳥喜晴乘屋語，野農侵曉荷鋤耕。", "不須杯勺勾春思，幸有詩書愜此生。", "桃杏繁枝一回首，爭如松竹伴秋清。"]'),
('198361f4-4d0e-47f2-8c09-27824643ec42','書懷','陳宓','宋','宋诗','song-poetry','','[]','書卷叢中偏得垂，園花開後却慵看。',32,'全唐诗/poet.song.185000.json','["書卷叢中偏得垂，園花開後却慵看。", "嵬胸莫受一塵染，壯歲須騰萬里翰。"]'),
('94eb3161-c200-456b-8f60-ecfed4b1886b','春暮','陳宓','宋','宋诗','song-poetry','','[]','春暮見花空有恨，病餘怯酒謾重溫。',32,'全唐诗/poet.song.185000.json','["春暮見花空有恨，病餘怯酒謾重溫。", "紫騮踏盡垂楊影，可笑書生獨掩門。"]'),
('682a05b1-4dc2-434e-b8b0-8e3e894581b9','寄題桂籍  其一','陳宓','宋','宋诗','song-poetry','','[]','姓名高揭萬人中，奏對縱橫出漢宮。',64,'全唐诗/poet.song.185000.json','["姓名高揭萬人中，奏對縱橫出漢宮。", "肯詫一時燕許手，要垂百代惠夷風。", "壁間先烈猶忠赤，堂上嘉賓盡醉紅。", "常相風流今孰繼，作成儒雅看侯功。"]'),
('34c980c7-06be-4276-a7a0-d302ed27075b','寄題桂籍  其二','陳宓','宋','宋诗','song-poetry','','[]','胸次如冰貫九流，衛刀凜凜御千牛。',64,'全唐诗/poet.song.185000.json','["胸次如冰貫九流，衛刀凜凜御千牛。", "兩年報政爲閩最，不日成堂見令脩。", "有袴久騰南國詠，結絇行作禁庭遊。", "日邊已有絲綸下，不使君侯惠一州。"]'),
('76d24fdf-abb8-405f-8680-9f792b1b7d21','感春','陳宓','宋','宋诗','song-poetry','','[]','春來物物盡欣怡，不到人間寒自眉。',32,'全唐诗/poet.song.185000.json','["春來物物盡欣怡，不到人間寒自眉。", "願得清時同貞觀，旅行終日不憂饑。"]'),
('221665c7-fa43-4080-bf8e-fd8b5a5abc4b','春半桃李盛開','陳宓','宋','宋诗','song-poetry','','[]','縞裙練帨映丹霞，默默無言不自誇。',32,'全唐诗/poet.song.185000.json','["縞裙練帨映丹霞，默默無言不自誇。", "陌上行人重回首，一年春事數朝花。"]'),
('8ad166f8-3730-4a71-94e8-703b307a4a47','丁巳調選','陳宓','宋','宋诗','song-poetry','','[]','人生四十方强仕，一調十年能幾回。',64,'全唐诗/poet.song.185000.json','["人生四十方强仕，一調十年能幾回。", "蟬冕未加頭蚤累，詩成水上見風行。", "筆端萬類因陵暴，世態浮雲任變更。", "且盡花前一樽酒，何須身後五言聲。"]'),
('9e341e7a-cf30-4eb6-92b7-133f815828bb','秋夜','陳宓','宋','宋诗','song-poetry','','[]','水清沙淺見魚鰭，雪凈天空數雁飛。',64,'全唐诗/poet.song.185000.json','["水清沙淺見魚鰭，雪凈天空數雁飛。", "白月無瑕呈佩玦，黄花有露綴珠璣。", "西風勸我繙書葉，促織催人送戍衣。", "最喜蚊雷中夜靜，長檠容得一燈微。"]'),
('1a1784d7-c5e6-4b1c-92ef-a4f3f4d79932','秋酌','陳宓','宋','宋诗','song-poetry','','[]','不飲踰時心已灰，黄花忽破杪秋來。',64,'全唐诗/poet.song.185000.json','["不飲踰時心已灰，黄花忽破杪秋來。", "初無雅興酬佳節，謾把霜英浸玉醅。", "免俗未能聊復爾，清時端可賦康哉。", "明年此日知何處，好遣詩筒數往回。"]'),
('37799f6a-f8cc-4929-a3fb-69974ab145b7','和樞上人韵','陳宓','宋','宋诗','song-poetry','','[]','禪心獨理燈無盡，曲論懷私物不齊。',64,'全唐诗/poet.song.185000.json','["禪心獨理燈無盡，曲論懷私物不齊。", "拱木已嚴千歲冢，狂瀾難决萬金隄。", "古今蔽顯神功相，天地韜藏裕眼迷。", "會看清風明月夕，雲間端有鶴來栖。"]'),
('8835f3fd-7c66-415d-b5f8-053b5cf77f3c','和方漕孚若遊瀑布','陳宓','宋','宋诗','song-poetry','','[]','一派能令玉作山，千年那復更愁乾。',64,'全唐诗/poet.song.185000.json','["一派能令玉作山，千年那復更愁乾。", "初疑雲陣漏寒月，乍似鷗群趁急湍。", "領客適當晴正好，結亭偏愜暑來看。", "知君欲奉潘輿樂，千乘何如此地安。"]'),
('7879b7b2-1bbf-409c-a302-ddcc62a4fa6e','和胡仲方留題清果寺壁','陳宓','宋','宋诗','song-poetry','','[]','盞斝已殘休惜別，功名未就正堪愁。',32,'全唐诗/poet.song.185000.json','["盞斝已殘休惜別，功名未就正堪愁。", "野梅風味關人意，獨占群花最上頭。"]'),
('dac6a0eb-d182-457a-a60d-bafe0907ac46','寄陳次顔  其一','陳宓','宋','宋诗','song-poetry','','[]','蕭條幾載寓泉南，盂飯盤蔬味自甘。',64,'全唐诗/poet.song.185000.json','["蕭條幾載寓泉南，盂飯盤蔬味自甘。", "卓志每求顔氏樂，清風能激蹠徒貪。", "□而好施人難及，老不忘書我所慚。", "鼓瑟求齊雖未巧，會看宵夢到晴嵐。"]'),
('f3949c66-14a5-4836-968e-fdd47db95902','寄陳次顔  其二','陳宓','宋','宋诗','song-poetry','','[]','人年六十志先衰，年過唯君意不疲。',64,'全唐诗/poet.song.185000.json','["人年六十志先衰，年過唯君意不疲。", "胸次嵬嵬山立壁，書叢矻矻鳥粘黐。", "重裘兼味人能賤，冬葛朝虀世所師。", "借問別來新著作，大篇無惜愜吾思。"]'),
('355706ad-7982-40f3-bc1e-42cb00388cfc','自勉','陳宓','宋','宋诗','song-poetry','','[]','蓋世聲名都在少，君看前輩合何如。',32,'全唐诗/poet.song.185000.json','["蓋世聲名都在少，君看前輩合何如。", "我年若此成何事，白日還同過隙駒。"]'),
