('76b52ec7-2ad0-43ac-8101-2a18e5bdd055','和柯東海梅花之什','陳宓','宋','宋诗','song-poetry','','[]','誰將鉛粉比清真，天賦殊姿秀色勻。',64,'全唐诗/poet.song.185000.json','["誰將鉛粉比清真，天賦殊姿秀色勻。", "祇許謫仙爲酒友，應呼衛玠作塵人。", "懸燈不減秋冬雪，入盞先浮隔歲春。", "堪笑古今同一白，詩人吟著總凝神。"]'),
('efd8ed99-0746-489b-9265-d85240f17754','和柯東海潘瓜山遊南園韵','陳宓','宋','宋诗','song-poetry','','[]','下帷窺圃事多違，到得南園已夕暉。',64,'全唐诗/poet.song.185000.json','["下帷窺圃事多違，到得南園已夕暉。", "松竹不忙無世態，柳梅相逐見天機。", "僕便蕭散朝猶睡，鶴慣羈孤晚自歸。", "如此得閑堪自適，底須危處始知幾。"]'),
('872e2764-f50c-4af5-b7d1-a5e45bc292cb','和東海韵','陳宓','宋','宋诗','song-poetry','','[]','炎空欲暮赤雲橫，何日秋風可抗衡。',64,'全唐诗/poet.song.185000.json','["炎空欲暮赤雲橫，何日秋風可抗衡。", "盡捲疎簾通水氣，靜聽密罟得魚聲。", "山開曠野天全見，人倚平欄夜自明。", "衙鼓三通歸路近，歌眠猶念竹陰清。"]'),
('7d46ea75-e338-479a-b413-3fb441a4ad84','南園新作小舟與客遊白湖柯某東海有詩次韵','陳宓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','好著西湖藕似船，青秧綠水正相緣。',64,'全唐诗/poet.song.185000.json','["好著西湖藕似船，青秧綠水正相緣。", "漫從畧彴無人處，喚得嬋娟欲雨天。", "雲意愛隨雙槳動，山光祇在短蓬邊。", "小園暇日頻來往，老竹喬松看歲年。"]'),
('89bdafb7-06ab-4f0d-869a-9d9d0bb50e47','同柯東海出湖','陳宓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','欲訪西湖久未晴，故應穿屐踏泥行。',64,'全唐诗/poet.song.185000.json','["欲訪西湖久未晴，故應穿屐踏泥行。", "不因世事無時盡，那識波光有底清。", "翠竹碧蓮迷上下，雕欄畫閣壓崢嶸。", "扁舟正好頻來買，烟景何人與子爭。"]'),
('e1bf42ff-ddf2-43d8-810d-777b4e88f310','題妙寂僧無礙端硯','陳宓','宋','宋诗','song-poetry','','[]','紫潤携來愜性情，藍田空負價連城。',64,'全唐诗/poet.song.185000.json','["紫潤携來愜性情，藍田空負價連城。", "揮殘老兔猶能健，研盡輕螺未覺聲。", "淵底取歸龍想睡，巖心鑿破地須驚。", "我無才思長懷抱，元氣何年結得成。"]'),
('288f240a-671f-4595-ae46-af4a3cb01c50','題妙寂僧無礙明碧軒','陳宓','宋','宋诗','song-poetry','','[]','何處便宜養性情，禪床更著玉縱橫。',32,'全唐诗/poet.song.185000.json','["何處便宜養性情，禪床更著玉縱橫。", "應是高人幽隠地，開軒遠月迥雙明。"]'),
('3fa946ed-cd78-4fcc-a57f-b49eb1643adf','見月','陳宓','宋','宋诗','song-poetry','','[]','皓月忽從牆角見，好風時送竹聲來。',32,'全唐诗/poet.song.185000.json','["皓月忽從牆角見，好風時送竹聲來。", "事隨日出無時暇，薄暮塵襟始一開。"]'),
('89bcb5f8-4d55-4882-b00d-fa003fd0e869','問月','陳宓','宋','宋诗','song-poetry','','[]','百萬蒼生罹熱惱，三年素女苦高寒。',32,'全唐诗/poet.song.185000.json','["百萬蒼生罹熱惱，三年素女苦高寒。", "清光若解知民瘼，留與人間夜夜看。"]'),
('aea39f88-4adc-4d49-82d7-30fea8c3e2c1','素馨茉莉  其一','陳宓','宋','宋诗','song-poetry','','[]','骨細肌豐一樣香，沉香亭北象牙床。',32,'全唐诗/poet.song.185000.json','["骨細肌豐一樣香，沉香亭北象牙床。", "移根若向清都植，應憶當年瘴雨鄉。"]'),
('6210d6a3-c02b-4b67-aca6-11679de18c66','素馨茉莉  其二','陳宓','宋','宋诗','song-poetry','','[]','姊娣雙承雨露恩，至今猶有斷腸魂。',64,'全唐诗/poet.song.185000.json','["姊娣雙承雨露恩，至今猶有斷腸魂。", "道人不受濃香足，四山甘雨已如傾。", "蚤知縣令才能薄，頼有禪翁願力宏。", "宿麥頓蘇民氣樂，更期膏潤接春耕。"]'),
('885b865a-1dc4-4a08-9ee9-f650788ae492','欲登蓬萊山謝雨恐泥濘不可行是早忽晴併紀其異','陳宓','宋','宋诗','song-poetry','','[]','喧枕浪浪直到明，驅車欲謝却成晴。',64,'全唐诗/poet.song.185000.json','["喧枕浪浪直到明，驅車欲謝却成晴。", "天人契合豈無意，草木□途俱有情。", "賸作寰中三日施，依前岩畔一泓清。", "願言嗣此長霑足，得暇還來聽午鯨。"]'),
('e5f0d8fc-e7b1-4c8f-8b88-eb0ed90eb59d','予宰安溪日景山相訪還山之興浩不可留詩以送之','陳宓','宋','宋诗','song-poetry','','[]','經年不見意彌親，來愜相思洗吏塵。',64,'全唐诗/poet.song.185000.json','["經年不見意彌親，來愜相思洗吏塵。", "陋邑苦難留上客，好山終是戀高人。", "同看臘底梅筠月，便想雲間笋蕨春。", "此去書堂能幾驛，詩筒莫憚往來頻。"]'),
('5b1517b6-6d0b-4a7b-989d-f12a81b9a772','寄題真希元毋自欺齋','陳宓','宋','宋诗','song-poetry','','[]','本來真是與真非，祇爲因循逐物移。',64,'全唐诗/poet.song.185000.json','["本來真是與真非，祇爲因循逐物移。", "當面雷同還自笑，此心機動已天知。", "窮通有命寧由我，邪正唯人更問誰。", "委曲周防終恐拙，何如直道了無危。"]'),
('3cd84b6e-2bb8-4221-a09a-2c5fba597aed','謝鄭夾漈子惠詩索草堂扁榜  其一','陳宓','宋','宋诗','song-poetry','','[]','五十種書今幾見，數千年史尚堪傳。',32,'全唐诗/poet.song.185000.json','["五十種書今幾見，數千年史尚堪傳。", "草堂底用標遺跡，自是鄉人苦愛貧。"]'),
('7b6403f0-e32d-482d-b306-8c6b8d0ffdde','謝鄭夾漈子惠詩索草堂扁榜  其二','陳宓','宋','宋诗','song-poetry','','[]','子長健筆許誰隣，特起先生繼獲麟。',32,'全唐诗/poet.song.185000.json','["子長健筆許誰隣，特起先生繼獲麟。", "摹寫遺書禮嚴像，豈無當代好賢人。"]'),
('666658da-b716-40ba-877c-ffa5dca21216','謝鄭夾漈子惠詩索草堂扁榜  其三','陳宓','宋','宋诗','song-poetry','','[]','八齡幼子今頭白，袖有清詩忽到門。',32,'全唐诗/poet.song.185000.json','["八齡幼子今頭白，袖有清詩忽到門。", "前代謾誇棠與笏，何如詩禮典刑存。"]'),
('9b5f6267-70c4-4e93-861e-fc17a1a11b0c','次安溪趙簿雲津閣韵  其一','陳宓','宋','宋诗','song-poetry','','[]','西來一派接天流，誰結危欄占上游。',64,'全唐诗/poet.song.185000.json','["西來一派接天流，誰結危欄占上游。", "樹蘸碧波元不暑，沙攢白鷺更宜秋。", "沉酣勝處方知味，濡滯窮山未拙謀。", "欲把君詩鑱翠壁，聲名長與此溪留。"]'),
('e7dd5474-50b4-45de-8fdf-0ad0b5dd312b','次安溪趙簿雲津閣韵  其二','陳宓','宋','宋诗','song-poetry','','[]','兼旬積雨截晴虹，洗出溪山罨畫中。',64,'全唐诗/poet.song.185000.json','["兼旬積雨截晴虹，洗出溪山罨畫中。", "別浦漁歌來暝色，長橋人語半秋空。", "吏閑剩得三更月，民阜多逢五日風。", "作計追陪今恐後，杯盤隨意底須豐。"]'),
('45c5d7bb-c7d7-4584-a1e1-78b20b79174e','王主簿右州某日思其歸因見黄華動淵明之興方欲寄詩忽承佳句次韵見意  其一','陳宓','宋','宋诗','song-poetry','','[]','夢魂何日不家山，底事淹留數月間。',32,'全唐诗/poet.song.185000.json','["夢魂何日不家山，底事淹留數月間。", "忽見黄華羞泛酒，淵明心事若相關。"]'),
('eb016fc2-b457-4d52-899b-564b80352abf','王主簿右州某日思其歸因見黄華動淵明之興方欲寄詩忽承佳句次韵見意  其二','陳宓','宋','宋诗','song-poetry','','[]','靜坐思君秋日長，清波白鷺兩茫茫。',32,'全唐诗/poet.song.185000.json','["靜坐思君秋日長，清波白鷺兩茫茫。", "定應嚼遍湘纍菊，寄我新詩字字香。"]'),
('9125ccb0-7ffd-412f-b53c-1a81855ea4d3','登清水巖謝晴承知丞惠詩次韵爲謝','陳宓','宋','宋诗','song-poetry','','[]','田里今年少嘆嗟，前溪敢放夜痕加。',64,'全唐诗/poet.song.185000.json','["田里今年少嘆嗟，前溪敢放夜痕加。", "天開璧玉三千岫，水遶黄雲一萬家。", "古寺安閑茶可飽，深村取次酒能賒。", "歸來晚及西津渡，百丈虹梁喜有涯。"]'),
('7d1ec352-6ea1-4613-aab9-5303bdf0bc3a','和王主簿  其一','陳宓','宋','宋诗','song-poetry','','[]','水色嵐光杳靄間，詩人得句意偏閑。',32,'全唐诗/poet.song.185000.json','["水色嵐光杳靄間，詩人得句意偏閑。", "我今收拾胸中去，歸賦淮南大小山。"]'),
('ef3f5e39-7979-4347-9930-1cea7ae92f14','和王主簿  其二','陳宓','宋','宋诗','song-poetry','','[]','爲問西來何處船，風餐霜宿更安眠。',32,'全唐诗/poet.song.185000.json','["爲問西來何處船，風餐霜宿更安眠。", "殘燈一點明於月，只傍前洲白鷺邊。"]'),
('9690e0c7-e17f-4d5d-ae06-c70b5e6afb27','和王主簿  其三','陳宓','宋','宋诗','song-poetry','','[]','朅來十日佳眠食，爲愛溪山似客清。',32,'全唐诗/poet.song.185000.json','["朅來十日佳眠食，爲愛溪山似客清。", "我亦本無三宿戀，中年可奈故人情。"]'),
('23c3e309-f950-492b-a14c-79407335bc03','和王主簿  其四','陳宓','宋','宋诗','song-poetry','','[]','世間真色知何物，肯把溪山換莫愁。',32,'全唐诗/poet.song.185000.json','["世間真色知何物，肯把溪山換莫愁。", "擬具小舟乘月下，一尊相屬漾寒流。"]'),
('c6aff970-439b-4437-9efa-98a925175b55','題先公正獻詩集','陳宓','宋','宋诗','song-poetry','','[]','飛車去逐赤松仙，殘藁空留四十年。',64,'全唐诗/poet.song.185000.json','["飛車去逐赤松仙，殘藁空留四十年。", "致主恥居三代後，乞身期在二疏前。", "清朝厚眷真難報，白髮孤遺祇自憐。", "珍重我翁忠孝句，子孫百世更須傳。"]'),
('a0496773-1516-4014-ba75-ec8c6d10a400','賦梅堂閑吟  其一','陳宓','宋','宋诗','song-poetry','','[]','天公久不試鉛華，盡把清香付此花。',32,'全唐诗/poet.song.185000.json','["天公久不試鉛華，盡把清香付此花。", "白玉堂中春未動，等閑攀折野人家。"]'),
('f49a7559-3906-4028-84aa-f95fb03f6eb3','賦梅堂閑吟  其二','陳宓','宋','宋诗','song-poetry','','[]','祇知風骨清於玉，敢把精神看作花。',32,'全唐诗/poet.song.185000.json','["祇知風骨清於玉，敢把精神看作花。", "一陣異香明月下，定知來自玉皇家。"]'),
('a264a629-555b-41d2-84b3-3e859dacd773','賦梅堂閑吟  其三','陳宓','宋','宋诗','song-poetry','','[]','世間何物最鮮華，摇落林中第一花。',32,'全唐诗/poet.song.185000.json','["世間何物最鮮華，摇落林中第一花。", "作計莫輸蜂蝶後，深房淺萼便爲家。"]'),
('c376c1ef-3744-4e1d-aee4-d2f3ef2aea9b','賦梅堂閑吟  其四','陳宓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','謾自塵勞鬢欲華，故園空鏁未開花。',32,'全唐诗/poet.song.185000.json','["謾自塵勞鬢欲華，故園空鏁未開花。", "年年飽看春來去，輸與西湖處士家。"]'),
