('e5ca7062-0181-4bee-9c52-9dcbdfac5375','賦梅堂閑吟  其六','陳宓','宋','宋诗','song-poetry','','[]','窮冬天意似奢華，白璧明珠剩作花。',32,'全唐诗/poet.song.185000.json','["窮冬天意似奢華，白璧明珠剩作花。", "付與東風向何處，恩勤不爲五侯家。"]'),
('ca079da6-cd75-4a9a-8583-ec525c003cc0','賦梅堂閑吟  其七','陳宓','宋','宋诗','song-poetry','','[]','濃霜輕雪妬清華，暖日烘時祇見花。',32,'全唐诗/poet.song.185000.json','["濃霜輕雪妬清華，暖日烘時祇見花。", "天意似憐塵世界，故將茅舍換仙家。"]'),
('d70ecea7-8710-4eb4-be6f-d1b60789a21b','賦梅堂閑吟  其八','陳宓','宋','宋诗','song-poetry','','[]','地宜冬暖早韶華，回首牆東李亦花。',32,'全唐诗/poet.song.185000.json','["地宜冬暖早韶華，回首牆東李亦花。", "畢竟晨粧自羞澀，豈堪位置壽陽家。"]'),
('915256fb-da51-46bf-87e3-d74f04beb7bc','賦梅堂閑吟  其九','陳宓','宋','宋诗','song-poetry','','[]','金掌何人吸露華，爭如瓦盞泛霜花。',32,'全唐诗/poet.song.185000.json','["金掌何人吸露華，爭如瓦盞泛霜花。", "移床來傍花邊坐，底用雲嵐頂上家。"]'),
('46278689-242b-474c-8b0d-f20978eedfbe','賦梅堂閑吟  其一○','陳宓','宋','宋诗','song-poetry','','[]','老覺無情戀物華，玉塵那復惜飛花。',32,'全唐诗/poet.song.185000.json','["老覺無情戀物華，玉塵那復惜飛花。", "春風祇在襟懷裏，試問藍溪吏隠家。"]'),
('d286a8ef-b749-429c-886c-1ce2cadf7988','清水巖禱晴  其一','陳宓','宋','宋诗','song-poetry','','[]','作吏風塵頭欲白，此身那不自優游。',32,'全唐诗/poet.song.185000.json','["作吏風塵頭欲白，此身那不自優游。", "一心恰似商人婦，苦雨終風便作愁。"]'),
('70c36421-c094-41f8-999a-e46761646114','清水巖禱晴  其二','陳宓','宋','宋诗','song-poetry','','[]','簷聲喧耳歷三旬，雲氣低低過一春。',32,'全唐诗/poet.song.185000.json','["簷聲喧耳歷三旬，雲氣低低過一春。", "今日舉頭逢皎日，也知天道總由人。"]'),
('0cd61c79-9ee2-4a97-b51e-ca5ef75bd0a4','久不到流惠楊至之相訪邀遊楊以幹亟歸因呈之','陳宓','宋','宋诗','song-poetry','','[]','衆峰奇秀四圍旁，擁出千尋月樣塘。',64,'全唐诗/poet.song.185000.json','["衆峰奇秀四圍旁，擁出千尋月樣塘。", "隻鷺雙鳬自來往，圓荷細草競高長。", "密雲带雨天應近，晚照酣春水自香。", "幸有家人來共看，如何也作簿書忙。"]'),
('b376c407-55b5-43af-9fc9-1bfece3ffeab','約楊至之潘謙之登清水巖不果和潘韵','陳宓','宋','宋诗','song-poetry','','[]','春入溪山幾許深，擬陪杖屨遠追尋。',64,'全唐诗/poet.song.185000.json','["春入溪山幾許深，擬陪杖屨遠追尋。", "千章古木都凝綠，百囀黄鸝尚好音。", "君有佳人同笑語，我懷拙患阻登臨。", "移時竚立西塘上，有酒盈樽敢自斟。"]'),
('3329a9fd-70af-488b-9b24-ed5e2d0e7ce4','縣圃梔子花三重生簡潘君','陳宓','宋','宋诗','song-poetry','','[]','疎花早不奈香何，三疊瓊葩底用多。',32,'全唐诗/poet.song.185000.json','["疎花早不奈香何，三疊瓊葩底用多。", "最是動人情意處，黄梅已老未逢荷。"]'),
('0ea0b3ac-8256-47ad-88fc-7ec8295b8181','謝王丞餉臨漳火山綠筍  其一','陳宓','宋','宋诗','song-poetry','','[]','晚來細雨送輕愁，小院梅黄恰似秋。',64,'全唐诗/poet.song.186000.json','["晚來細雨送輕愁，小院梅黄恰似秋。", "忽得滿盤堆鶴頂，更驚觸眼出貓頭。", "祇知渴吻三危飲，却愧枯腸萬卷搜。", "多謝美人情鄭重，明珠見餉恐空投。"]'),
('89ca5e88-31be-4606-b4fb-298dde896705','謝王丞餉臨漳火山綠筍  其二','陳宓','宋','宋诗','song-poetry','','[]','撫民無術知何補，空負家山幾度秋。',64,'全唐诗/poet.song.186000.json','["撫民無術知何補，空負家山幾度秋。", "豈有甘凉來可口，但知朱墨苦埋頭。", "近城好景頻須到，適意新詩底用搜。", "從此若逢休暇日，定應閉戶轄深投。"]'),
('1695c2f9-1214-4628-9cf6-689c6040fd85','回吳信可謝寄唐人詩','陳宓','宋','宋诗','song-poetry','','[]','忽傳佳句到深林，總是鏗金戛玉音。',32,'全唐诗/poet.song.186000.json','["忽傳佳句到深林，總是鏗金戛玉音。", "長恨古人今不見，由來今古一般心。"]'),
('59598c5e-4754-43d6-8a50-40e1c3bea3a5','與友人中元作別九月十日復會中間節物不得共觀追酬所願有今夕在聊成小詩謝之','陳宓','宋','宋诗','song-poetry','','[]','兩逢佳節獨登樓，一醉樽前擬並酬。',32,'全唐诗/poet.song.186000.json','["兩逢佳節獨登樓，一醉樽前擬並酬。", "昨日黄華今更好，此宵明月勝中秋。"]'),
('63c222b6-20d8-4408-84b1-93a1ed31e221','贈丘漢叔','陳宓','宋','宋诗','song-poetry','','[]','自昔經明岱岳間，于今君獨得淵源。',64,'全唐诗/poet.song.186000.json','["自昔經明岱岳間，于今君獨得淵源。", "力扶正學人知懼，撥去浮言道自存。", "講貫一堂常奪席，異同諸子謾專門。", "懷奇莫嘆無知己，會見經幃待討論。"]'),
('cbe4333d-ce24-479b-924a-9bca8193e4af','和王丞惠酒次韵','陳宓','宋','宋诗','song-poetry','','[]','春風出甕初迎臘，和氣烘人欲滿堂。',32,'全唐诗/poet.song.186000.json','["春風出甕初迎臘，和氣烘人欲滿堂。", "多謝分來壽慈母，年年喜得對梅嘗。"]'),
('e1c4b8cc-5912-4bd6-941b-9de2785136bf','鳬茈餉王丞','陳宓','宋','宋诗','song-poetry','','[]','仙谿賸得紫琅玕，風味仍同荔子看。',32,'全唐诗/poet.song.186000.json','["仙谿賸得紫琅玕，風味仍同荔子看。", "何似清漳霜後橘，野人還敢薦君盤。"]'),
('fa2f1ae0-06c2-4b36-832a-480830a071f1','承同安宰惠朱文公祠堂記輒以小詩爲謝','陳宓','宋','宋诗','song-poetry','','[]','紫陽仙伯昔曾來，陳迹何人戀碧苔。',32,'全唐诗/poet.song.186000.json','["紫陽仙伯昔曾來，陳迹何人戀碧苔。", "爲愛同安毛令尹，恩勤祠宇奉尊罍。"]'),
('0d10a007-2c21-4403-844c-ac1e6fdbc897','南園小船','陳宓','宋','宋诗','song-poetry','','[]','五年前具一扁舟，四歲枯乾水絕流。',64,'全唐诗/poet.song.186000.json','["五年前具一扁舟，四歲枯乾水絕流。", "今日重將篷竹理，暇朝聊作芰荷遊。", "十分清浪堪飛棹，廿里長溝足下鉤。", "七袠有親顛欲華，人生舍此更何求。"]'),
('bf866c66-1de7-4b15-bfa2-d2c1cdc7b5f5','謝雨清水巖  其一','陳宓','宋','宋诗','song-poetry','','[]','樓閣重重俯見山，炎風吹雪到窗間。',32,'全唐诗/poet.song.186000.json','["樓閣重重俯見山，炎風吹雪到窗間。", "聯鑣來此班荆坐，分得高僧半日閑。"]'),
('19a84248-1af1-4106-a402-05bb38224680','謝雨清水巖  其二','陳宓','宋','宋诗','song-poetry','','[]','我來謝雨到名山，記得重來半歲間。',32,'全唐诗/poet.song.186000.json','["我來謝雨到名山，記得重來半歲間。", "却笑乖龍太多事，不如科斗得長閑。"]'),
('da0c33df-0494-4784-b1cb-e752821a9552','秋夜四鼓玩月  其一','陳宓','宋','宋诗','song-poetry','','[]','露氣盤空月墮煙，開軒移榻卧檐前。',32,'全唐诗/poet.song.186000.json','["露氣盤空月墮煙，開軒移榻卧檐前。", "近來不慮消磨盡，空洞胸懷但貯天。"]'),
('e6a9a5e0-2ba9-40e7-b08f-c665bedbeead','秋夜四鼓玩月  其二','陳宓','宋','宋诗','song-poetry','','[]','琅玕衣袂竹方床，熱惱肝脾頓得凉。',32,'全唐诗/poet.song.186000.json','["琅玕衣袂竹方床，熱惱肝脾頓得凉。", "誰送苕溪來枕畔，輕裘短棹水雲鄉。"]'),
('e773ad84-6886-46fb-aa92-bc26b666c056','鳳池橋成余長泰以詩賀次韵謝之','陳宓','宋','宋诗','song-poetry','','[]','驂鸞翼翼裊清風，眼見雲霄有路通。',64,'全唐诗/poet.song.186000.json','["驂鸞翼翼裊清風，眼見雲霄有路通。", "自是衆賢欣出力，何如小己敢貪功。", "指揮須得千人敵，遲速都申一念中。", "已築新堤平似掌，登橋人與此橘同。"]'),
('7642aa9a-cd6c-4014-a734-126304812769','安溪鹿鳴呈諸先輩','陳宓','宋','宋诗','song-poetry','','[]','威鳳來翔羽翼新，藍溪風氣益溫醇。',64,'全唐诗/poet.song.186000.json','["威鳳來翔羽翼新，藍溪風氣益溫醇。", "彤墀看唱三名外，璧水猶登四十人。", "仙李蟠根連月窟，桂枝平步折天津。", "雪窗莫忘辛勤日，省酒簪花曲水濱。"]'),
('e3a410b4-b5f9-4b44-88ab-12494af7fcf7','四月下旬見黄梅水梔花','陳宓','宋','宋诗','song-poetry','','[]','人間桃李漫春風，流水飛埃過眼空。',32,'全唐诗/poet.song.186000.json','["人間桃李漫春風，流水飛埃過眼空。", "誰信黄梅深院靜，水梔如玉映群紅。"]'),
('8bc9304d-a70c-48b0-8bed-777a928c487c','五月下旬雨後喜晴','陳宓','宋','宋诗','song-poetry','','[]','曉來初日滿林光，猶見枝頭梅子黄。',32,'全唐诗/poet.song.186000.json','["曉來初日滿林光，猶見枝頭梅子黄。", "一對蟬聲相上下，柳絲摇曳與俱長。"]'),
('76de3745-3572-4cc0-a577-79869444acfa','同喻景山遊月湖','陳宓','宋','宋诗','song-poetry','','[]','兼旬不到月湖來，無數荷花雨裏開。',64,'全唐诗/poet.song.186000.json','["兼旬不到月湖來，無數荷花雨裏開。", "燕是舊知頻遶棟，蟬如有意共銜杯。", "公庭兀坐雖無暇，佳友同携得幾回。", "冒雨作閑成勝賞，兒童迎道任相咍。"]'),
('e758e607-1116-46cb-a36e-2df4c6a403f2','宰邑垂滿喜與王梅溪孫主簿合并承入秋闈當別兩月其可無詩以志此恨  其一','陳宓','宋','宋诗','song-poetry','','[]','貢士何年屋萬間，手栽仙桂萬人攀。',32,'全唐诗/poet.song.186000.json','["貢士何年屋萬間，手栽仙桂萬人攀。", "聞孫雅有祖風烈，想見霜袍萬眼環。"]'),
('8d4ee824-b6fb-4c1f-a6a3-70b80dd4a9b0','宰邑垂滿喜與王梅溪孫主簿合并承入秋闈當別兩月其可無詩以志此恨  其二','陳宓','宋','宋诗','song-poetry','','[]','兩家事契幾人同，一見風流憶乃翁。',32,'全唐诗/poet.song.186000.json','["兩家事契幾人同，一見風流憶乃翁。", "何事別離當兩月，空山兀坐晚秋風。"]'),
('f29f3592-704d-4e47-bed3-7ff3b5e9031b','九日登安溪鳳山','陳宓','宋','宋诗','song-poetry','','[]','鳳凰天上遠來翔，好看連天碧玉絛。',64,'全唐诗/poet.song.186000.json','["鳳凰天上遠來翔，好看連天碧玉絛。", "不學無才空老大，逢辰有客盡英豪。", "癡人臺峻爭馳馬，我輩身輕一似猱。", "笑倚西風傾菊酒，醉歸穩跨貫山鰲。"]'),
('ba475be7-3919-4a5e-ad97-6ecc04c7dbfe','和贊府趙師洪韵','陳宓','宋','宋诗','song-poetry','','[]','明珠顆顆映寒驪，六月清風滿袖知。',64,'全唐诗/poet.song.186000.json','["明珠顆顆映寒驪，六月清風滿袖知。", "祇覺衰容增老媿，空煩妙語爲噓吹。", "三年刻楮成何事，一日哦松剩得詩。", "從此年豐公事少，夕陽橋上賦漣漪。"]'),
('1ff4217a-b42b-4aa4-8a1d-4737f27aa140','縣治登梁和寄居余叔濟韵  其一','陳宓','宋','宋诗','song-poetry','','[]','古縣公庭二百春，聊因風雨一番新。',64,'全唐诗/poet.song.186000.json','["古縣公庭二百春，聊因風雨一番新。", "恨無尺寸堪酬主，敢有絲毫更擾民。", "方嘆閭閻驚脫水，却慚梁棟欲超塵。", "年豐俗美多餘暇，鴈鶩行中看雀馴。"]'),
('49b24f06-816f-4388-b6eb-83d11ea372ea','縣治登梁和寄居余叔濟韵  其二','陳宓','宋','宋诗','song-poetry','','[]','賓僚滿座昔難知，盡是才當漢石渠。',64,'全唐诗/poet.song.186000.json','["賓僚滿座昔難知，盡是才當漢石渠。", "訟牒已資賢共次，茶甌聊復話公餘。", "千村早見刀爲犢，比屋仍看經荷鋤。", "疎拙却便明月夜，小窗松竹謾觀書。"]'),
('2831f551-0d00-4aad-b5d3-d57811bc584d','和喻景山賦梅韵','陳宓','宋','宋诗','song-poetry','','[]','質白偏能照玉船，體輕終愛舞蹁躚。',64,'全唐诗/poet.song.186000.json','["質白偏能照玉船，體輕終愛舞蹁躚。", "眼前欲賦半妝額，夢裏須携五色掾。", "愁對素蟾寒寂寞，故燒紅蠟暖清娟。", "寄聲青女休相妬，不學海棠酣夜眠。"]'),
('f9519c55-2932-461a-b8e7-c376188f5b82','同林潘二先生登舟  其一','陳宓','宋','宋诗','song-poetry','','[]','暇日衣襟嬾自船，扁舟不繫任風緣。',64,'全唐诗/poet.song.186000.json','["暇日衣襟嬾自船，扁舟不繫任風緣。", "人間避暑疑無地，湖上乘凉別有天。", "魚靜不驚香餌下，花紅偏稱夕陽邊。", "從今日日須來看，才隔秋風便數年。"]'),
('f4d9614f-c04c-4e96-a374-518f743e5785','同林潘二先生登舟  其二','陳宓','宋','宋诗','song-poetry','','[]','何日長橋一酒船，簑衣擺盡世間緣。',64,'全唐诗/poet.song.186000.json','["何日長橋一酒船，簑衣擺盡世間緣。", "乘風弄笛多蓮夏，吹火烹鱸欲雪天。", "山際煙雲來有底，湖中風月浩無邊。", "細看造化渾無老，只有朱顔易得年。"]'),
('4c0c0f80-d7b2-4034-83e0-13c576e4cfa4','謝黄齋長送雙蓮和其韵','陳宓','宋','宋诗','song-poetry','','[]','雙蓮價重百隋侯，聞道飛觴日夜浮。',64,'全唐诗/poet.song.186000.json','["雙蓮價重百隋侯，聞道飛觴日夜浮。", "那得此花開鳳沼，依前盛事占鰲頭。", "直如晁董同時對，清似夷齊並臂游。", "快誦君詩驚倦眼，和篇雖拙敢遲留。"]'),
('27d40563-7f96-4702-94eb-a2f7412d411f','放生池産雙蓮  其一','陳宓','宋','宋诗','song-poetry','','[]','不作風流時樣粧，月明宮殿舞霓裳。',32,'全唐诗/poet.song.186000.json','["不作風流時樣粧，月明宮殿舞霓裳。", "須知並立慇懃意，爲祝吾皇聖壽長。"]'),
('b4f23d57-42a9-4777-a989-9af89c83958e','放生池産雙蓮  其二','陳宓','宋','宋诗','song-poetry','','[]','年來仙實兩呈祥，衮衮公侯詎可量。',32,'全唐诗/poet.song.186000.json','["年來仙實兩呈祥，衮衮公侯詎可量。", "勞力更宜勤積善，天公元自愛詞章。"]'),
('2ed3b15c-b18a-4237-9aaa-8712e264dc91','題清隠祠','陳宓','宋','宋诗','song-poetry','','[]','高標千載有誰攀，風雨祠堂尚一間。',32,'全唐诗/poet.song.186000.json','["高標千載有誰攀，風雨祠堂尚一間。", "寄語當年詹令尹，吾今亦欲早歸山。"]'),
('e02f27e3-c536-4ae7-a0cf-cb1253fc5182','登蓬萊山謝雨','陳宓','宋','宋诗','song-poetry','','[]','師座茲山幾百春，精神長是念斯民。',32,'全唐诗/poet.song.186000.json','["師座茲山幾百春，精神長是念斯民。", "我非濟旱爲霖手，合作巖隈洒掃人。"]'),
('3bc43398-4fc5-4624-9d09-0fa931a1c816','臘望玩月','陳宓','宋','宋诗','song-poetry','','[]','癡雨頓晴如有約，素娥雖老更多情。',32,'全唐诗/poet.song.186000.json','["癡雨頓晴如有約，素娥雖老更多情。", "何人肯向雪中看，已作新年滿意明。"]'),
('962f0635-c704-482b-8f91-a24f79ed6a34','雲津閣','陳宓','宋','宋诗','song-poetry','','[]','山色月中猶見碧，溪流枕上更宜聲。',32,'全唐诗/poet.song.186000.json','["山色月中猶見碧，溪流枕上更宜聲。", "身輕閣穩欣投宿，此是還家第一程。"]'),
('230d9b3c-f3e8-400c-9a6f-dc92979fd115','早起','陳宓','宋','宋诗','song-poetry','','[]','三年飽識溪山面，未省煙雲際曉生。',32,'全唐诗/poet.song.186000.json','["三年飽識溪山面，未省煙雲際曉生。", "閣迥樓長正相映，桃源圖上有人行。"]'),
('7f362915-6283-437f-91ff-4ba3757a2a04','和卓省元韵','陳宓','宋','宋诗','song-poetry','','[]','六十堂堂一講師，平生矻矻鬢成絲。',64,'全唐诗/poet.song.186000.json','["六十堂堂一講師，平生矻矻鬢成絲。", "紫陽道坦行來熟，洛水源深向上窺。", "身豈匏瓜常不食，味耽昌歜有同誰。", "旁人莫笑饑腸苦，回頰甘香勝似飴。"]'),
('d91e247c-fa03-451a-8b07-64b0427df54d','呈章通判','陳宓','宋','宋诗','song-poetry','','[]','蚤歲曾從諸老游，溫恭儒雅更風流。',64,'全唐诗/poet.song.186000.json','["蚤歲曾從諸老游，溫恭儒雅更風流。", "閩中善政皆堪紀，身外虛名底用求。", "滿榼載春行樂處，長途未暑候如秋。", "經年每恨過從少，况是難爲兩月留。"]'),
('f9fab781-178b-4888-baaa-650e07589844','次林司戶清水巖韵','陳宓','宋','宋诗','song-poetry','','[]','禱雨當年百丈峰，森森夾徑聳脩筇。',64,'全唐诗/poet.song.186000.json','["禱雨當年百丈峰，森森夾徑聳脩筇。", "甘霖尚想四垂合，清境無因一到重。", "仙伯遺縱參佛跡，王公新詠張軍容。", "索詩尚及疎庸令，筳寸何堪擊鉅鍾。"]'),
('867e25ad-86b6-48de-9989-27f427b763f6','次喻景山韵  其一','陳宓','宋','宋诗','song-poetry','','[]','眼前兒輩謾嘈嘈，癢處憑誰著手搔。',32,'全唐诗/poet.song.186000.json','["眼前兒輩謾嘈嘈，癢處憑誰著手搔。", "堪恨紫陽雙鬢白，閉門吮筆自箋騷。"]'),
('1dc2c11a-ec28-4e7d-8bfc-a5f5a0553f81','次喻景山韵  其二','陳宓','宋','宋诗','song-poetry','','[]','連雨昏濛隠月痕，月邊新蘂故應存。',32,'全唐诗/poet.song.186000.json','["連雨昏濛隠月痕，月邊新蘂故應存。", "春風日夜來無限，欺得陶家半掩門。"]'),
('b1a3017a-4b09-428a-95a1-9cf18028f8f3','次喻景山韵  其三','陳宓','宋','宋诗','song-poetry','','[]','凌寒愛酒謫仙人，一笑能回萬壑春。',32,'全唐诗/poet.song.186000.json','["凌寒愛酒謫仙人，一笑能回萬壑春。", "難佩待歸天上去，却看桃李媚紅塵。"]'),
('fb3210c0-033a-4f23-87d6-b5d05e02641a','次喻景山韵  其四','陳宓','宋','宋诗','song-poetry','','[]','晨起尋閑共話難，夜深相對菊花寒。',32,'全唐诗/poet.song.186000.json','["晨起尋閑共話難，夜深相對菊花寒。", "如何風雨多才思，故作扁舟上下灘。"]'),
('b215467d-8842-42c4-99dd-45d22319568b','次喻景山韵  其五','陳宓','宋','宋诗','song-poetry','','[]','休嗟光景速於飛，爲愛春從柳上歸。',32,'全唐诗/poet.song.186000.json','["休嗟光景速於飛，爲愛春從柳上歸。", "好是新年添一歲，却知今是與前非。"]'),
('ccbc0b23-f747-4ff8-af01-71c61974f8a4','得梅溪像','陳宓','宋','宋诗','song-poetry','','[]','生平尊仰梅溪像，望日遷居恪及門。',32,'全唐诗/poet.song.186000.json','["生平尊仰梅溪像，望日遷居恪及門。", "誕子偶然同是日，命名端合作梅孫。"]'),
('bd315522-5561-44cc-bfd3-1d2e008f4fd7','贈林教諭','陳宓','宋','宋诗','song-poetry','','[]','囊中惟有聖賢書，宅是簞瓢陋巷圖。',32,'全唐诗/poet.song.186000.json','["囊中惟有聖賢書，宅是簞瓢陋巷圖。", "我一見君先自愧，題詩歸擬揭庭隅。"]'),
('505d52f3-983d-4ec3-bf0c-9c34b5293c79','和柯東海趣歸韵','陳宓','宋','宋诗','song-poetry','','[]','塵土三年事一官，歸心如馬脫鞿鞍。',32,'全唐诗/poet.song.186000.json','["塵土三年事一官，歸心如馬脫鞿鞍。", "莫嫌頭髮半斑白，留得雙眸看歲寒。"]'),
('0ef09b57-58b0-47e5-870f-834cbaf87d32','謝傅監倉','陳宓','宋','宋诗','song-poetry','','[]','昔年常侍紫樞仙，風骨森然在眼前。',64,'全唐诗/poet.song.186000.json','["昔年常侍紫樞仙，風骨森然在眼前。", "一覽十行俱默誦，三更殘卷尚朱箋。", "詩書自古稱難繼，衣鉢于今信有傳。", "每拜名章唯自愧，思慳莫和短篇長。"]'),
('b230503e-aa89-4c5c-8155-f2f498529457','赴官安溪回與柯東海同宿閑吟','陳宓','宋','宋诗','song-poetry','','[]','道逢酒舍定遲回，無奈詩篇費剪裁。',32,'全唐诗/poet.song.186000.json','["道逢酒舍定遲回，無奈詩篇費剪裁。", "忽得好風還自喜，那知細雨隔溪來。"]'),
('0a327754-2cd1-4fb2-8e7c-6f388222c296','行在端午','陳宓','宋','宋诗','song-poetry','','[]','百萬人家夜雨鳴，市聲喚出曉來晴。',32,'全唐诗/poet.song.186000.json','["百萬人家夜雨鳴，市聲喚出曉來晴。", "誰知天與吾皇意，要不妨農不害民。"]'),
('c20ccddd-028b-4a28-a91a-30c719ff1245','月巖  其一','陳宓','宋','宋诗','song-poetry','','[]','誰將玉斧鑿嵐煙，放出團團白晝天。',32,'全唐诗/poet.song.186000.json','["誰將玉斧鑿嵐煙，放出團團白晝天。", "自是天公恨盈缺，故開雲月要長圓。"]'),
('8f9ea571-8041-4c60-9710-ceb45d6a94eb','月巖  其二','陳宓','宋','宋诗','song-poetry','','[]','人間元有廣寒宮，誰道仙凡路不通。',32,'全唐诗/poet.song.186000.json','["人間元有廣寒宮，誰道仙凡路不通。", "借問蓬萊相近否，不須七椀去乘風。"]'),
('facb8beb-9adf-45c0-b6c3-e9f12139b20c','月巖  其三','陳宓','宋','宋诗','song-poetry','','[]','常時百步馬先疲，今日巖前故不遲。',32,'全唐诗/poet.song.186000.json','["常時百步馬先疲，今日巖前故不遲。", "回首兔宮猶未遠，會須千里巧相隨。"]'),
('78fb5d32-63fd-4cce-9d19-ff93bc1a411c','丫頭巖  其一','陳宓','宋','宋诗','song-poetry','','[]','看盡行人兩鬢秋，雙鬟猶自結丫頭。',32,'全唐诗/poet.song.186000.json','["看盡行人兩鬢秋，雙鬟猶自結丫頭。", "梳風櫛雨常如沐，送往迎來不解愁。"]'),
('731ec4a8-8113-4372-ac47-f9bd18998561','丫頭巖  其二','陳宓','宋','宋诗','song-poetry','','[]','造物肧腪何日始，人間歲月謾川流。',32,'全唐诗/poet.song.186000.json','["造物肧腪何日始，人間歲月謾川流。", "我行自役真堪笑，有此登臨恨莫留。"]'),
('d09841b0-f471-4307-bb65-250b456f3b93','湯泉','陳宓','宋','宋诗','song-poetry','','[]','洗垢清塵一派湯，瀹蔬溉稻却甘凉。',64,'全唐诗/poet.song.186000.json','["洗垢清塵一派湯，瀹蔬溉稻却甘凉。", "難將人力營爲勝，須信天工造化長。", "井小常時供鼎沸，澤多終歲遍山陽。", "我生幾度經行此，可笑區區有底忙。"]'),
('52c3fdcc-82ea-4dab-a572-82a0f81d176a','五月六日雨','陳宓','宋','宋诗','song-poetry','','[]','山雲乍展青油幕，檐雨齊神白玉簪。',32,'全唐诗/poet.song.186000.json','["山雲乍展青油幕，檐雨齊神白玉簪。", "多謝天公辦豐歲，野人先擬粟盈甔。"]'),
('df126389-70b0-4ebc-a3bd-5aecae268d92','重九','陳宓','宋','宋诗','song-poetry','','[]','長年佳節近重陽，到骨深恩一味凉。',64,'全唐诗/poet.song.186000.json','["長年佳節近重陽，到骨深恩一味凉。", "鳳尾有心堪悅目，雞頭當穀可充腸。", "凌雲穿月開丹桂，映日排空數拒霜。", "莫與春光較先後，請君晚節玩秋芳。"]'),
('cd27529f-36cf-4223-9ca5-11c3efbb8eb1','喜雨','陳宓','宋','宋诗','song-poetry','','[]','連日暘烏不敢驕，放教清雨出層霄。',32,'全唐诗/poet.song.186000.json','["連日暘烏不敢驕，放教清雨出層霄。", "誰言六月無冰雪，丈三餘深壓畫橋。"]'),
('fc9a7bb0-dec9-40b2-9554-d62bcd4a9a46','和林堂長第一溪山韵','陳宓','宋','宋诗','song-poetry','','[]','伊誰排比此溪山，祇與高人倚徙看。',64,'全唐诗/poet.song.186000.json','["伊誰排比此溪山，祇與高人倚徙看。", "不是三秋足風露，從來六月亦清寒。", "雙鋒未用平殘虜，巨刃先將剸險灘。", "我亦形容最佳處，崔詩在上句成難。"]'),
('765ef20a-4a30-467f-b39f-34f3a97c5fb0','和林堂長及林教龍門三灘之什','陳宓','宋','宋诗','song-poetry','','[]','渴絕河流幾萬年，如何枵腹卧大湫。',64,'全唐诗/poet.song.186000.json','["渴絕河流幾萬年，如何枵腹卧大湫。", "挾風長使天難暑，噓氣能令歲有秋。", "倦客擬將陪杖屨，高村贏得擅林丘。", "平生不爲鱸魚鱠，笑看兒童理釣鈎。"]'),
('2696129c-815c-43f5-9df3-f8c88323c69b','詠荔子','陳宓','宋','宋诗','song-poetry','','[]','天垂甘露絳綃囊，凝作清冰更有香。',64,'全唐诗/poet.song.186000.json','["天垂甘露絳綃囊，凝作清冰更有香。", "偏與荷花妬顔色，不教盧橘見容光。", "蔡公筆妙曾分品，坡老名高合得嘗。", "最喜不爲妃子污，千年風月水雲鄉。"]'),
('3f879424-479c-4978-b92f-c822a30ead38','予守南康適當旱歲睹東坡玉澗留題喜雨書之庶幾新年三白之符也','陳宓','宋','宋诗','song-poetry','','[]','雪堂居士醉方熟，玉澗仙人冷不眠。',32,'全唐诗/poet.song.186000.json','["雪堂居士醉方熟，玉澗仙人冷不眠。", "送與安州潑醅酒，一年三白是豐年。"]'),
('247bb3a3-f9bc-484c-9b48-5954eab62461','初到南康示諸邑令','陳宓','宋','宋诗','song-poetry','','[]','田里三年兩旱乾，茅檐十室九饑寒。',32,'全唐诗/poet.song.186000.json','["田里三年兩旱乾，茅檐十室九饑寒。", "慇勤此日無他事，好把斯民子樣看。"]'),
('a040fe2a-df28-4ca1-b4ef-d98e69b5e94a','南康喜雪','陳宓','宋','宋诗','song-poetry','','[]','萬里乾坤一玉山，新春都作臘前寒。',64,'全唐诗/poet.song.186000.json','["萬里乾坤一玉山，新春都作臘前寒。", "滿園柳眼未曾破，何處梅花如許殘。", "䔩䔩每驚穿屋至，疎疎偏稱隔簾看。", "自慚老守無恩惠，空嘆編氓出戶難。"]'),
('b6282497-a187-46e5-81aa-01fe9729e082','題南康歸宗寺','陳宓','宋','宋诗','song-poetry','','[]','山陰逸氣追千古，不但揮毫一段奇。',32,'全唐诗/poet.song.186000.json','["山陰逸氣追千古，不但揮毫一段奇。", "到此風流故無恙，遊人休問舊來池。"]'),
('fc823ccd-67ea-4dee-a36a-1093cfc84124','嘉定戊寅秋同蔡念成諸人遊三疊泉泉舊名三級改今名巖間莓苔隠然有字如玉色衆皆曰古人留題也即而視之其末有密官二字餘皆似字而不可曉他日復往則不復有睹因作詩以紀之','陳宓','宋','宋诗','song-poetry','','[]','去城三十躡雲端，特地山靈縱我觀。',32,'全唐诗/poet.song.186000.json','["去城三十躡雲端，特地山靈縱我觀。", "白玉岩邊數行字，祇知末後密并官。"]'),
('4f2365d4-c91a-4821-8cf3-f9b3cb9b2364','贈羽士','陳宓','宋','宋诗','song-poetry','','[]','獨擅茲山四十年，凝之去後見君賢。',32,'全唐诗/poet.song.186000.json','["獨擅茲山四十年，凝之去後見君賢。", "羽衣時向雲間去，爲愛飛泉不肯仙。"]'),
('632c7e99-c304-4d47-9750-28f79fafe133','南康郡圃','陳宓','宋','宋诗','song-poetry','','[]','三沼流通作一家，清風偏趁夕陽斜。',32,'全唐诗/poet.song.186000.json','["三沼流通作一家，清風偏趁夕陽斜。", "我來退食知懷愧，敢對波心蓮子花。"]'),
('a99943da-6599-4f13-8ffc-fe4475ad3450','題冰玉堂','陳宓','宋','宋诗','song-poetry','','[]','此是劉君處士家，茅簷猶想舊橫斜。',32,'全唐诗/poet.song.186000.json','["此是劉君處士家，茅簷猶想舊橫斜。", "我今添著朱夫子，薄祀秋初薦水花。"]'),
('6121abc8-0ba3-42fe-9b53-ec9950ee2908','南康食芡梨','陳宓','宋','宋诗','song-poetry','','[]','吳頭楚尾將三載，芡觜梨腮又一秋。',32,'全唐诗/poet.song.186000.json','["吳頭楚尾將三載，芡觜梨腮又一秋。", "豈爲鱸魚覓歸去，在家飲水百無憂。"]'),
('d59d90c4-8261-4514-8774-1be28929711c','和天台戴復古韵','陳宓','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','半生胸次著嵯峨，到得廬山鬢欲皤。',64,'全唐诗/poet.song.186000.json','["半生胸次著嵯峨，到得廬山鬢欲皤。", "列岫但蒙排闥入，一壺未許扣舷歌。", "清風六月猶嫌剩，明月三秋不厭多。", "擬向清朝新白鹿，結茅深處傍松坡。"]'),
('33e6f6a1-35ee-4ddd-823c-176c5aa3ef88','陪潘王二丈池上','陳宓','宋','宋诗','song-poetry','','[]','薰風萬蓋擁輕紅，長是相看六月中。',32,'全唐诗/poet.song.186000.json','["薰風萬蓋擁輕紅，長是相看六月中。", "忽有一花迎白露，定應來伴木芙容。"]'),
('f70fa5d5-dec1-415c-af84-73fc8ffb0604','題開先','陳宓','宋','宋诗','song-poetry','','[]','距城近只十五里，三度來遊兩載中。',64,'全唐诗/poet.song.186000.json','["距城近只十五里，三度來遊兩載中。", "山骨潄來成白玉，水痕深處見蒼龍。", "竹間待月爲佳友，柱上留題憶長公。", "此去重來知幾日，携家戀別莫怱怱。"]'),
('f024d55f-3a11-463e-ae2e-8cfd1e66ed65','八月十日同潘王遊曾城和潘韵','陳宓','宋','宋诗','song-poetry','','[]','羌廬聚處秋將半，山色湖光翠映璃。',64,'全唐诗/poet.song.186000.json','["羌廬聚處秋將半，山色湖光翠映璃。", "河漢乘槎端可到，蓬壺跨海屹難移。", "織織天外知商舶，獵獵沙頭見酒旗。", "欲豁塵襟須得月，題詩仍記共來時。"]'),
('a0d68193-2022-4315-8452-748b4288cdf8','泛舟遊曾城阻風','陳宓','宋','宋诗','song-poetry','','[]','奉親來此別湖山，九日先偷一日閑。',64,'全唐诗/poet.song.186000.json','["奉親來此別湖山，九日先偷一日閑。", "四面平鋪蒼玉佩，遠峰偏結碧螺鬟。", "一杯且奉慈顔喜，兩載真成短鬢斑。", "珍重南風如有意，片帆留滯故相攀。"]'),
('fbb6d343-7879-4d33-a08a-007831d34fd7','題雲石深趣堂','陳宓','宋','宋诗','song-poetry','','[]','廣文官舍先無塵，誰著嵐光几上陳。',64,'全唐诗/poet.song.186000.json','["廣文官舍先無塵，誰著嵐光几上陳。", "个裏盡消三伏暑，胸中長作四時春。", "不因泉石耽成癖，那識簞瓢味更真。", "顧我年來羈吏鞅，清閑羞見讀書人。"]'),
('296efb10-376e-45d5-aea2-7b6f125c75fd','題湖堂長春風堂','陳宓','宋','宋诗','song-poetry','','[]','柯翰由來元氣同，要須壯歲似兒童。',32,'全唐诗/poet.song.186000.json','["柯翰由來元氣同，要須壯歲似兒童。", "君家友愛誰能比，一榻長如二月中。"]'),
('ddb651cc-9965-453e-9573-39090530de3a','廬山愛蓮堂觀雨','陳宓','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','秀色真香先自清，更將輕雨出芳明。',32,'全唐诗/poet.song.186000.json','["秀色真香先自清，更將輕雨出芳明。", "蕭蕭打葉雖堪聽，爭似時時瀉水聲。"]'),
('3e155057-84c5-412c-a6c0-33dbe82f4b0e','陪趙工部三峽白鹿之遊有感而賦  其一','陳宓','宋','宋诗','song-poetry','','[]','昔年相見尚兒童，今日同遊鬢欲翁。',32,'全唐诗/poet.song.186000.json','["昔年相見尚兒童，今日同遊鬢欲翁。", "佳處山川總如舊，見君如見紫陽公。"]'),
('6c762fdf-72a8-436a-a0cd-98ca082b019c','陪趙工部三峽白鹿之遊有感而賦  其二','陳宓','宋','宋诗','song-poetry','','[]','一澗縈紆與洞深，長年金石孔堂音。',32,'全唐诗/poet.song.186000.json','["一澗縈紆與洞深，長年金石孔堂音。", "此身無計巢雲壑，歸去蓬窗只此心。"]'),
('8d931466-1829-4b37-a45a-d60fdc5306bf','和傅監倉禱雨','陳宓','宋','宋诗','song-poetry','','[]','五月秧針尚未勻，忍看溝底欲生塵。',64,'全唐诗/poet.song.186000.json','["五月秧針尚未勻，忍看溝底欲生塵。", "禱祈已久勞州邑，禳禬終當狥士民。", "天道豈云難感格，人心無過定恭寅。", "新詩見寵非吾事，霖雨須還岩築人。"]'),
('b64a8819-3e9c-49c5-97df-ec89f1f06c7a','山丹五本盛開  其一','陳宓','宋','宋诗','song-poetry','','[]','今年丹荔逐南風，獨有名花發舊叢。',32,'全唐诗/poet.song.186000.json','["今年丹荔逐南風，獨有名花發舊叢。", "似恨庭前絳囊少，慇懃來獻繡毬紅。"]'),
('45971eff-2d2d-4b5b-9587-32a0fe1e1416','山丹五本盛開  其二','陳宓','宋','宋诗','song-poetry','','[]','簇簇丹葩巧作叢，開時兩月受薰風。',32,'全唐诗/poet.song.186000.json','["簇簇丹葩巧作叢，開時兩月受薰風。", "北人見此應偷眼，未羨猩唇鶴頂紅。"]'),
('0919680d-e2af-4ee4-bd64-b65047f24b81','謝何茂才惠詩  其一','陳宓','宋','宋诗','song-poetry','','[]','雅思追期正始音，若將擲地定成金。',32,'全唐诗/poet.song.186000.json','["雅思追期正始音，若將擲地定成金。", "年來塵土雙侵鬢，頼有清詩時一吟。"]'),
('42e36952-bf98-41c3-b359-2330508eee1d','謝何茂才惠詩  其二','陳宓','宋','宋诗','song-poetry','','[]','紅塵垂老得何郎，筆力駸駸到馬楊。',32,'全唐诗/poet.song.186000.json','["紅塵垂老得何郎，筆力駸駸到馬楊。", "更擬他年求妙語，青山深趣爲君藏。"]'),
('dc429db5-ac97-4eb2-b049-31e2679c029c','右','陳宓','宋','宋诗','song-poetry','','[]','詩跨唐人未數錢，定應妙思入風煙。',64,'全唐诗/poet.song.186000.json','["詩跨唐人未數錢，定應妙思入風煙。", "才堪華國華寧老，句得驚人即是仙。", "世事但將酬一醉，侯封那可敵千篇。", "天葩况值春初到，蜂蝶紛紛看撲緣。"]'),
('0534866b-d083-4fd5-8686-38dbfb3036fe','次方詩境韵','陳宓','宋','宋诗','song-poetry','','[]','久別何人與砭肓，新詩見寄味偏長。',64,'全唐诗/poet.song.186000.json','["久別何人與砭肓，新詩見寄味偏長。", "求仙已得丹升鼎，鑿石仍成玉作堂。", "暖日松筠香北牖，清風書卷散東床。", "靜中剩得無窮味，笑看蜂衙早晚忙。"]'),
('bbfd5109-d623-4084-98a1-19ea3393c639','和饒司理','陳宓','宋','宋诗','song-poetry','','[]','往年曾識老名儒，今日方欣拜履初。',64,'全唐诗/poet.song.186000.json','["往年曾識老名儒，今日方欣拜履初。", "小試不妨三語掾，平生何止五車書。", "詞源已作泉初注，德性仍知玉不如。", "自古活人由小利，會看囹圄著園蔬。"]'),
('8668202c-404b-49e0-9789-8df37e7d4f98','和方機宜  其一','陳宓','宋','宋诗','song-poetry','','[]','侵曉同穿紫翠寒，輕雲隨步去仍還。',64,'全唐诗/poet.song.186000.json','["侵曉同穿紫翠寒，輕雲隨步去仍還。", "誰言濱海無多地，著得擎天有底山。", "空闊望中愁目短，險巇歷盡覺心頑。", "石田樵汲真堪絬，豈惜疎茅結一間。"]'),
('e43c34d3-ffc8-49a9-99d3-8049187942ce','和方機宜  其二','陳宓','宋','宋诗','song-poetry','','[]','絕頂樵翁總是仙，花紅草綠自年年。',64,'全唐诗/poet.song.186000.json','["絕頂樵翁總是仙，花紅草綠自年年。", "瓊樓玉宇成虛誕，盤石長松足醉眠。", "小竇偏能施雨澤，深崖常恐出雲煙。", "遊人合作宿山計，家在孤城返照邊。"]'),
('1b51b8b8-c2cd-4115-bb19-cd48649b47ed','和鄭知縣遊山韵','陳宓','宋','宋诗','song-poetry','','[]','至樂山行未易加，不應疾走便堪誇。',32,'全唐诗/poet.song.186000.json','["至樂山行未易加，不應疾走便堪誇。", "清秋莫負重來約，世事從教似掀沙。"]'),
('0b37dcdb-2044-4074-a54e-ed781bf7eef3','和鄭潛夫遊山韵','陳宓','宋','宋诗','song-poetry','','[]','千仞巑岏本自平，只應蒼步欠徐行。',64,'全唐诗/poet.song.186000.json','["千仞巑岏本自平，只應蒼步欠徐行。", "回崖凈拭連城璧，廉石高羅武庫兵。", "風易生雲常澒洞，泉能作雨轉甘清。", "重遊須待九秋後，已約猿猱管送迎。"]'),
('004f05b9-d604-4d79-9717-fb286e46012c','和潘瓜山遊山韵','陳宓','宋','宋诗','song-poetry','','[]','直上通天只一門，千尋璧玉薦漥尊。',64,'全唐诗/poet.song.186000.json','["直上通天只一門，千尋璧玉薦漥尊。", "低頭直笑海堪挹，舉手常驚斗可捫。", "有月襟懷增洒落，無風衣袂自飛翻。", "山靈想見開顔笑，日暮遊人列炬喧。"]'),
('eca0a902-ee3f-4db7-b740-00a6737b868b','初到延平會四邑宰  其一','陳宓','宋','宋诗','song-poetry','','[]','經歲旱荒仍疾癘，字民職業合何如。',32,'全唐诗/poet.song.186000.json','["經歲旱荒仍疾癘，字民職業合何如。", "去年欠負都蠲了，好把新租議減除。"]'),
('f9810aa5-d575-4633-a01f-ab1ffebabe47','初到延平會四邑宰  其二','陳宓','宋','宋诗','song-poetry','','[]','郡縣本來同一體，何須催賦屬州家。',32,'全唐诗/poet.song.186000.json','["郡縣本來同一體，何須催賦屬州家。", "如今已許從民便，升斗須防顆粒加。"]'),
('1b06a230-94d8-4e5a-9fcf-a96a05f5c155','初到延平會四邑宰  其三','陳宓','宋','宋诗','song-poetry','','[]','是邦凋瘵古來無，只爲從前有羨餘。',32,'全唐诗/poet.song.186000.json','["是邦凋瘵古來無，只爲從前有羨餘。", "第一切須除此弊，庶幾民力少能舒。"]'),
('38282b12-ad33-4967-bc80-c244df3fd6de','和范省元','陳宓','宋','宋诗','song-poetry','','[]','太守方將畎畝行，先煩鄉彥探春耕。',64,'全唐诗/poet.song.186000.json','["太守方將畎畝行，先煩鄉彥探春耕。", "人登高嶺如梯峻，雨足深川作掌平。", "發廩正須憑義舉，蠲租已覺負仁聲。", "要知貧富乘除理，施盡囷倉却解盈。"]'),
('2f80ae62-34ee-453f-8c22-87910541cc17','題延平張相公廟  其一','陳宓','宋','宋诗','song-poetry','','[]','想像孤忠尚凜然，古祠何止更千年。',32,'全唐诗/poet.song.186000.json','["想像孤忠尚凜然，古祠何止更千年。", "清標自是人難泯，不爲區區一劍傳。"]'),
('07286ae9-df2f-4816-812d-07772380d523','題延平張相公廟  其二','陳宓','宋','宋诗','song-poetry','','[]','匪躬盡瘁握機權，雖值時危亦晏然。',32,'全唐诗/poet.song.186000.json','["匪躬盡瘁握機權，雖值時危亦晏然。", "况有式乾遺奏在，若教勇退更身全。"]'),
('5fd667bc-0c35-40a7-9201-be7938dfe874','題延平張相公廟  其三','陳宓','宋','宋诗','song-poetry','','[]','地下寶光猶解見，眼前天象却茫然。',32,'全唐诗/poet.song.186000.json','["地下寶光猶解見，眼前天象却茫然。", "君恩自古難貪戀，乃父反輸少子賢。"]'),
('bc6e6f1c-dbbb-41df-abb0-c85197436504','延平六月祈雨感應賡林堂長韵','陳宓','宋','宋诗','song-poetry','','[]','喚起神龍百里來，中腸一夜九縈迴。',32,'全唐诗/poet.song.186000.json','["喚起神龍百里來，中腸一夜九縈迴。", "天心自爲民心動，多謝諸賢舉賀杯。"]'),
('6e01f412-dbaa-40d0-aa7a-1db1c11690ec','往溪源祈雨賡李司法韵  其一','陳宓','宋','宋诗','song-poetry','','[]','欲見高田翻䆉䅉，不辭廿里陟崎嶇。',32,'全唐诗/poet.song.186000.json','["欲見高田翻䆉䅉，不辭廿里陟崎嶇。", "早禾已失三之一，便雨還能救得無。"]'),
('1a5c0c9e-ef90-4883-9338-4a7739965e49','往溪源祈雨賡李司法韵  其二','陳宓','宋','宋诗','song-poetry','','[]','一春雨脈發清泉，何以平疇旱欲然。',32,'全唐诗/poet.song.186000.json','["一春雨脈發清泉，何以平疇旱欲然。", "太守自慚無善政，鈴齋朝夕謾祈天。"]'),
('f8f7cbeb-23ef-4116-a099-be3645580187','第一溪山','陳宓','宋','宋诗','song-poetry','','[]','萬家樓觀巧迴環，紫翠泓澄俯仰間。',32,'全唐诗/poet.song.186000.json','["萬家樓觀巧迴環，紫翠泓澄俯仰間。", "莫道七閩無好境，東南第一此家山。"]'),
('19c1b3e9-aa33-4297-9e1c-1fc16a2dfcc4','端硯六絕  其一','陳宓','宋','宋诗','song-poetry','','[]','昔我高皇渡江日，擬將文治復輿圖。',32,'全唐诗/poet.song.186000.json','["昔我高皇渡江日，擬將文治復輿圖。", "炎方不敢珍韶石，來獻君王寫禹謨。"]'),
('8ada6026-8ed3-48a8-a2e8-1aec42db3f4f','端硯六絕  其二','陳宓','宋','宋诗','song-poetry','','[]','憶昔先臣從武皇，最承天寵與恩光。',32,'全唐诗/poet.song.186000.json','["憶昔先臣從武皇，最承天寵與恩光。", "孤兒白髮雖圖報，見著烏號泣數行。"]'),
('c9d46401-be77-4ed3-b242-e6beac0181b6','端硯六絕  其三','陳宓','宋','宋诗','song-poetry','','[]','紫瓊宜墨世間稀，合與韓公屬好辭。',32,'全唐诗/poet.song.186000.json','["紫瓊宜墨世間稀，合與韓公屬好辭。", "若是只教誇染翰，獻之難受屬羲之。"]'),
('3dcad0d1-c0ba-4dc0-b70f-74df5c8777e0','端硯六絕  其四','陳宓','宋','宋诗','song-poetry','','[]','一段無瑕真萬金，臨窗忽見洗塵心。',32,'全唐诗/poet.song.186000.json','["一段無瑕真萬金，臨窗忽見洗塵心。", "中間方寸君知否，便是仙家綠綺琴。"]'),
('961b79f0-d942-4e17-b185-63f7f26b113f','端硯六絕  其五','陳宓','宋','宋诗','song-poetry','','[]','至寶非關少識真，都緣未覩十城珍。',32,'全唐诗/poet.song.186000.json','["至寶非關少識真，都緣未覩十城珍。", "如何絕域窮南地，却有唐朝輔相人。"]'),
('63bf97a7-c208-47de-b054-0493a5d0c8a3','端硯六絕  其六','陳宓','宋','宋诗','song-poetry','','[]','少年刻志好臨池，老去方知大是癡。',32,'全唐诗/poet.song.186000.json','["少年刻志好臨池，老去方知大是癡。", "今日開奩聊一笑，暫時把玩似當時。"]'),
('bb1ab69f-8c6e-45db-920e-46b86e9032fc','六月禱衍山劍鐔得雨  其一','陳宓','宋','宋诗','song-poetry','','[]','自昔山川致雲雨，我今壇築爲焚香。',32,'全唐诗/poet.song.186000.json','["自昔山川致雲雨，我今壇築爲焚香。", "三回應禱皆如響，始驗吾儒道術長。"]'),
('af8ba878-b8b5-4a23-8bc6-597484d16d09','六月禱衍山劍鐔得雨  其二','陳宓','宋','宋诗','song-poetry','','[]','連宵清雨洗炎光，六月渾如九月凉。',32,'全唐诗/poet.song.186000.json','["連宵清雨洗炎光，六月渾如九月凉。", "擬向暇晨村郭外，西風高下看雲黄。"]'),
('361b9dfc-ca4f-4959-9376-bbc801d29f45','六月禱衍山劍鐔得雨  其三','陳宓','宋','宋诗','song-poetry','','[]','窘無財粟振民饑，仰扣天閽愧納詞。',32,'全唐诗/poet.song.186000.json','["窘無財粟振民饑，仰扣天閽愧納詞。", "連月心胸成菀結，通宵一雨爲醫治。"]'),
('16da8da4-35a3-4181-b42e-087aed826e3b','六月禱衍山劍鐔得雨  其四','陳宓','宋','宋诗','song-poetry','','[]','好善如君似饑渴，春華下筆吐芳詞。',32,'全唐诗/poet.song.186000.json','["好善如君似饑渴，春華下筆吐芳詞。", "莫言郡小無多事，協力從今請共治。"]'),
('c61e30e9-2dcd-4354-beb2-ea8f95728b7a','延平呈潘王二丈  其一','陳宓','宋','宋诗','song-poetry','','[]','小樓中峙萬峰環，正值青螺取巧間。',32,'全唐诗/poet.song.186000.json','["小樓中峙萬峰環，正值青螺取巧間。", "坐待清風送明月，等閑高枕對溪山。"]'),
('c1c9bfdc-a986-4686-b9cc-26a172ad9df3','延平呈潘王二丈  其二','陳宓','宋','宋诗','song-poetry','','[]','一水縈紆玉带環，雜花粧點四時間。',32,'全唐诗/poet.song.186000.json','["一水縈紆玉带環，雜花粧點四時間。", "欲知招演堂中境，便是水梔盆裏山。"]'),
('af548a41-333b-46e8-b5b6-6d5d9196616d','和王子賢兄','陳宓','宋','宋诗','song-poetry','','[]','芒鞋未辦足先輕，擬踏白雲深處行。',32,'全唐诗/poet.song.186000.json','["芒鞋未辦足先輕，擬踏白雲深處行。", "何日癡兒了公事，却將泉石課詩程。"]'),
('15f37354-c5dc-4af2-b4c0-5c2a1bedb4af','延平郡學有小閣予名之曰穹林雲壑和葉教韵  其一','陳宓','宋','宋诗','song-poetry','','[]','炎空長學兩冥冥，况是清風足底生。',32,'全唐诗/poet.song.186000.json','["炎空長學兩冥冥，况是清風足底生。", "頼有詩人解模寫，丹青端的貌難成。"]'),
('7765bf8b-0e12-4fb1-876b-17962ad67f79','延平郡學有小閣予名之曰穹林雲壑和葉教韵  其二','陳宓','宋','宋诗','song-poetry','','[]','山水胡爲仁智好，正緣真味少人知。',32,'全唐诗/poet.song.186000.json','["山水胡爲仁智好，正緣真味少人知。", "曲肱飲水忘言處，更著胸中此段奇。"]'),
('6866f6ad-fb90-40e8-9bbb-1cfd176c8bfc','延平郡學有小閣予名之曰穹林雲壑和葉教韵  其三','陳宓','宋','宋诗','song-poetry','','[]','雨過嵐光偏澒洞，月來林影更清深。',32,'全唐诗/poet.song.186000.json','["雨過嵐光偏澒洞，月來林影更清深。", "幽禽忽墜鏗然韵，便是天然綠綺琴。"]'),
('50833499-1539-402b-8d11-8c6e73468b48','趙君惟誼清文介行堅苦篤實遠來見訪以救科舉弊爲說可無一語言謝  其一','陳宓','宋','宋诗','song-poetry','','[]','菜根慣咬著芒鞋，便是津梁一世材。',32,'全唐诗/poet.song.186000.json','["菜根慣咬著芒鞋，便是津梁一世材。", "六月雨行緣底事，一身不惜惜人才。"]'),
('f5118824-df05-4f97-8e81-750e9ccfd292','趙君惟誼清文介行堅苦篤實遠來見訪以救科舉弊爲說可無一語言謝  其二','陳宓','宋','宋诗','song-poetry','','[]','我把尊賢榜舊堂，懷人忽至喜如狂。',32,'全唐诗/poet.song.186000.json','["我把尊賢榜舊堂，懷人忽至喜如狂。", "緣何不肯留城府，虛著新成八尺床。"]'),
('ba3325cb-df19-4dca-951c-61779e31c0ba','南劍鹿鳴','陳宓','宋','宋诗','song-poetry','','[]','嘉賓卅七燕公堂，吾道方亨值一陽。',64,'全唐诗/poet.song.186000.json','["嘉賓卅七燕公堂，吾道方亨值一陽。", "學力早知深孔孟，鄉風端可繼陳楊。", "雲霄九萬朝天闕，禮樂三千染御香。", "老守尚能觀盛事，春深時節喜如狂。"]'),
('a83c7140-308a-4c23-bccb-705aca95f528','題野亭','陳宓','宋','宋诗','song-poetry','','[]','向晚風光分外新，野亭高處最撩人。',64,'全唐诗/poet.song.186000.json','["向晚風光分外新，野亭高處最撩人。", "綢繆翠袖分還合，委曲寒波去轉親。", "小艇時過明鏡裏，危欄獨倚畫圖身。", "公餘對此長懷愧，檢點胸中未洗塵。"]'),
('33ae1fab-0b7e-4ee4-8f22-752cf6d81134','題玉井','陳宓','宋','宋诗','song-poetry','','[]','自昔高誇十丈蓮，我今平步華峰巔。',32,'全唐诗/poet.song.186000.json','["自昔高誇十丈蓮，我今平步華峰巔。", "年來妄想驅除盡，不信人間是有仙。"]'),
('5f5cfa29-6332-4dce-9908-b7b46856ef0f','延平書院落成柬諸友  其一','陳宓','宋','宋诗','song-poetry','','[]','當日二程門下士，獨分此道過來南。',32,'全唐诗/poet.song.186000.json','["當日二程門下士，獨分此道過來南。", "百年世事相傳處，書院天生著劍鐔。"]'),
('db9c888b-1b68-40e9-a710-b520d64ff0be','延平書院落成柬諸友  其二','陳宓','宋','宋诗','song-poetry','','[]','群峰九疊勢來雄，直作吾儒五畝宮。',32,'全唐诗/poet.song.186000.json','["群峰九疊勢來雄，直作吾儒五畝宮。", "隔斷市廛纔一水，讀書如坐萬山中。"]'),
('31bf26ef-7714-43d0-9974-8f3f45cfae59','次李弘齋韵送任宰','陳宓','宋','宋诗','song-poetry','','[]','近日延平創小齋，四方佳友爲朋來。',64,'全唐诗/poet.song.186000.json','["近日延平創小齋，四方佳友爲朋來。", "雖爲書上究餘味，更要心中絕點埃。", "健德千年期不已，高標萬變詎能推。", "直須義利途中辦，寧使饑腸屢隠雷。"]'),
('52102162-85f2-4f68-90eb-7ee7f800513d','與高畫生','陳宓','宋','宋诗','song-poetry','','[]','衰顔不似十年前，今日重模一惘然。',32,'全唐诗/poet.song.186000.json','["衰顔不似十年前，今日重模一惘然。", "擬向滄洲寄塵迹，憑君歸報小蓬仙。"]'),
('2f016ae5-24fd-4206-89ac-b5c4572cebef','延平得雪  其一','陳宓','宋','宋诗','song-poetry','','[]','連年疾癘緣何事，祇爲天時太暖生。',32,'全唐诗/poet.song.186000.json','["連年疾癘緣何事，祇爲天時太暖生。", "今日六花初獻瑞，定知田里頓身輕。"]'),
('67c495ea-6f5a-4499-b2bd-894bc980715c','延平得雪  其二','陳宓','宋','宋诗','song-poetry','','[]','豐穰已喜新年瑞，凍餒還思卒歲難。',32,'全唐诗/poet.song.186000.json','["豐穰已喜新年瑞，凍餒還思卒歲難。", "安得長縑并廣庾，爲渠千里作衾簞。"]'),
('44fdbb68-9451-41d3-a729-00a858759a2a','延平得雪  其三','陳宓','宋','宋诗','song-poetry','','[]','凌晨訟牒如山積，呵手移時爲破除。',32,'全唐诗/poet.song.186000.json','["凌晨訟牒如山積，呵手移時爲破除。", "幸有清溪明似鏡，忍休偷眼雪晴餘。"]'),
('b1a8a8eb-8fb5-4397-8ffd-284826bc087e','延平得雪  其四','陳宓','宋','宋诗','song-poetry','','[]','衍山先自無塵土，更著飛瓊細糝看。',32,'全唐诗/poet.song.186000.json','["衍山先自無塵土，更著飛瓊細糝看。", "可笑一生緣好事，却將衰鬢敵隆寒。"]'),
('8716af25-bc50-4230-b74c-6d6f467d08d4','延平郡齋分韵','陳宓','宋','宋诗','song-poetry','','[]','百年琢就流杯石，來泛清波未半時。',32,'全唐诗/poet.song.186000.json','["百年琢就流杯石，來泛清波未半時。", "幸有九賢俱畢集，却嫌當坐欠羲之。"]'),
('1e95af23-29be-4e07-a1a8-b69abf4e3f37','次延平郡文學宴新進士韵','陳宓','宋','宋诗','song-poetry','','[]','文章千丈吐寒芒，更要新登孔氏堂。',64,'全唐诗/poet.song.186000.json','["文章千丈吐寒芒，更要新登孔氏堂。", "講學若能羶自至，致君端使鳳來翔。", "衍山劍水多奇産，赤箭丹砂詎可當。", "自有名儒常輩出，莫將詩句詫錢郎。"]'),
('916912e8-1fd9-4658-a151-5f5c8bc5ea37','和范茂才','陳宓','宋','宋诗','song-poetry','','[]','小小平欄容易攀，欄邊楊柳又成班。',64,'全唐诗/poet.song.186000.json','["小小平欄容易攀，欄邊楊柳又成班。", "是非榮辱不到地，南北東西都見山。", "但解心寬長有趣，不因境勝始能閑。", "從今與子安心訣，外物由來總不關。"]'),
('e179bd18-1b41-4d2b-82ad-7d52dcae50e3','陪劉學錄巖壑之遊次韵  其一','陳宓','宋','宋诗','song-poetry','','[]','常欲從君一夜譚，自慚風骨带塵凡。',32,'全唐诗/poet.song.186000.json','["常欲從君一夜譚，自慚風骨带塵凡。", "今朝款曲陪嘉話，更聽松聲出翠岩。"]'),
('51a3c308-0923-4aac-b787-a449c1c6da05','陪劉學錄巖壑之遊次韵  其二','陳宓','宋','宋诗','song-poetry','','[]','山路嶔𡼭戒足趨，萬竿繞逕自蕭疎。',32,'全唐诗/poet.song.186000.json','["山路嶔𡼭戒足趨，萬竿繞逕自蕭疎。", "世間何事真堪羨，月壑雲岩卧讀書。"]'),
('dede51b9-581a-4157-bb00-f6ac872fad14','與劉學錄','陳宓','宋','宋诗','song-poetry','','[]','年來幸得奉仙翁，開口良辰一笑同。',64,'全唐诗/poet.song.186000.json','["年來幸得奉仙翁，開口良辰一笑同。", "節物催人雙鬢水，人生何必慕登瀛。", "三方翠巘天同色，四面黄雲掌樣平。", "更著回還如蔕白，殷紅時暫愜秋容。"]'),
('d58ae90d-9cf8-41cd-900c-cb3dfc2c1541','又次劉學錄韵','陳宓','宋','宋诗','song-poetry','','[]','八月川原旱欲然，季秋連雨頓澄鮮。',64,'全唐诗/poet.song.186000.json','["八月川原旱欲然，季秋連雨頓澄鮮。", "明朝領客成無暇，七日登高不厭前。", "菡萏掃除如暑凈，芙蓉綽約作春妍。", "佳人得得同來看，萸菊年年却懶搴。"]'),
('5a2b9866-41b6-4c3f-8b90-8f8f9fc97dc4','憶飲井','陳宓','宋','宋诗','song-poetry','','[]','一泓渴濟萬夫焦，去作滄溟蚤暮潮。',64,'全唐诗/poet.song.186000.json','["一泓渴濟萬夫焦，去作滄溟蚤暮潮。", "我欲結亭觀遠景，距城七里不爲遥。", "疏泉鑿石作漥池，亂石堆中竹最宜。", "風動琅玕和玉珮，個中律呂少人知。"]'),
('30885763-6b08-41ee-baaf-550bc7340736','聞延平水沴  其一','陳宓','宋','宋诗','song-poetry','','[]','延平山水東南冠，連歲何辜致許菑。',32,'全唐诗/poet.song.186000.json','["延平山水東南冠，連歲何辜致許菑。", "積雨隄防宜有素，後時悔懊謾興哀。"]'),
('8e5fde5f-a0a3-4853-82b9-ce9cab69c3c5','聞延平水沴  其二','陳宓','宋','宋诗','song-poetry','','[]','鸛鳴早合遷崖際，漁唱先教集岸隈。',32,'全唐诗/poet.song.186000.json','["鸛鳴早合遷崖際，漁唱先教集岸隈。", "見說高樓如小舫，呼號聲雜怒濤豗。"]'),
('b052712a-985b-47df-9c1f-98faf2775a5a','聞延平水沴  其三','陳宓','宋','宋诗','song-poetry','','[]','我是延平舊史君，忍聞水沴欲銷魂。',32,'全唐诗/poet.song.186000.json','["我是延平舊史君，忍聞水沴欲銷魂。", "人言辛酉溪流漲，更減今年丈二痕。"]'),
('72bd3a77-aa68-4bc6-ab6d-7c779ed4b1e3','簡山行諸丈','陳宓','宋','宋诗','song-poetry','','[]','鯉湖仙去幾何年，翠壁蒼崖峻屬天。',64,'全唐诗/poet.song.186000.json','["鯉湖仙去幾何年，翠壁蒼崖峻屬天。", "愧我衰蹤滯塵土，羨君逸足跨雲煙。", "驚天姓字名濡隠，無地樓臺舊相賢。", "莫道迹陳人已遠，聯鑣到處草猶妍。"]'),
('98f47cf0-8430-4e4b-b7c1-71adfb30f26b','次劉制幹潛夫趣續譜韵','陳宓','宋','宋诗','song-poetry','','[]','濃陰尚想升平日，老幹曾經五百年。',64,'全唐诗/poet.song.186000.json','["濃陰尚想升平日，老幹曾經五百年。", "商略正須憑衆口，品題誰敢繼先賢。", "素團比玉清仍潤，繁顆如星艷欲然。", "天予瓌奇資賦詠，况當詩思似流泉。"]'),
('b24c11fe-ea7e-4d28-b5c1-c72ddf386f0e','次方雲臺韵','陳宓','宋','宋诗','song-poetry','','[]','泉石膏肓世欲忘，扁舟更遡壽湖光。',64,'全唐诗/poet.song.186000.json','["泉石膏肓世欲忘，扁舟更遡壽湖光。", "也知他日持荷橐，不似閑時製芰裳。", "雨後尚餘新稻熟，風前偏覺荔枝香。", "人生有祿親頭白，萬石何如宦本鄉。"]'),
('ef704798-bb46-4631-99a3-c4490d2ba549','與楊信齋','陳宓','宋','宋诗','song-poetry','','[]','半春積雨逗濃寒，隴畝都翻宿藁殘。',64,'全唐诗/poet.song.186000.json','["半春積雨逗濃寒，隴畝都翻宿藁殘。", "要得三秋□成熟，直須千里絕高乾。", "瘵疲悉振慚無力，租賦頻蠲覺更難。", "頼有詩人知中意，佳篇時遣鄙懷寬。"]'),
('fec6e1da-1f23-46d9-8713-7102017e06c7','嘉定間贈丁寺丞使虜','陳宓','宋','宋诗','song-poetry','','[]','故宮龍德尚如新，忍使衣冠拜虜塵。',64,'全唐诗/poet.song.186000.json','["故宮龍德尚如新，忍使衣冠拜虜塵。", "九世舊讐猶有憾，百年中國豈無人。", "金繒第一休教遣，伯姪從今莫强親。", "天與此時那可共，堂堂虜使正精神。"]'),
('e248aadf-d4d3-4a8d-aeea-954a461e8697','和劉制幹潛夫','陳宓','宋','宋诗','song-poetry','','[]','制閫宣勞已再朞，胸中方寸了無私。',64,'全唐诗/poet.song.186000.json','["制閫宣勞已再朞，胸中方寸了無私。", "誰言今日平齊策，不似當年代蔡時。", "馬上陳琳能草檄，幕中韓愈更長詩。", "休嫌衡岳官曹冷，文士何嘗繫職司。"]'),
('ee6b9706-569b-4375-9ed2-b8a37430a668','和傅監倉南園遊船','陳宓','宋','宋诗','song-poetry','','[]','小舟初具似漁家，一曲清溪便可誇。',64,'全唐诗/poet.song.186000.json','["小舟初具似漁家，一曲清溪便可誇。", "垂釣便能升躍鯉，歸篙時復带栖鴉。", "園亭不掃心長靜，水竹無多鏡自華。", "暇日儻來同笑語，書囊詩卷未應涯。"]'),
('881df4ee-0261-44d6-866c-20c664658d9c','六月三日大風雨蔡忠惠家玉堂紅一洗而盡因憶去年三山帥憲各致餽','陳宓','宋','宋诗','song-poetry','','[]','三年渴想玉堂紅，六月都隨一夜風。',32,'全唐诗/poet.song.186000.json','["三年渴想玉堂紅，六月都隨一夜風。", "却憶去年當此際，一時臺府餽筠籠。"]'),
('34a2b0ed-2d2b-4a0b-8b8c-1070b03c2af6','與趙錄參遊東湖  其一','陳宓','宋','宋诗','song-poetry','','[]','天河鑿就餘三畝，臘雨增成四尺波。',32,'全唐诗/poet.song.186000.json','["天河鑿就餘三畝，臘雨增成四尺波。", "我與同寮來共看，一時都喜鏡初磨。"]'),
('ba792e63-233f-4aca-89dd-800a701e041f','與趙錄參遊東湖  其二','陳宓','宋','宋诗','song-poetry','','[]','四山圍繞池居內，百雉周遭人莫過。',32,'全唐诗/poet.song.186000.json','["四山圍繞池居內，百雉周遭人莫過。", "此是延平新勝概，月明擬辦一漁簑。"]'),
('770b6fdd-b944-4988-8422-30263f85c34d','延平鳳山','陳宓','宋','宋诗','song-poetry','','[]','洞中流水雲門樂，崖上寒莎伏帝裳。',32,'全唐诗/poet.song.186000.json','["洞中流水雲門樂，崖上寒莎伏帝裳。", "覿面突高三百尺，擬將金薤託琳琅。"]'),
('753921e8-6d39-45ed-aa34-fba4b02a4d4a','題延平招演堂','陳宓','宋','宋诗','song-poetry','','[]','好山四遶作銀屏，秀水忝流玉樣青。',64,'全唐诗/poet.song.186000.json','["好山四遶作銀屏，秀水忝流玉樣青。", "雨後龍精穿皦日，夜初漁火混疎星。", "躊躇直擬長來宅，取次都堪小結亭。", "謾酌三杯求一醉，終然心事獨醒醒。"]'),
('4f2e9c5c-db82-46fb-9c72-8b04c8609b88','和泉州施通判  其一','陳宓','宋','宋诗','song-poetry','','[]','君侯來佐刺桐鄉，小試聊看主貢場。',32,'全唐诗/poet.song.186000.json','["君侯來佐刺桐鄉，小試聊看主貢場。", "新闢千間歡萬士，盡醫百蠹處奇方。"]'),
('5631a899-5c2e-49fc-b69b-c11826c1cc63','和泉州施通判  其二','陳宓','宋','宋诗','song-poetry','','[]','清源古郡多堪紀，識遠才雄有幾人。',32,'全唐诗/poet.song.186000.json','["清源古郡多堪紀，識遠才雄有幾人。", "片善可爲垂後訓，搜羅詩景一時新。"]'),
('c8d37010-30ba-4a67-8ce9-112edbb41c9f','和泉州施通判  其三','陳宓','宋','宋诗','song-poetry','','[]','物性由來易變遷，精金百鍊始知堅。',32,'全唐诗/poet.song.186000.json','["物性由來易變遷，精金百鍊始知堅。", "相逢即別無佳語，有負慇懃見贈篇。"]'),
('55789df9-69a5-40e6-9e70-151ae435d739','和泉州施通判  其四','陳宓','宋','宋诗','song-poetry','','[]','紙帳無風紙被溫，何殊錦段與綿屯。',32,'全唐诗/poet.song.186000.json','["紙帳無風紙被溫，何殊錦段與綿屯。", "若知睡裏真滋味，組麗由來不足論。"]'),
('98f3d605-eb26-4ff0-a08b-a5e5dd2dd6c3','題西淙','陳宓','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','當年巨刃劈崖開，便擁雙虬海上來。',64,'全唐诗/poet.song.186000.json','["當年巨刃劈崖開，便擁雙虬海上來。", "舊跡幾年甘隠霧，新名一日怕驚雷。", "池邊有地惟生茝，石上無泥更植梅。", "酷似廬山難忘處，卧龍白鹿勘書臺。"]'),
('9b52cf25-c83d-4851-b1f6-30809b60e052','因讀魯論賡潘丈韵','陳宓','宋','宋诗','song-poetry','','[]','八十年前一筆門，須將舊事與重論。',64,'全唐诗/poet.song.186000.json','["八十年前一筆門，須將舊事與重論。", "幸承顯考箕裘後，全頼宣尼典籍存。", "道統精微傳舜禹，性原善惡辨楊孫。", "學由踐履工夫入，敬義當稽六二坤。"]'),
('17d50848-65ed-4069-adf8-541e9950bd7e','題豐穎樓','陳宓','宋','宋诗','song-poetry','','[]','壽溪百里薦寒流，來護楊君少尹丘。',64,'全唐诗/poet.song.186000.json','["壽溪百里薦寒流，來護楊君少尹丘。", "三復先公當日翰，重脩處士舊時樓。", "高山不減八千仞，往事空餘五十秋。", "闢作小齋教子姪，好將萬卷著雙眸。"]'),
('13edd20c-c416-4af3-895b-29e735a01c1e','同潘丈遊東平瀑  其一','陳宓','宋','宋诗','song-poetry','','[]','天公特地放初晴，許我聯鑣琬琰行。',32,'全唐诗/poet.song.186000.json','["天公特地放初晴，許我聯鑣琬琰行。", "新著茅亭憑到晚，難將一字扁佳名。"]'),
('9db01cff-7b31-42f2-9c6a-249ada86e233','同潘丈遊東平瀑  其二','陳宓','宋','宋诗','song-poetry','','[]','喧天動地作驚霆，生定中扃轉更寧。',32,'全唐诗/poet.song.186000.json','["喧天動地作驚霆，生定中扃轉更寧。", "三疊飛泉凝似霧，却疑石轉解過靈。"]'),
('14977058-5420-48d8-a35f-2c84d444b505','同潘丈遊東平瀑  其三','陳宓','宋','宋诗','song-poetry','','[]','水深厲涉祇肩輿，未信當年子産疎。',32,'全唐诗/poet.song.186000.json','["水深厲涉祇肩輿，未信當年子産疎。", "到得中流心不競，等閑一葉去凌虛。"]'),
('0de1545a-b3ee-4470-af92-37c3603316c7','次樓宗簿禱雨韵','陳宓','宋','宋诗','song-poetry','','[]','農家累月望雲霓，多謝賢侯懇切祈。',64,'全唐诗/poet.song.186000.json','["農家累月望雲霓，多謝賢侯懇切祈。", "群望三旬幾遍走，百川一夜忽東之。", "天心感格真堪必，歲事豐登尚可期。", "和氣致祥非誕語，願將此意播聲詩。"]'),
('0b647a3c-3133-4e0e-a7fb-04005c5ef245','憶天台之遊','陳宓','宋','宋诗','song-poetry','','[]','小酌一杯金鑿落，共聽終席玉潺湲。',32,'全唐诗/poet.song.186000.json','["小酌一杯金鑿落，共聽終席玉潺湲。", "何時築室屏山側，靜與秋蟾作伴眠。"]'),
('42665ca6-b807-44e6-b014-66357c814bc4','約潘丈及小喻登橫玉臺觀木香酴醾  其一','陳宓','宋','宋诗','song-poetry','','[]','春前桃李謾紛紛，梅後冰標獨有君。',32,'全唐诗/poet.song.186000.json','["春前桃李謾紛紛，梅後冰標獨有君。", "莫將今日推明日，要看三分到七分。"]'),
('7a4fd933-6e59-44dd-92ed-fa736ee2ad95','約潘丈及小喻登橫玉臺觀木香酴醾  其二','陳宓','宋','宋诗','song-poetry','','[]','暮年無事掛胸懷，祇爲酴醾築此臺。',32,'全唐诗/poet.song.186000.json','["暮年無事掛胸懷，祇爲酴醾築此臺。", "恰似唐朝元會日，露翻珠翠六宮來。"]'),
('1b7ef016-0cbe-4030-9279-9f605c40b91d','橫玉臺','陳宓','宋','宋诗','song-poetry','','[]','橫玉初登斗樣臺，倚欄一带雪花堆。',32,'全唐诗/poet.song.186000.json','["橫玉初登斗樣臺，倚欄一带雪花堆。", "兒時親見前朝事，不忍春深載酒來。"]'),
('a46fe0e6-74cb-4de2-9f17-52859b25eca8','介亭','陳宓','宋','宋诗','song-poetry','','[]','春融四澤形如介，著我茅亭跨此間。',32,'全唐诗/poet.song.186000.json','["春融四澤形如介，著我茅亭跨此間。", "縱使戴星朝玉闕，終輸乘月看金瀾。"]'),
('45935111-cdfc-4a0a-88f3-d82511fd6a9b','添築橫玉再賦  其一','陳宓','宋','宋诗','song-poetry','','[]','臺成草草怕花殘，趁得香濃一凭欄。',32,'全唐诗/poet.song.186000.json','["臺成草草怕花殘，趁得香濃一凭欄。", "忽見四圍澄碧繞，懶將雙眼向花看。"]'),
('47e5d115-8804-48ea-9f77-e1b0dc903c21','添築橫玉再賦  其二','陳宓','宋','宋诗','song-poetry','','[]','一花爛熳一花殘，先後無時不傍欄。',32,'全唐诗/poet.song.186000.json','["一花爛熳一花殘，先後無時不傍欄。", "春到園林元不老，請君細把化工看。"]'),
('f5654bb9-6e4e-47d8-af47-e2fbb39155a0','寄鶴山魏侍郎  其一','陳宓','宋','宋诗','song-poetry','','[]','朝辭巖禁暮荒城，底是人間辱與榮。',32,'全唐诗/poet.song.186000.json','["朝辭巖禁暮荒城，底是人間辱與榮。", "料得胸中無點累，每於夜半省鍾聲。"]'),
('85685194-0da0-4282-a9ce-4085f2b86498','寄鶴山魏侍郎  其二','陳宓','宋','宋诗','song-poetry','','[]','濂洛遺音喜復鳴，未由會面只心傾。',32,'全唐诗/poet.song.186000.json','["濂洛遺音喜復鳴，未由會面只心傾。", "平生格物工夫到，好惡真如月樣明。"]'),
('8be61e64-232c-462a-8f8b-77d319b6814b','寄鶴山魏侍郎  其三','陳宓','宋','宋诗','song-poetry','','[]','草草三間舊揭名，中藏一片愛君誠。',32,'全唐诗/poet.song.186000.json','["草草三間舊揭名，中藏一片愛君誠。", "騷人賦盡群芳卉，得似梅邊讀易清。"]'),
('b68a1e90-bb5a-4ae5-b489-d6aae887d5ba','掬水錫壺','陳宓','宋','宋诗','song-poetry','','[]','白鑞鎔成滴水池，新荷初展濺珠璣。',32,'全唐诗/poet.song.186000.json','["白鑞鎔成滴水池，新荷初展濺珠璣。", "一絲晝夜無時息，勝似甘霖六月飛。"]'),
('82d69d54-8a7b-41c7-986e-a4b7e7d28c72','飲井多景亭','陳宓','宋','宋诗','song-poetry','','[]','山海前陳遠景多，一泓冰雪醒沉痾。',32,'全唐诗/poet.song.186000.json','["山海前陳遠景多，一泓冰雪醒沉痾。", "憑誰六月同來看，奈此清風爽氣何。"]'),
('e6536f9a-cbed-4ef4-8259-24c11baa257c','謝潘瓜山遊東湖惠詩','陳宓','宋','宋诗','song-poetry','','[]','東湖覿面本情親，到得東湖動隔旬。',32,'全唐诗/poet.song.186000.json','["東湖覿面本情親，到得東湖動隔旬。", "若道四并成浪語，如何寸步不由人。"]'),
('c3620e39-07b3-4e3d-a77e-914c0a60c3f7','題新創南樓榜曰寬閑','陳宓','宋','宋诗','song-poetry','','[]','樓高二丈只三間，四面平疇繞海山。',64,'全唐诗/poet.song.186000.json','["樓高二丈只三間，四面平疇繞海山。", "白水青秧開凈練，碧巒蒼巘擁妝鬟。", "靜中始覺乾坤大，老去唯思歲月慳。", "但願心田如此闊，一生到了得清閒。"]'),
('9cca3b64-d9d5-4227-bea5-a8c60b248373','江瑶柱','陳宓','宋','宋诗','song-poetry','','[]','江上分來三寸瑶，殷勤海若道寒潮。',64,'全唐诗/poet.song.186000.json','["江上分來三寸瑶，殷勤海若道寒潮。", "盡將馬甲深深鎖，好把鸞刀款款挑。", "榼酒怪來星不醉，杯羹元是雪難消。", "若將陳紫同時賞，飲罷身端在泬寥。"]'),
('c5d97f99-df47-479d-8e88-4bf62c406488','八月五日妙寂道中  其一','陳宓','宋','宋诗','song-poetry','','[]','漫漫紅紫是誰栽，八月春風暗裏來。',32,'全唐诗/poet.song.186000.json','["漫漫紅紫是誰栽，八月春風暗裏來。", "過眼紛紛難盡憶，殷勤却看稻花開。"]'),
('9c01a523-807a-445e-9e52-09eb36bfeb9a','八月五日妙寂道中  其二','陳宓','宋','宋诗','song-poetry','','[]','山間萬點綴黄瓊，盡是秋光釀得成。',32,'全唐诗/poet.song.186000.json','["山間萬點綴黄瓊，盡是秋光釀得成。", "殘暑滿城癡未退，一枝能使去兼程。"]'),
('93492286-1a63-49db-b984-57f930192478','移花','陳宓','宋','宋诗','song-poetry','','[]','移根烈日倍常炎，渴作油雲欲雨占。',32,'全唐诗/poet.song.186000.json','["移根烈日倍常炎，渴作油雲欲雨占。", "抱甕自慚衰矣久，翻盆喜得沛然沾。"]'),
('31068330-71e5-4786-8a61-4b4cf915b2bb','和林堂長韵  其一','陳宓','宋','宋诗','song-poetry','','[]','近學陶公小闢窗，境閑地迥壯心降。',64,'全唐诗/poet.song.186000.json','["近學陶公小闢窗，境閑地迥壯心降。", "臨階曲水清堪照，隔檻奇峰勇莫扛。", "靜對每嗟人尚獨，清標長想玉難雙。", "新詩忽自龍門墜，紙上波濤更擊撞。"]'),
('10b0fcc9-042b-44e1-b1e3-3a473c686177','和林堂長韵  其二','陳宓','宋','宋诗','song-poetry','','[]','山齋盡日激清湍，未許人間俗客看。',64,'全唐诗/poet.song.186000.json','["山齋盡日激清湍，未許人間俗客看。", "搗藥暇時來舞鶴，誦書聲裏答鳴鸞。", "千年正統源流遠，三聖遺書簡牘殘。", "顧我何年陪講席，未應劍水舊盟寒。"]'),
('793f4385-6470-4fd8-8f46-77b9a2471a72','次劉學錄梅韵  其一','陳宓','宋','宋诗','song-poetry','','[]','一株相伴古城隈，日日扶筇探未開。',32,'全唐诗/poet.song.186000.json','["一株相伴古城隈，日日扶筇探未開。", "除是風饕還暫往，若教雪壓亦須來。"]'),
('01c2d2fc-ab99-4fbc-bc41-2ec88c460e58','次劉學錄梅韵  其二','陳宓','宋','宋诗','song-poetry','','[]','春風來信已分明，不待騷人玉笛橫。',32,'全唐诗/poet.song.186000.json','["春風來信已分明，不待騷人玉笛橫。", "莫道未開難等候，開時却恐轉關情。"]'),
('93827788-8627-4022-8959-337c7f968811','次劉學錄梅韵  其三','陳宓','宋','宋诗','song-poetry','','[]','明珠的皪逞妍姿，倏見風前舞袖披。',32,'全唐诗/poet.song.186000.json','["明珠的皪逞妍姿，倏見風前舞袖披。", "祇是嚼芳酸已露，况當小雨弄黄時。"]'),
('471808c4-2a51-4e1b-8872-e9507454d7ec','次劉學錄梅韵  其四','陳宓','宋','宋诗','song-poetry','','[]','瓊裾初到似含羞，剩擬人間款曲留。',32,'全唐诗/poet.song.186000.json','["瓊裾初到似含羞，剩擬人間款曲留。", "祇恐寒夜歸去蚤，先須秉燭問端由。"]'),
('6aeb05d3-ed2e-420a-a844-d8b7480c2036','次劉學錄梅韵  其五','陳宓','宋','宋诗','song-poetry','','[]','南方地暖開仍早，容易離思歲月長。',32,'全唐诗/poet.song.186000.json','["南方地暖開仍早，容易離思歲月長。", "幸有高人知此意，山遊百度又何妨。"]'),
('a67f8535-df13-4079-860f-8225f4e8877d','同柯兄遊東湖','陳宓','宋','宋诗','song-poetry','','[]','荷張萬蓋迎仙艦，葵卷千旗擁將壇。',32,'全唐诗/poet.song.186000.json','["荷張萬蓋迎仙艦，葵卷千旗擁將壇。", "顧我從來嗤羽化，飽看仍不負空餐。"]'),
('f12eada9-d085-44d8-9319-a26ca2a0b973','西窗芭蕉','陳宓','宋','宋诗','song-poetry','','[]','青羅千丈拶窗排，玉樹移從海底栽。',64,'全唐诗/poet.song.186000.json','["青羅千丈拶窗排，玉樹移從海底栽。", "夜半偏能延月住，暑深長是挹凉來。", "竹君似欠封侯骨，松老難當翰□□。", "□□仁皇群玉宴，諸賢一葉拜金杯。"]'),
('3aa27725-bd27-4985-9c51-120536b2b690','西橋玩月  其一','陳宓','宋','宋诗','song-poetry','','[]','西橋小小似垂虹，十里薰風胯下通。',32,'全唐诗/poet.song.186000.json','["西橋小小似垂虹，十里薰風胯下通。", "萬蓋紅粧都不看，壺公立在月明中。"]'),
('77f53945-f6a8-47ed-9b51-c94ada58f886','西橋玩月  其二','陳宓','宋','宋诗','song-poetry','','[]','一月那知幾日明，望舒端正對佳晴。',32,'全唐诗/poet.song.186000.json','["一月那知幾日明，望舒端正對佳晴。", "池臺跬步城無禁，縱病何能不動情。"]'),
('10d8cd1c-91f9-4d65-9c7f-92c40c897fac','南園荔子熟名曰魏紫蓋是陳家紫種以先公賜封大名地冠之','陳宓','宋','宋诗','song-poetry','','[]','先世栽來四十年，南園魏紫始名傳。',64,'全唐诗/poet.song.186000.json','["先世栽來四十年，南園魏紫始名傳。", "丁香乍翠蘭芬烈，龍腦初開玉色鮮。", "可踵蔡家名翰苑，誰誇烏石擅山前。", "追思往事渾如昨，食罷無言意惘然。"]'),
('c090ef52-c16a-4c67-a4e7-071d5d9173f9','延平范子登同姪祖年見訪惠詩次韵','陳宓','宋','宋诗','song-poetry','','[]','森森九桂植岩幽，所謂伊人在一洲。',64,'全唐诗/poet.song.186000.json','["森森九桂植岩幽，所謂伊人在一洲。", "別後道尊君可慕，病餘學廢我堪羞。", "雪驚新白傳佳詠，雲□殘黄會晚秋。", "多謝聯鑣垂訪意，疎慵猶可誨還不。"]'),
('0ba27add-2483-4034-8144-ae352a39cbf8','次劉學錄韵併以胡桃寄之','陳宓','宋','宋诗','song-poetry','','[]','中腴外勁介如堅，能伴寒松晚菊鮮。',32,'全唐诗/poet.song.186000.json','["中腴外勁介如堅，能伴寒松晚菊鮮。", "聞道元城心似鐵，故教持向蛤蜊前。"]'),
('eacebd60-1535-4a53-b87c-bde012555af7','重九前一日劉學錄以詩招潘楊二丈登高二丈辭之劉以詩見寄仍和之','陳宓','宋','宋诗','song-poetry','','[]','一秋好處黄葉節，自昔名言不浪傳。',32,'全唐诗/poet.song.186000.json','["一秋好處黄葉節，自昔名言不浪傳。", "八日登高勝九日，今年不飲便明年。"]'),
('fe54301f-7c11-4980-9b62-3da6ee10cc43','又和喜晴','陳宓','宋','宋诗','song-poetry','','[]','年來日日候陰晴，渾是耕耘隴上人。',32,'全唐诗/poet.song.186000.json','["年來日日候陰晴，渾是耕耘隴上人。", "但得鷄豚歡里社，敢將蠱鼠累陶鈞。"]'),
('8dd002e2-81e6-4001-840b-ff1afac26031','偶題','陳宓','宋','宋诗','song-poetry','','[]','三麾一節已難堪，更蒙天恩舘職忝。',64,'全唐诗/poet.song.186000.json','["三麾一節已難堪，更蒙天恩舘職忝。", "居士本來還舊服，叢祠猶復戴華簪。", "身微國效將安用，家竊官供祇自慙。", "料得清時耕𤱶畝，未應朝夕缺瓶甔。"]'),
('6499d9dd-7aa2-40e4-a904-f4e84b204ae2','八月八夕邀劉學錄','陳宓','宋','宋诗','song-poetry','','[]','老來歲月去如流，佳節前期約共遊。',64,'全唐诗/poet.song.186000.json','["老來歲月去如流，佳節前期約共遊。", "玉露盡驅三伏暑，銀蟾堪□作中秋。", "交朋得暇頻相過，身世須忘百不憂。", "尚有讀書心未足，寒光憑爲洗雙眸。"]'),
('eb66c1f6-8693-46d5-ac7e-72d642667c61','中秋夕無月前兩夕皆明','陳宓','宋','宋诗','song-poetry','','[]','四時丹桂年年好，萬歲青娥个个妍。',64,'全唐诗/poet.song.186000.json','["四時丹桂年年好，萬歲青娥个个妍。", "但看世人生與老，不愁玉兔缺仍圓。", "攻侵屬國雪中節，巧趁鴟夷烟際船。", "我把清光貯胸次，從教飛轍碧宵緣。"]'),
('98d74a0f-be19-46bd-80c5-1854e3b3caf5','招劉學錄','陳宓','宋','宋诗','song-poetry','','[]','去年八月登高集，今歲依然共此筵。',64,'全唐诗/poet.song.186000.json','["去年八月登高集，今歲依然共此筵。", "莫訝霜毛成種種，且欣露蘂已鮮鮮。", "小橋擬換香山版，曲岸新成范蠡船。", "少年青春還易度，不如來看晚秋天。"]'),
('8535f985-a956-4512-9aa5-d67ea5b7d3de','柳絮','陳宓','宋','宋诗','song-poetry','','[]','人道楊花渾似雪，那知雪不似楊花。',64,'全唐诗/poet.song.186000.json','["人道楊花渾似雪，那知雪不似楊花。", "春深解送餘寒去，晝永偏依麗日斜。", "點綴樓臺成繪畫，發揮桃李作奢華。", "多情不忍輕離別，笑殺飛霙便委沙。"]'),
('079b4eb9-af4b-4d99-9ded-fdc8eb4fe1ad','游壺山絕頂呈同游諸友','陳宓','宋','宋诗','song-poetry','','[]','壺山相對自童兒，五十分能蟹井窺。',32,'全唐诗/poet.song.186000.json','["壺山相對自童兒，五十分能蟹井窺。", "寄語諸君休憚險，更須脚力驗它時。"]'),
('080dda7a-3ec1-4e64-9976-97b946a16548','呈江西趙倉及真帥','陳宓','宋','宋诗','song-poetry','','[]','雨雪成泥沒膝深，暑風如灼轉難禁。',64,'全唐诗/poet.song.186000.json','["雨雪成泥沒膝深，暑風如灼轉難禁。", "願開周道平夷砥，更植甘棠蔽芾陰。", "少借緇黄多暇力，只捐燕饗有餘金。", "當年閩帥留遺跡，來往行人感至今。"]'),
('7361387f-87ed-4197-81d5-09affc65d97e','題王忠文公新祠','陳宓','宋','宋诗','song-poetry','','[]','仰瞻新像凜清秋，猶带當時體國憂。',64,'全唐诗/poet.song.186000.json','["仰瞻新像凜清秋，猶带當時體國憂。", "聽斷直教心悅服，撫縻端自意誠求。", "遂令百世思嚬笑，不但三年絕嘆愁。", "甲子一周遺愛在，後來多少踵前脩。"]'),
('c12aff6b-0058-4ddf-b6ac-c5e0e01a5f21','次劉學錄韵','陳宓','宋','宋诗','song-poetry','','[]','中年早透利名關，坐看孤雲際海還。',64,'全唐诗/poet.song.186000.json','["中年早透利名關，坐看孤雲際海還。", "晝靜架書偏悅目，秋凉庭樹倍怡顔。", "不陪長者終朝誨，那得塵蹤一日閑。", "我亦小園初種竹，請君來闖出籬斑。"]'),
('9077c5ce-6227-4291-b065-abf38ca3de1d','往桐城會傅侍郎葬次蘇教思恭韵','陳宓','宋','宋诗','song-poetry','','[]','一別清凉十二秋，仙翁已作九霄遊。',64,'全唐诗/poet.song.186000.json','["一別清凉十二秋，仙翁已作九霄遊。", "急披龍具壺山麓，來會牛眠蘇嶺頭。", "事業直須關宇宙，身名莫使負山丘。", "臨分相勉無它語，道學難收歲不留。"]'),
('22214870-6a6d-47c6-8d18-2730c42b7d30','次泉守游郎中  其一','陳宓','宋','宋诗','song-poetry','','[]','七閩徧數刺桐州，自昔賢侯惠愛留。',64,'全唐诗/poet.song.186000.json','["七閩徧數刺桐州，自昔賢侯惠愛留。", "洛水橋新渾似昨，梅溪人誦不能休。", "近來善政稱三最，相繼清名照九秋。", "我別十年思一到，不知何日此心酬。"]'),
('cc40e59e-7947-46c8-8ad5-5895761fb308','次泉守游郎中  其二','陳宓','宋','宋诗','song-poetry','','[]','窮山野老腹應便，冕黻朝天袂屢牽。',64,'全唐诗/poet.song.186000.json','["窮山野老腹應便，冕黻朝天袂屢牽。", "黄霸擬登三事列，寇恂仍借一朞年。", "極知公意山林巒，自是天心鰥寡憐。", "顧我閑人鄰邑住，密依仁政亦熙然。"]'),
('e39243b5-0cb5-4206-944a-7ce04b360096','陳遂鄉有墅在楓亭扁曰廛山求詩寄之','陳宓','宋','宋诗','song-poetry','','[]','溪山鎮日不離門，一市人家自寂喧。',64,'全唐诗/poet.song.186000.json','["溪山鎮日不離門，一市人家自寂喧。", "居士本非爲素隠，小窗端合勝華軒。", "同時桃李驚開蚤，晚歲松篁喜獨存。", "我最愛山思覓暇，袖琴來聽玉潺湲。"]'),
('a3fd3d6e-fe5b-4d26-aa63-3a1869217b1f','橫玉臺','陳宓','宋','宋诗','song-poetry','','[]','雨後楊花撲藕芽，東君雅興正雄誇。',64,'全唐诗/poet.song.186000.json','["雨後楊花撲藕芽，東君雅興正雄誇。", "酴醾疊疊能香玉，蛺蝶紛紛解舞花。", "夜暖蟾光初可玩，晝長烏景未應斜。", "東湖水滿清明近，來看三分欲拆葩。"]'),
('06981b16-58a6-43d2-897b-3898bdee93ac','寄喻景山','陳宓','宋','宋诗','song-poetry','','[]','草堂南望到無因，遥想芒鞋避暑塵。',32,'全唐诗/poet.song.186000.json','["草堂南望到無因，遥想芒鞋避暑塵。", "六月携家玩泉石，大飛驚見此山人。"]'),
('e40e0d43-8081-4e2c-a196-abed963377e7','和劉學錄韵  其一','陳宓','宋','宋诗','song-poetry','','[]','簪組虛加病倦身，暮年始羨葛天民。',32,'全唐诗/poet.song.186000.json','["簪組虛加病倦身，暮年始羨葛天民。", "門前幸有田堪治，旋買漁舠學放綸。"]'),
('e8ba5787-2855-4b2e-be70-ce25714808a5','和劉學錄韵  其二','陳宓','宋','宋诗','song-poetry','','[]','壺公千載嶙峋面，今日開奩滿鏡春。',32,'全唐诗/poet.song.186000.json','["壺公千載嶙峋面，今日開奩滿鏡春。", "玉立插□長不老，比之太白更精神。"]'),
('65c58e84-ce77-47a7-b160-190232d5dd92','和劉學錄韵  其三','陳宓','宋','宋诗','song-poetry','','[]','兩堤已著金絲縷，平岸行看翠羽茵。',32,'全唐诗/poet.song.186000.json','["兩堤已著金絲縷，平岸行看翠羽茵。", "春晝漸長無一事，艤舟日日待詩人。"]'),
('eb2b8ffb-bc69-4895-812a-e31acc03819c','謝劉學錄惠詩','陳宓','宋','宋诗','song-poetry','','[]','清時自昔有閑人，不獨巢由作外臣。',64,'全唐诗/poet.song.186000.json','["清時自昔有閑人，不獨巢由作外臣。", "聖宋每容求退士，名公多得自由身。", "年將六十仍衰病，才乏錙銖過忝塵。", "若待掛冠年事至，伊誰盡得七旬春。"]'),
('c0008982-111d-4260-ad30-62f5c78b8cb4','賡莆田黄宰梅韵','陳宓','宋','宋诗','song-poetry','','[]','見雪方知惜早梅，飛英久已入清罍。',64,'全唐诗/poet.song.186000.json','["見雪方知惜早梅，飛英久已入清罍。", "青春不覺堂堂至，白髮從教急急催。", "守令仁風能遠被，袴襦和氣已先回。", "從今野老安田里，擬向新年慶大來。"]'),
('dbcd7955-f0ed-4c25-930e-a33cbbae0963','謝東園主人惠荔枝陳紫栽  其一','陳宓','宋','宋诗','song-poetry','','[]','君憐我已是衰翁，乞與長身小圃中。',32,'全唐诗/poet.song.186000.json','["君憐我已是衰翁，乞與長身小圃中。", "不待兒童須遠井，眼前雙紫爛薰風。"]'),
('be71e82b-5fb9-4b8e-aa62-b51acaf5c7ce','謝東園主人惠荔枝陳紫栽  其二','陳宓','宋','宋诗','song-poetry','','[]','千年老幹對壺峰，不數槐庭兩翠龍。',32,'全唐诗/poet.song.186000.json','["千年老幹對壺峰，不數槐庭兩翠龍。", "六月薰風騰彩筆，赤瑛蒼璧畫圖供。"]'),
('30556de6-39e9-4efe-befb-097ed601cb41','謝東庵方處士惠荔枝并詩','陳宓','宋','宋诗','song-poetry','','[]','肺熱仍當六月間，文園多病正求安。',32,'全唐诗/poet.song.186000.json','["肺熱仍當六月間，文園多病正求安。", "何人乞與黄金掌，玉屑清秋露作團。"]'),
('f28e24b9-3dab-44a2-8d15-dc39a4ddf887','承劉學錄示三山佳詠兼欲下旬仙鯉湖宿約以詩謝之  其一','陳宓','宋','宋诗','song-poetry','','[]','誦君盈軸三山詠，喚起前回二紀遊。',32,'全唐诗/poet.song.186000.json','["誦君盈軸三山詠，喚起前回二紀遊。", "老我無因重一到，時將佳句洗昏眸。"]'),
('2b3433eb-53c3-4c8f-9501-9fd3c3c609c2','承劉學錄示三山佳詠兼欲下旬仙鯉湖宿約以詩謝之  其二','陳宓','宋','宋诗','song-poetry','','[]','六年作意觀仙鯉，未得清閑自在身。',32,'全唐诗/poet.song.186000.json','["六年作意觀仙鯉，未得清閑自在身。", "近日孫歸娛膝下，擬拚三日奉高人。"]'),
('c98db995-eb32-40be-895e-35e51cf5591f','承劉學錄示三山佳詠兼欲下旬仙鯉湖宿約以詩謝之  其三','陳宓','宋','宋诗','song-poetry','','[]','秋聲又向耳邊鳴，轉眼平頭六十人。',32,'全唐诗/poet.song.186000.json','["秋聲又向耳邊鳴，轉眼平頭六十人。", "最是讀書難久坐，不甘空負百年身。"]'),
('b98abd8a-4373-484e-b661-27040d1548ee','承劉學錄示三山佳詠兼欲下旬仙鯉湖宿約以詩謝之  其四','陳宓','宋','宋诗','song-poetry','','[]','藤床竹簟稱羸身，獨卧空齋絕點塵。',32,'全唐诗/poet.song.186000.json','["藤床竹簟稱羸身，獨卧空齋絕點塵。", "更有池臺堪却暑，一生清苦愧先人。"]'),
('39d3b08c-0bab-4772-b1c1-dd882de24b2f','謝趙昌父寄詩','陳宓','宋','宋诗','song-poetry','','[]','先生心事本韜藏，無奈詩名宇宙香。',64,'全唐诗/poet.song.186000.json','["先生心事本韜藏，無奈詩名宇宙香。", "古柏幹隆宜壑卧，野梅心苦不羹嘗。", "百年忽遇中興主，九袠猶煩告老章。", "歲晚雪深難出戶，謝篇遥拜德公床。"]'),
('9e90e378-e64e-44fe-a5ff-993d54da23ff','東湖有雙蓮之瑞賡潘瓜山韵','陳宓','宋','宋诗','song-poetry','','[]','積雨東湖久不遊，清風忽送瑞香浮。',64,'全唐诗/poet.song.186000.json','["積雨東湖久不遊，清風忽送瑞香浮。", "初疑並咮鸞窺鏡，元是同心友聚頭。", "我已收身棲𤱶畝，君看盛事擅閩甌。", "從今有月皆佳夕，旋辦輕舠遡碧流。"]'),
('73b5f8ae-3ca6-4e3d-9e6c-95e8f15cc06e','又賡劉學錄雙蓮韵','陳宓','宋','宋诗','song-poetry','','[]','亭亭玉立謝栽培，却笑凡花雜草萊。',64,'全唐诗/poet.song.186000.json','["亭亭玉立謝栽培，却笑凡花雜草萊。", "水面不教蜂蝶見，天邊偏引鷺鷗來。", "化工豈是誇呈瑞，人意何須豈妄猜。", "並秀六房如可信，里中他日又公台。"]'),
('3ad2afe6-2450-4ada-903d-f8a931e82c45','又和劉學錄','陳宓','宋','宋诗','song-poetry','','[]','千竿修碧凈無塵，長伴先生自在身。',64,'全唐诗/poet.song.186000.json','["千竿修碧凈無塵，長伴先生自在身。", "萬卷舊書中夜燭，滿懷和氣四時春。", "長年潄煉顔如玉，一字推敲句有神。", "請踐往時漁艇約，夜深共話兩三人。"]'),
('d778acb9-b0b9-4a85-ae7a-456991e0b2b8','葉吉陽赴任中道而返作居思堂以自娛以詩贈之','陳宓','宋','宋诗','song-poetry','','[]','海山深處擁旌旗，六十紅顔未是遲。',64,'全唐诗/poet.song.186000.json','["海山深處擁旌旗，六十紅顔未是遲。", "千里行程中道返，百年心事幾人知。", "近家園小堪娛目，插架書多足課兒。", "閑看好山忙作吏，主人得計祇緣思。"]'),
('2daa3344-3797-414e-83cc-19b223a0cebd','題陳君肯堂','陳宓','宋','宋诗','song-poetry','','[]','昔人創業無窮思，張大由來在子孫。',64,'全唐诗/poet.song.186000.json','["昔人創業無窮思，張大由來在子孫。", "輪奐已成張老室，駟軒行看漢于門。", "詩書古訓時時習，孝友家風世世存。", "聞道董帷勤課子，不妨遊息有名園。"]'),
('2fed402b-015d-4816-a031-d094c12d392a','約劉學錄同潘喻二丈集滄洲','陳宓','宋','宋诗','song-poetry','','[]','一年擬待中秋夕，連日頻聞正午雷。',64,'全唐诗/poet.song.186000.json','["一年擬待中秋夕，連日頻聞正午雷。", "天若有心開玉匣，月應無恨入金罍。", "素娥與我元無分，秀句憑君試爲催。", "取出團圓盈天璧，不教留在白雲堆。"]'),
('a5710685-852a-4212-be8e-20fbbf4130c6','次年又約二丈集滄洲  其一','陳宓','宋','宋诗','song-poetry','','[]','去年今夕晴還雨，今歲連朝雨忽晴。',31,'全唐诗/poet.song.186000.json','["去年今夕晴還雨，今歲連朝雨忽晴。", "不請高人來共看，月華肯十分明。"]'),
('74d93943-a60a-42a6-a622-6502b628a771','次年又約二丈集滄洲  其二','陳宓','宋','宋诗','song-poetry','','[]','滄洲荷蓋已先枯，嫩處猶堪酌酒壺。',32,'全唐诗/poet.song.186000.json','["滄洲荷蓋已先枯，嫩處猶堪酌酒壺。", "小舫共遊期到曉，夜深尚可覓寒鱸。"]'),
('6e70c45e-4e08-47bc-9af3-d22cceb75487','和潘丈四子詩韵','陳宓','宋','宋诗','song-poetry','','[]','此心無日不風沂，常恐春隨柳絮飛。',64,'全唐诗/poet.song.186000.json','["此心無日不風沂，常恐春隨柳絮飛。", "才覺迷途先獨復，便於安危作真歸。", "生來理欲雖殊本，轉處危微在一機。", "同志願言勤諷詠，莫教古瑟至音希。"]'),
('b1bd94c6-62ed-4176-beb1-817d13ba1916','酌建陽王氏酒','陳宓','宋','宋诗','song-poetry','','[]','不杯神觀已陶然，三四蓬壺小有天。',32,'全唐诗/poet.song.186000.json','["不杯神觀已陶然，三四蓬壺小有天。", "當日流霞唯一盞，却輸玉嫗是真仙。"]'),
('147293f8-08da-48f7-98c8-0a7d401c4f13','約潘瓜山劉學錄登高  其一','陳宓','宋','宋诗','song-poetry','','[]','三年八日登高集，喜趁衰年尚健身。',32,'全唐诗/poet.song.186000.json','["三年八日登高集，喜趁衰年尚健身。", "不爲黄華浮白酒，世間難得是閑人。"]'),
('6de96385-2858-44a9-8ec8-eee90cf3312d','約潘瓜山劉學錄登高  其二','陳宓','宋','宋诗','song-poetry','','[]','聞君欲作三山客，且約先銜九日杯。',32,'全唐诗/poet.song.186000.json','["聞君欲作三山客，且約先銜九日杯。", "莫道隔年方再會，芙蓉恰恰遶湖開。"]'),
('96e77aca-cf93-41a4-a961-e947245c9464','謝東園主人惠竹石以紫石盆貯之','陳宓','宋','宋诗','song-poetry','','[]','幽人巧琢紫璠璵，中貯琅玕一尺餘。',32,'全唐诗/poet.song.186000.json','["幽人巧琢紫璠璵，中貯琅玕一尺餘。", "怪石嵌岩苔蘚古，坐移衡霍入吾廬。"]'),
('9607cdda-a553-4ffb-8c7c-67f916dc2d8c','潘丈遊南寺靈巖天台回遂呈劉學錄','陳宓','宋','宋诗','song-poetry','','[]','不到南山逐勝遊，新詩題遍柳公樓。',64,'全唐诗/poet.song.186000.json','["不到南山逐勝遊，新詩題遍柳公樓。", "須驅塵世蚊蝱暑，喚起雲天鵰鶚秋。", "醆斝獻酬依未蔭，笑談喧寂間川流。", "自憐因病成慵懶，一日那無一日休。"]'),
('abcdcf83-c247-4315-b74d-d23408eb25eb','邀同社十七人遊靈巖天台次前韵呈潘劉','陳宓','宋','宋诗','song-poetry','','[]','凌晨避暑作清遊，烈日方中悚玉樓。',64,'全唐诗/poet.song.186000.json','["凌晨避暑作清遊，烈日方中悚玉樓。", "石刻儼如元祐日，榜題猶带有唐秋。", "二三弟姪皆同志，十一賓朋盡勝流。", "共侍潘劉兩夫子，夕陽歸路語難休。"]'),
('52d15c20-9ca1-46ff-9525-1bf1e32d7885','風雨漲簷溜憶東平以疾不往','陳宓','宋','宋诗','song-poetry','','[]','不到東平夏又秋，閑居身尚不吾由。',32,'全唐诗/poet.song.186000.json','["不到東平夏又秋，閑居身尚不吾由。", "可憐巖上千尋瀑，不似簷前一派流。"]'),
('59be95eb-93cf-4439-a622-80607738dbf4','和白居易西亭詩韵','陳宓','宋','宋诗','song-poetry','','[]','不是清高辭好爵，都緣衰病乞閑身。',32,'全唐诗/poet.song.186000.json','["不是清高辭好爵，都緣衰病乞閑身。", "年來印曆依然在，批上東湖第五春。"]'),
('a8254e13-9151-4881-83aa-596dc020623f','送真右史守泉','陳宓','宋','宋诗','song-poetry','','[]','昔人爲太守，南物不入囊。',288,'全唐诗/poet.song.186000.json','["昔人爲太守，南物不入囊。", "亦有市文集，悔恨不能忘。", "所以致平理，閭閻富而康。", "泉民困賦役，脫身事舟航。", "絕域在何許，羈留動經霜。", "南風不堪託，十發五飄揚。", "過期不見歸，妻子泣相望。", "所得知幾何，舊債未及償。", "公家既重征，忍痛如刳腸。", "况復吏不仁，低價盡取將。", "民財本膏血，舶貨尤可傷。", "吾聞坡仙言，犂牛博沉香。", "燔牛以祈福，鬼神尚弗享。", "安可以人命，緘封壽侯王。", "上天不可欺，厥咎必有當。", "近年有賢守，永嘉詹事王。", "不買一錢物，至今垂耿光。", "後來豈無繼，落落難爲常。", "祇今逢右史，真節動八方。", "江東百萬戶，水旱俱不荒。", "明時豈憚黷，實欲重淮陽。", "舶使出名門，家傳饒清芳。", "玉雪兩相映，酷熱變寒凉。", "預聽桐城謠，合浦珠還鄉。"]'),
('959e8338-ad3f-4eb2-a2c6-7c5752504f40','送鄒給事','陳宓','宋','宋诗','song-poetry','','[]','皇天祐我宋，衮衮生巨人。',288,'全唐诗/poet.song.186000.json','["皇天祐我宋，衮衮生巨人。", "正學邁賈董，彤庭親選掄。", "聲名喧宇宙，勳業見寅亮。", "偉哉呂與李，王陳踵經綸。", "文章特餘事，德行金玉純。", "文靖有雅量，風雲際熙辰。", "所以到聖治，唐虞俗再淳。", "先生軼前駕，學力欺孟荀。", "平生事靖退，墨頭自要津。", "群小競狐媚，佳兵媒其身。", "挺然出正論，玉色垂大紳。", "銀臺凜風駁，世仰鳳與麟。", "直道志丘壑，通塗輟樞鈞。", "豈爲一己計，寧牧千里民。", "泉山號大郡，氓賈甲七閩。", "以寬則容姦，急則鰥寡顰。", "先生得其道，三年政和均。", "孰疾不得醫，孰屈不得伸。", "餐藥置左右，砂芹不再陳。", "建閣儲六籍，鑿井膏城闉。", "巍巍百雉堞，樓櫓俄一新。", "海壖亦有學，窮邑增廩囷。", "百廢已具舉，一毫不驚塵。", "此特以迹言，孰識襟懷春。"]'),
('9a34daef-bbd6-49e9-be57-e9dadb9fb8d9','送陳守子華宿土囊有感','陳宓','宋','宋诗','song-poetry','','[]','三年抱恙多閉門，祇得兩度敲禪扃。',96,'全唐诗/poet.song.186000.json','["三年抱恙多閉門，祇得兩度敲禪扃。", "道人問我緣底出，爲送鄉城兩史君。", "闤中暑濕如炊甑，山寺陰凉百僧定。", "往年過此苦怱怱，今日海山看古鏡。", "伊誰一念飯行人，至今規矩猶如新。", "可嘆延平小書舍，虛致雩橋風月夜。"]'),
('b46db034-c6b2-40f5-a557-3138a4e1a33a','送師道弟調選','陳宓','宋','宋诗','song-poetry','','[]','人生重五馬，亦須在中州。',96,'全唐诗/poet.song.186000.json','["人生重五馬，亦須在中州。", "若弟虛慕名，不憚南荒陬。", "何如貳近郡，責輕俸仍優。", "親老可近侍，取廉不嫌求。", "勿信他人語，只足企前脩。", "我衰又多病，卧家將四秋。", "小池有芰荷，遲子來共遊。", "作詩送行李，勇返勿悠悠。"]'),
('093cf62d-f870-4f1f-8877-b75e993f99ed','送劍浦王丞','陳宓','宋','宋诗','song-poetry','','[]','二松雖在眼，三徑每興思。',132,'全唐诗/poet.song.186000.json','["二松雖在眼，三徑每興思。", "到官未數月，歸袖西風披。", "雅志不可屈，凌晨騎難追。", "視彼嗜進者，寧能無忸怩。", "月湖老居士，勇退世所知。", "年未至謝事，一疏攄天墀。", "卧家不肯出，八年山水嬉。", "秀句滿泉石，無因寄目窺。", "見爲我致謝，吾今鬢成絲。", "試郡了無術，空餐愧鰥嫠。", "行矣還山林，逢人頻寄詩。"]'),
('df7bb69d-ae8a-4be8-80ab-7f65ffe7bc6f','送黄帳幹之江西任','陳宓','宋','宋诗','song-poetry','','[]','黄君真可人，鄉校久推許。',180,'全唐诗/poet.song.186000.json','["黄君真可人，鄉校久推許。", "文詞波濤翻，勁氣金石沮。", "危言奉大對，考官不敢取。", "五十尉南邦，聲名塞漳浦。", "閭里喜過從，未聽滄洲雨。", "于何舍我去，遊宦大江滸。", "吾聞江西民，自昔號貧窶。", "邇來公私匱，孰能明取與。", "君今佐使長，賢明可進語。", "地要連邊淮，洞深要摩撫。", "鄭公有成規，士飽始禦侮。", "同僚得鄉彥，燈窗飫勤苦。", "崇臺共經綸，數郡足機杼。", "竱心愛民力，西顧寬當宁。", "行行謹勿遲，赤子方仰乳。"]'),
('da486373-b593-4ef5-9828-915828d05392','安溪送泉倅','陳宓','宋','宋诗','song-poetry','','[]','平生順天命，渴飲與饑飯。',216,'全唐诗/poet.song.186000.json','["平生順天命，渴飲與饑飯。", "不能便利趨，俛首榷商販。", "隨群謁上官，言語但樸愿。", "豈知事迎合，宛轉若藤蔓。", "秉心實無它，世俗乃憎怨。", "豈期筮仕初，邂逅適素願。", "明公行都來，郡政畢已逮。", "不惟辱寬假，時亦蒙誘勸。", "王事有期程，後我念遲鈍。", "公今趨天朝，尚我坐塵坌。", "感恩顧未報，送別益增恨。", "偉哉佐此邦，聲名不前遜。", "專城亦數月，蒙福數十萬。", "清介持一律，冰玉不可溷。", "從來士大夫，德劭才或困。", "豈如明公賢，全美難悉論。", "行看廟堂上，相先以名獻。", "斐然作詩歌，聊寫意繾綣。"]'),
('e9f27fd4-af17-4ec3-84fe-0483166ca24f','三山送樓幹','陳宓','宋','宋诗','song-poetry','','[]','九仙山頭二月春，百花璀璀凝芳辰。',240,'全唐诗/poet.song.186000.json','["九仙山頭二月春，百花璀璀凝芳辰。", "看花未省並驄馬，酌酒况復違佳人。", "人人家在赤城裏，五百大士疑前身。", "襟懷喜作冰玉相，耳目不染聲色塵。", "鯨呿鰲擲擅文傑，撐腹萬卷筆有神。", "妙齡卓冠蘭宮士，便合褰裳要路津。", "玉堂三事久虛職，憲幕兩載留南閩。", "平生避名如避寇，諸公詎肯遺奇珍。", "顯親急欲賁泉壤，襆被路馬趨嚴宸。", "囊中之方久不試，小試疲瘵蘇斯民。", "自慙草木非君味，傾蓋一見情何親。", "金篦時爲發膜翳，淡交耐久如荀陳。", "懸知後會近可卜，暫時分披仍逡巡。", "丈夫萬里耿相望，所要守道全其真。", "準擬千鍾澆此恨，却恐爛醉污車茵。"]'),
('083cf835-535a-415b-8c3d-103770c8194c','送鄭丈婿孚先改秩用廣西諸公韵','陳宓','宋','宋诗','song-poetry','','[]','間關萬里遊嶺海，誰知丈夫志有在。',128,'全唐诗/poet.song.186000.json','["間關萬里遊嶺海，誰知丈夫志有在。", "古賢足迹滿四方，豈但青編勤摭采。", "胸多聞見益崔嵬，節歷險夷終不改。", "山川輝潤認珠玉，草木芬芳瀼蘭茝。", "如何識者尚爾稀，呈露炎方越三載。", "西風穩送朝天行，高懷皎皎秋俱清。", "有親鶴髮要榮養，伉儷不必多爲情。", "翺翔一鶚橫空翼，喧啾百鳥息飛鳴。"]'),
('6ef4c26b-98cd-499e-883c-3b939f87c122','送李尉赴寧德任','陳宓','宋','宋诗','song-poetry','','[]','誰謂山城僻，而居尉秩卑。',48,'全唐诗/poet.song.186000.json','["誰謂山城僻，而居尉秩卑。", "地偏聲易著，才鉅職優爲。", "學召源流遠，仁隨大小施。", "雲龕當日事，即此以爲基。"]'),
('fb81dd0b-9b01-4128-a827-1bf3cb9cafbb','送圭子赴淮南總所排岸任','陳宓','宋','宋诗','song-poetry','','[]','久叨簪紱裔，初筮帝王州。',48,'全唐诗/poet.song.186000.json','["久叨簪紱裔，初筮帝王州。", "祖德期無忝，君恩要力酬。", "存心惟敬謹，律己必清脩。", "千里書頻寄，重親鬢已秋。"]'),
('b6c1c179-45f5-4c93-9b3c-6b4ccf981510','送師道弟赴官靖州','陳宓','宋','宋诗','song-poetry','','[]','去佐湖陰郡，炎征六十程。',48,'全唐诗/poet.song.186000.json','["去佐湖陰郡，炎征六十程。", "東南疆尚狹，朝暮騎仍輕。", "民困恩宜厚，蠻驕隙易生。", "廉勤先訓在，遲汝振家聲。"]'),
('13041052-272b-495f-947a-41b0e983e354','送方簽判赴江西任','陳宓','宋','宋诗','song-poetry','','[]','洪都稱大府，上幕得名賢。',48,'全唐诗/poet.song.186000.json','["洪都稱大府，上幕得名賢。", "事業三千牘，聲名四十年。", "民征須力減，酒禁更堪憐。", "餘力猶能辦，開塗及濟川。"]'),
('04a54ef1-ab4b-4e33-b254-541f55769909','送楊丈志仁歸三山','陳宓','宋','宋诗','song-poetry','','[]','不見楊夫子，于今歲再逾。',48,'全唐诗/poet.song.186000.json','["不見楊夫子，于今歲再逾。", "窮經探古聖，執禮邁諸儒。", "參月陪高論，西風操別袪。", "鍾山容膝地，亦足當吾廬。"]'),
('72dda59c-6579-4614-8925-70b968db546a','送姚僉判','陳宓','宋','宋诗','song-poetry','','[]','杜門三載疑無緣，不似當年在劍川。',64,'全唐诗/poet.song.186000.json','["杜門三載疑無緣，不似當年在劍川。", "衰病可曾同酒琖，俗氛那得和詩篇。", "楓宸領袖三千士，蓮幕徊翔十七年。", "榮進在公真素定，槎溪嫡派看初傳。"]'),
('575c1fe2-c521-4bb3-997e-d69cc6123334','送劉學錄之建陽  其一','陳宓','宋','宋诗','song-poetry','','[]','馬蹄千里踏春風，爲愛河陽製錦工。',32,'全唐诗/poet.song.186000.json','["馬蹄千里踏春風，爲愛河陽製錦工。", "首重儒宗新像設，不妨特地拜文公。"]'),
('f0c9fd69-2bc2-4b66-a71c-f5de84d661f4','送劉學錄之建陽  其二','陳宓','宋','宋诗','song-poetry','','[]','寶劍韜藏久未伸，天生南浦一文人。',32,'全唐诗/poet.song.186000.json','["寶劍韜藏久未伸，天生南浦一文人。", "好將玉匣呈巖電，洗出寒光萬丈新。"]'),
('460fb637-ab33-483a-848e-24aa6596fd22','送莆田黄宰','陳宓','宋','宋诗','song-poetry','','[]','松竹林中一鉅儒，逢人開口是璣珠。',64,'全唐诗/poet.song.186000.json','["松竹林中一鉅儒，逢人開口是璣珠。", "三年訟簡獄生草，百里刑清鞭用蒲。", "直節正當裨黼扆，高情何事憶枌榆。", "送公歸後慵回首，尺素西風恐鴈孤。"]'),
('fb4293b7-1a74-4b6e-a98b-f8c4a351da5b','送師道弟守德慶','陳宓','宋','宋诗','song-poetry','','[]','乃父高皇侍從臣，汝今潜邸牧疲民。',64,'全唐诗/poet.song.186000.json','["乃父高皇侍從臣，汝今潜邸牧疲民。", "天低日近偏臨照，土曠人稀費撫循。", "得暇詩書休釋手，先公法律自治身。", "舟來勿寄南方物，只寄平反愜老親。"]'),
('a6d4039f-ee98-4c0b-8694-13028d36d83e','三山送真景元','陳宓','宋','宋诗','song-poetry','','[]','蓋世功名國子師，青春入覲道方夷。',64,'全唐诗/poet.song.186000.json','["蓋世功名國子師，青春入覲道方夷。", "榮華素定終須有，事業難期便勇爲。", "此日清尊同一笑，明朝丹陛聽危詞。", "東風總送仙舟去，楊柳江頭謾似絲。"]'),
('5acb49cb-8f1d-4a78-9675-d7fdada542c8','送孫生季蕃歸浙水','陳宓','宋','宋诗','song-poetry','','[]','平生行止都無著，恰似孤雲自在閑。',64,'全唐诗/poet.song.186000.json','["平生行止都無著，恰似孤雲自在閑。", "四十餘年倦江浙，二千里外擇溪山。", "窮愁元不上雙鬢，秀句僅能窺一班。", "與子暫分非久別，西風時節賦刀鐶。"]'),
('7fb5f2f6-e1ef-4a10-892e-a8ff6ecc216d','送胡仲方西歸','陳宓','宋','宋诗','song-poetry','','[]','後進無因見老成，一覘風采快平生。',64,'全唐诗/poet.song.186000.json','["後進無因見老成，一覘風采快平生。", "南來幸有同寮契，西去寧無惜別情。", "五載官聯親懿德，遠夷君長慕清名。", "明時用取真才具，休使詩聲祇自鳴。"]'),
('47f91070-493d-432c-a140-617f477adf53','送陳國正','陳宓','宋','宋诗','song-poetry','','[]','美譽清名世所推，南州曾作幾人師。',64,'全唐诗/poet.song.186000.json','["美譽清名世所推，南州曾作幾人師。", "不遲班鬢登臺省，却喜青雲得路岐。", "節義定高東漢士，文章須復董生時。", "郡芳非久霑霖雨，且看儒宮習少儀。"]'),
('75ccf5b4-a32c-4cbb-b02e-6fa4b0bf8253','送延平二堂長','陳宓','宋','宋诗','song-poetry','','[]','延平學術號淵源，端的名師四代傳。',64,'全唐诗/poet.song.186000.json','["延平學術號淵源，端的名師四代傳。", "連歲朋來多秀士，一朝歸去兩高賢。", "休言道統追千載，但淑人心直幾錢。", "見說新侯真好學，弓旌不日定招延。"]'),
('2bfff705-d106-45cd-9e05-f5c5c6d66975','送撫州李兄武伯歸鄉  其一','陳宓','宋','宋诗','song-poetry','','[]','少年文學已精深，更向周程一派尋。',32,'全唐诗/poet.song.186000.json','["少年文學已精深，更向周程一派尋。", "千里求師寧憚遠，殷勤要識聖賢心。"]'),
('ad522d4a-a0c0-4dc3-b883-b9ca8e7a2bac','送撫州李兄武伯歸鄉  其二','陳宓','宋','宋诗','song-poetry','','[]','我恨逢師較已遲，羨君早歲獨先知。',32,'全唐诗/poet.song.186000.json','["我恨逢師較已遲，羨君早歲獨先知。", "歸時剩把遺書讀，莫道□峰永別離。"]'),
('f64c2df9-bb9d-48ba-98e7-d6caa91dcd71','臨安送鄭左藏  其一','陳宓','宋','宋诗','song-poetry','','[]','華髮蕭然入帝城，如何直道尚迂遲。',64,'全唐诗/poet.song.186000.json','["華髮蕭然入帝城，如何直道尚迂遲。", "從來白璧稱和氏，安得黄金到不疑。", "歸騎正須誇疾速，慈顔想見倍歡怡。", "人生最是團欒樂，况值薰風荔子時。"]'),
('d85ebcfb-0aba-4a23-b62c-444650dc0c26','臨安送鄭左藏  其二','陳宓','宋','宋诗','song-poetry','','[]','還家香稻薦新紅，樂歲佳辰定不空。',64,'全唐诗/poet.song.186000.json','["還家香稻薦新紅，樂歲佳辰定不空。", "綠醑好邀山月飲，紫鱗長與海潮通。", "不妨香火尋高士，祇恐經綸欠此翁。", "我亦欲歸歸未得，相逢端的是西風。"]'),
('61298c89-1f37-44bf-b799-74a3119851e0','送趙司直赴常德倅  其一','陳宓','宋','宋诗','song-poetry','','[]','武陵佳處是桃源，謬說伊誰爲探原。',32,'全唐诗/poet.song.186000.json','["武陵佳處是桃源，謬說伊誰爲探原。", "會得桃花流水意，歸來休向俗人言。"]'),
('6dd0991a-fecb-4b42-92ba-de3d186fd55d','送趙司直赴常德倅  其二','陳宓','宋','宋诗','song-poetry','','[]','當年好禮一河間，今日躬行倍譽難。',32,'全唐诗/poet.song.186000.json','["當年好禮一河間，今日躬行倍譽難。", "三百威儀皆曲中，胸中冰雪照人寒。"]'),
('0e0a9533-a9cc-4524-b50b-01d30d923a26','送王丞','陳宓','宋','宋诗','song-poetry','','[]','二王聲價重清漳，久合翺翔畫省郎。',64,'全唐诗/poet.song.186000.json','["二王聲價重清漳，久合翺翔畫省郎。", "再轉哦松人謂屈，一同製錦我師長。", "纖毫不擾民懷德，三載寬征惠及商。", "此去天庭承雨露，書來須及晚秋凉。"]'),
('16adb7ec-407b-4395-9f18-1e7693df95eb','送趙主簿','陳宓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','簿領官居小似船，清溪深處隠三年。',64,'全唐诗/poet.song.186000.json','["簿領官居小似船，清溪深處隠三年。", "才華警敏恢牛刃，行李蕭疎跨鶴仙。", "羅渡分携雖有恨，西湖相見豈無緣。", "殷勤記取臨岐語，金玉精神更節宣。"]'),
('a3fa0715-9e98-461e-b6cb-4d27fcfa7ab2','送李倅','陳宓','宋','宋诗','song-poetry','','[]','太末先生道德尊，朅來閩底佐雄藩。',64,'全唐诗/poet.song.186000.json','["太末先生道德尊，朅來閩底佐雄藩。", "兩年不作如絃急，千里真成挾纊溫。", "南畝但聞農擊壤，列城那得吏敲門。", "胸中久藴經綸業，盍上星辰侍紫垣。"]'),
('4f18e394-f3a1-4918-b64c-1b68970d246c','送胡提幹','陳宓','宋','宋诗','song-poetry','','[]','奇琛瓌賮滿桐城，中有清冰一段明。',64,'全唐诗/poet.song.186000.json','["奇琛瓌賮滿桐城，中有清冰一段明。", "靜室只知心可養，當官底患志難行。", "三年兩度承嘉話，百里無因訴別情。", "預想山陰溪畔雪，扁舟訪戴定尋盟。"]'),
('6216ca48-d115-47db-ae06-a9d0ebbc6cb2','送王推赴調  其一','陳宓','宋','宋诗','song-poetry','','[]','俯視庸流四海空，縱橫萬卷貯胸中。',64,'全唐诗/poet.song.186000.json','["俯視庸流四海空，縱橫萬卷貯胸中。", "蘭臺不日看登用，蓮幕三年肯奏功。", "松逕未荒心已動，雪舟誰辦興先窮。", "帝城春事需春到，詎許□菲褪白紅。"]'),
('7a52291b-71f7-4d73-acde-40242e01bfb8','送王推赴調  其二','陳宓','宋','宋诗','song-poetry','','[]','青春初破未容深，趁得清明到武林。',64,'全唐诗/poet.song.186000.json','["青春初破未容深，趁得清明到武林。", "官柳野花供醉矚，版橋山石愜歸心。", "長才凜凜恢遊刃，善政優優得理琴。", "好去天朝鳴佩玉，海邊童叟謾歌吟。"]'),
('331ca172-24be-4cbc-a600-ebd24b09cc8d','送懷安林知丞之官仍謝佳句  其一','陳宓','宋','宋诗','song-poetry','','[]','艾軒門第多諸父，尚想高齋講誦時。',32,'全唐诗/poet.song.186000.json','["艾軒門第多諸父，尚想高齋講誦時。", "誰道風流今已泯，親篇三復起予詩。"]'),
('24b9d6d1-7798-4e79-adc3-a5c663fe5965','送懷安林知丞之官仍謝佳句  其二','陳宓','宋','宋诗','song-poetry','','[]','讀書豈但資聞見，窮理方能識重輕。',32,'全唐诗/poet.song.186000.json','["讀書豈但資聞見，窮理方能識重輕。", "孔孟格言如日月，更須師友與詳評。"]'),
('2cf12b9d-88aa-406f-bcf6-c00077901d31','送懷安林知丞之官仍謝佳句  其三','陳宓','宋','宋诗','song-poetry','','[]','劍津初筮著能名，大府今看佐屬城。',32,'全唐诗/poet.song.186000.json','["劍津初筮著能名，大府今看佐屬城。", "愧我贈行無好語，祇將戒懼與明誠。"]'),
('34c5e818-c2bf-4ad0-acd2-8d7b10725b99','送林知丞赴石城任  其一','陳宓','宋','宋诗','song-poetry','','[]','往時吾里有師儒，受業窮年鄒魯如。',32,'全唐诗/poet.song.186000.json','["往時吾里有師儒，受業窮年鄒魯如。", "今日喜君求益友，螢窗共究聖賢書。"]'),
('f244e9a4-51e2-4f7b-85cc-c91d0c49eff0','送林知丞赴石城任  其二','陳宓','宋','宋诗','song-poetry','','[]','贛上貧民最可憐，唯憑令佐予安全。',32,'全唐诗/poet.song.186000.json','["贛上貧民最可憐，唯憑令佐予安全。", "正人况值爲侯牧，撫字催科審後先。"]'),
('1370bfd5-b702-44b9-bee6-a128fb3e97b1','送師道弟調選','陳宓','宋','宋诗','song-poetry','','[]','三年試邑似從軍，救過何心望策勳。',64,'全唐诗/poet.song.186000.json','["三年試邑似從軍，救過何心望策勳。", "但得當時無愧怍，便知後日有芳芬。", "身名莫嘆行將老，學業由來進在勤。", "子到長安謹交友，杜門切勿混蕕薰。"]'),
('a4200c7a-c870-4ce3-8ac7-9df6d0e1708f','送榷院姪之官','陳宓','宋','宋诗','song-poetry','','[]','積善門逢八十春，慈兄藴德復溫醇。',64,'全唐诗/poet.song.186000.json','["積善門逢八十春，慈兄藴德復溫醇。", "舊恩未報乾坤大，新渥仍霑雨露勻。", "博洽始能爲國計，清忠方不負廷紳。", "我今衰病知何用，訪有書來訪海滣。"]'),
('786ed455-5099-4c34-8995-4bc42d1b9353','壽外舅龔通判','陳宓','宋','宋诗','song-poetry','','[]','毓秀方壺應半千，先春二日秩初筵。',96,'全唐诗/poet.song.186000.json','["毓秀方壺應半千，先春二日秩初筵。", "澄陂萬頃難同量，野鶴高標不計年。", "楚國潔清真有繼，石君孝謹更光前。", "久期卓令三公秩，尚借陳蕃別駕賢。", "紛若盡隨春卉媚，恬然獨與雪筠堅。", "鄙人辱眷尤欽佩，拜壽裁詩佐玉船。"]'),
('90f9affe-fe9b-40a4-a9d5-05f191040877','人日壽外姑方氏','陳宓','宋','宋诗','song-poetry','','[]','九袠華齡開第一，畫堂瑞氣藹葱葱。',64,'全唐诗/poet.song.186000.json','["九袠華齡開第一，畫堂瑞氣藹葱葱。", "綵花寶勝年年好，綠鬢朱顔歲歲同。", "五福誰人如壽考，四時何日不春風。", "門闌應笑龍鍾壻，作吏風塵□兩翁。"]'),
('2f07a15a-cca2-4b04-9f1e-317f27f0d800','壽崇清陳侍郎','陳宓','宋','宋诗','song-poetry','','[]','衛武當年解賦詩，若揮椽筆定應疲。',64,'全唐诗/poet.song.186000.json','["衛武當年解賦詩，若揮椽筆定應疲。", "先生名德都相似，餘事才能更過之。", "雲岫圖書供宴坐，滄浪風月足追隨。", "久閑精力天教健，更看三爲帝者師。"]'),
('1b895b6b-0022-4f08-88f2-2989a64a4ff1','壽大兄帥參開國','陳宓','宋','宋诗','song-poetry','','[]','黄陂不撓已稱賢，况復胸中別有天。',64,'全唐诗/poet.song.186000.json','["黄陂不撓已稱賢，况復胸中別有天。", "最好誕朝嘉節後，更斟壽酒菊花前。", "平生不作南金想，晚歲真成白璧全。", "退食琳宮懷補報，壺山早晚祝堯年。"]'),
('82a8536c-7b8a-4a15-9e7d-8a82bfdcc7d6','壽劉學錄','陳宓','宋','宋诗','song-poetry','','[]','壽酒今年勝去年，綵衣膝下月宮仙。',32,'全唐诗/poet.song.186000.json','["壽酒今年勝去年，綵衣膝下月宮仙。", "丈人自有長生訣，子午常朝玉帝前。"]'),
('3ab54f65-b0a7-4405-94fc-623fc611c867','壽傅忠簡','陳宓','宋','宋诗','song-poetry','','[]','一陽初起黄鍾宮，紅日出海光曈矓。',272,'全唐诗/poet.song.186000.json','["一陽初起黄鍾宮，紅日出海光曈矓。", "天高地下氣久雺，萬物閉塞如惛懵。", "造化環復極則通，天於此時生我公。", "公之累世載孝忠，受天問氣和沖融。", "聚爲文章發鴻濛，一門二季繼乃翁。", "平生濟民願力洪，要令飛走毋罝籠。", "出殿大邦眷彌隆，富沙千里無疲癃。", "京口移鎮事益叢，流離滿目羅羈窮。", "公爲不食摩其躬，溝壑百萬俱恩蒙。", "刻身節用財自豐，所至露積民力充。", "民方慕公如阜螽，上章力去橫飛鴻。", "公以止足厲頹風，其如夏夷望膚功。", "晚作一第方簾櫳，頭白丹心尚宸楓。", "願公之壽等華嵩，我宋社稷長尊雄。", "嗟予小子最倥侗，公安取此不言鬷。", "知己之恩大穹窿，當期報效如纖塳。", "吟詩勸侑酒一中，愧我才淺難爲工。"]'),
('34cefbfd-aeac-450e-b462-181bf88585d9','壽龔國太','陳宓','宋','宋诗','song-poetry','','[]','三朝十國錫封頻，八袠華齡歲律新。',64,'全唐诗/poet.song.186000.json','["三朝十國錫封頻，八袠華齡歲律新。", "膝下平分千里月，門中渾作一家春。", "已將相業傳諸子，更喜聞孫早有人。", "歲挹壺山入壺斝，壽溪衮衮壽杯醇。"]'),
('03f9b428-ec99-4750-9f03-2ef3fffa963d','挽陳通直','陳宓','宋','宋诗','song-poetry','','[]','一門盛事更誰同，四代班衣八十翁。',64,'全唐诗/poet.song.186000.json','["一門盛事更誰同，四代班衣八十翁。", "有子可傳醫國術，在家還著活人功。", "平陽遺愛千年遠，有道新碑百丈豐。", "愧我無因陪執紼，祇將雙淚寄西風。"]'),
('a297d958-2a07-4907-b360-86fa1983bd46','挽王侍郎','陳宓','宋','宋诗','song-poetry','','[]','天台雄秀萃方岩，仙骨童時已不凡。',64,'全唐诗/poet.song.186000.json','["天台雄秀萃方岩，仙骨童時已不凡。", "才傑少魁金榜第，年高猶带侍臣銜。", "蚤因名節成閑退，晚等薰蕕謝謗讒。", "衰老濫稱門下客，有懷無復寄書函。"]'),
('9807a0cd-04b5-41bd-822c-3e705381d261','挽蔡汀州','陳宓','宋','宋诗','song-poetry','','[]','文價瓊琚重，心期玉雪清。',48,'全唐诗/poet.song.186000.json','["文價瓊琚重，心期玉雪清。", "如何後忠惠，不使累公卿。", "宰縣多遺愛，題輿有最聲。", "朱幡驚斷裂，悵望上杭城。"]'),
('3f01e4f3-c34a-46e9-aba0-2c509b915493','挽方處士','陳宓','宋','宋诗','song-poetry','','[]','早歲功名摘頷毛，盛年丘腹壯心豪。',64,'全唐诗/poet.song.186000.json','["早歲功名摘頷毛，盛年丘腹壯心豪。", "寧知天上台躔貴，不換山中處士高。", "滿架詩書供夜話，一園花柳送春醪。", "年開八袠誠何憾，無奈親姻自慘騷。"]'),
('8836729d-4ccd-4f89-9c15-e427ab4ed847','挽建寧林知丞','陳宓','宋','宋诗','song-poetry','','[]','闕下家聲世所宗，九侯珪組疊仍重。',64,'全唐诗/poet.song.186000.json','["闕下家聲世所宗，九侯珪組疊仍重。", "清風直節千尋聳，洪度澄陂萬頃容。", "教子辛勤方折桂，爲官清退謾哦松。", "活人未遂平生志，揮涕俄驚四尺封。"]'),
('916c44ee-81b7-4df9-b0b4-e73f63f8ded4','挽知府陳大著','陳宓','宋','宋诗','song-poetry','','[]','艾軒今有幾門人，盛德如公復喪淪。',64,'全唐诗/poet.song.186000.json','["艾軒今有幾門人，盛德如公復喪淪。", "蚤歲文名喧米廩，莫年祿秩竟朱輪。", "閭閻方頌循良政，臺閣猶傳剴切陳。", "擬俟垂車隨賀客，如何永別淚沾巾。"]'),
('c495658d-151c-4c6f-9cce-d67b6f34f5d5','聞海陽姪訃','陳宓','宋','宋诗','song-poetry','','[]','近來不得海陽書，但見諸公論薦渠。',32,'全唐诗/poet.song.186000.json','["近來不得海陽書，但見諸公論薦渠。", "四十二年成夭閼，慈兄豈是澤無餘。"]'),
('f100a668-152d-4683-a79f-805246123be9','挽傅仲斐生母李氏  其一','陳宓','宋','宋诗','song-poetry','','[]','版輿當日到莆陽，盛事于今語未央。',32,'全唐诗/poet.song.186000.json','["版輿當日到莆陽，盛事于今語未央。", "教子延師如學校，揮金提路作康莊。"]'),
('4935e636-b44b-44c7-babc-197846d4b1fd','挽傅仲斐生母李氏  其二','陳宓','宋','宋诗','song-poetry','','[]','已登椿柏七旬算，終錫花釵九樹妝。',32,'全唐诗/poet.song.186000.json','["已登椿柏七旬算，終錫花釵九樹妝。", "懿行在人今已矣，西風笳鼓助凄凉。"]'),
('a2c9309d-c322-4d3e-b896-56a78cbba8e4','挽方漕  其一','陳宓','宋','宋诗','song-poetry','','[]','使軺三度破胡塵，祇爲忠謀不爲身。',32,'全唐诗/poet.song.186000.json','["使軺三度破胡塵，祇爲忠謀不爲身。", "後輩金繒能不吝，却嗤木强是前人。"]'),
('96e1af33-4bf1-40e3-a4ee-0494acfcfbf3','挽方漕  其二','陳宓','宋','宋诗','song-poetry','','[]','半生與士共饑寒，百萬渾將一擲看。',32,'全唐诗/poet.song.186000.json','["半生與士共饑寒，百萬渾將一擲看。", "四十世官持簜節，活人無數奉親歡。"]'),
('0c7fe7f3-38be-4afc-a24a-523011a7617e','挽方漕  其三','陳宓','宋','宋诗','song-poetry','','[]','淮南草木舊知名，胡騎應愁水偃成。',32,'全唐诗/poet.song.186000.json','["淮南草木舊知名，胡騎應愁水偃成。", "自是人豪長不死，如何腸斷些歌聲。"]'),
('172f2ff1-da32-4b16-a5b8-b38ac8817a73','挽方寺丞','陳宓','宋','宋诗','song-poetry','','[]','璧水聲名冠上遊，蚤年絳帳向荆州。',64,'全唐诗/poet.song.186000.json','["璧水聲名冠上遊，蚤年絳帳向荆州。", "平生夢寐無塵土，壯歲雍容拜冕旒。", "共擬一麟爲國瑞，俄驚五馬作仙遊。", "貞元曾是同朝士，忍見丹旌葬壟丘。"]'),
('ae8deab2-db39-4220-9985-53bd9a8df094','挽鄭通判','陳宓','宋','宋诗','song-poetry','','[]','厚重公清譽藹然，人言端似楚公賢。',64,'全唐诗/poet.song.186000.json','["厚重公清譽藹然，人言端似楚公賢。", "爲官不取橫科勢，佐郡何妨二十年。", "徐邈介通常不變，陽城撫字已先傳。", "雙旌原上行人泣，况是交親淚迸泉。"]'),
('202925a6-5413-4ed6-9760-7bb829058cc1','挽高兵部','陳宓','宋','宋诗','song-poetry','','[]','蚤得師儒賞識深，明時碩輔盡知音。',64,'全唐诗/poet.song.186000.json','["蚤得師儒賞識深，明時碩輔盡知音。", "惠周南海交麾節，疏上中臺襆被扆。", "七袠正宜遊桂圃，五言何遽些梅林。", "鄰鄉父老同垂淚，兩縣甘棠蔽芾陰。"]'),
('7a5703ff-2dfc-482c-b2c3-2ce0976c93f0','挽外舅','陳宓','宋','宋诗','song-poetry','','[]','孝友生來閭里推，外家雙闕蚤知師。',64,'全唐诗/poet.song.186000.json','["孝友生來閭里推，外家雙闕蚤知師。", "歷官惠愛今龔遂，律己廉隅古伯夷。", "四郡聲稱如昨日，十年閑退未衰時。", "老成德望嗟難繼，笳鼓原頭淚滿頤。"]'),
('18a14179-6392-4d1f-ae13-134cf7e0923e','挽宋大卿','陳宓','宋','宋诗','song-poetry','','[]','蚤歲收科耀里閭，家傳祖訓是詩書。',64,'全唐诗/poet.song.186000.json','["蚤歲收科耀里閭，家傳祖訓是詩書。", "棠陰尚使民思惠，典計能令國有儲。", "九列簉班嗟已晚，十連奏最召方初。", "輀車想過桐鄉道，幾許鰥嫠淚灑裾。"]'),
('47d4be5f-3bdc-4e28-83e6-465013095c76','挽方僉判','陳宓','宋','宋诗','song-poetry','','[]','草堂種玉在長身，黌舍蜚聲四十春。',64,'全唐诗/poet.song.186000.json','["草堂種玉在長身，黌舍蜚聲四十春。", "佐府經綸堪活國，凌雲詞賦舊驚人。", "官聯僅與馮唐伍，壽考還臻絳老鄰。", "弱冠相知今白髮，西門祖送淚沾巾。"]'),
('25decfe6-b576-4c3a-a4d3-d98ffe3da73c','挽楊夫人','陳宓','宋','宋诗','song-poetry','','[]','笄年踰十便孀居，苦教孤兒共瘁劬。',64,'全唐诗/poet.song.186000.json','["笄年踰十便孀居，苦教孤兒共瘁劬。", "咸嘆鄒公如令子，不知冀缺是賢夫。", "貧能守志人難及，養不酬心世所吁。", "我詠國風長大息，共姜誰謂在今無。"]'),
('ff3119e3-b13e-4620-8246-b73da1bc8474','挽方瓊州恭人','陳宓','宋','宋诗','song-poetry','','[]','紹興宣諭一忠臣，爲慕名門遂作嬪。',64,'全唐诗/poet.song.186000.json','["紹興宣諭一忠臣，爲慕名門遂作嬪。", "慈訓由來承乃父，清規每解助良人。", "山中急辦瞻塋舍，囊裏曾無過□珍。", "丹旐翻飛人嘆息，諸孫祖送盡簪紳。"]'),
('ede26eba-009c-4fd3-aabf-16275f389bf5','挽鄭大監  其一','陳宓','宋','宋诗','song-poetry','','[]','策足膠庠上，收科弱冠中。',48,'全唐诗/poet.song.186000.json','["策足膠庠上，收科弱冠中。", "清文彌蓋壤，勁氣折王公。", "政術硎鋒穎，文章武事雄。", "輕財緣嗜義，已矣古人風。"]'),
('ff146be8-cf76-44ec-92de-c3e58cf903ed','挽鄭大監  其二','陳宓','宋','宋诗','song-poetry','','[]','鴞鷙天生異，鵬摶世擬遥。',48,'全唐诗/poet.song.186000.json','["鴞鷙天生異，鵬摶世擬遥。", "軺麾三錫命，省監兩登朝。", "報國丹心皦，浮生兩鬢凋。", "受恩知幾士，雨泣楚魂招。"]'),
('41ff02a1-df6b-45c1-bd9a-48c6a03a0ddd','挽張夫人','陳宓','宋','宋诗','song-poetry','','[]','籍甚金張世，歸歟王謝賢。',48,'全唐诗/poet.song.186000.json','["籍甚金張世，歸歟王謝賢。", "絲蘿能幾日，松柏早千年。", "誼重不再辱，身輕得自憐。", "平生不朽事，看付殺青傳。"]'),
('cad38438-a323-4a3a-a267-efd71d4cba07','挽吳縣尉孺人黄氏','陳宓','宋','宋诗','song-poetry','','[]','遠出無雙裔，來嬪第一家。',48,'全唐诗/poet.song.186000.json','["遠出無雙裔，來嬪第一家。", "兒時憂患集，婦道敬恭加。", "伉儷終身義，凄凉十歲華。", "夫賢仍子幼，閭里可勝嗟。"]'),
('96cb34fa-2ab8-4716-a82e-5f38ee7b70cd','挽許郎中','陳宓','宋','宋诗','song-poetry','','[]','前輩凋零盡，如何到月湖。',48,'全唐诗/poet.song.186000.json','["前輩凋零盡，如何到月湖。", "壯圖終未展，正論老尤孤。", "兩忝官聯舊，常蒙朋友呼。", "忽聞郎宿霣，衰淚倍沾鬢。"]'),
('26464230-fcac-46ee-9ec0-02af8ac53198','挽肯齋儲居士','陳宓','宋','宋诗','song-poetry','','[]','長樂與家鄰，安輿來往頻。',48,'全唐诗/poet.song.186000.json','["長樂與家鄰，安輿來往頻。", "詩方貽五字，訃祇隔三晨。", "事業傳賢嗣，鄉閭失善人。", "薰風丹荔熟，追感一沾巾。"]'),
('f61bf638-eef7-4099-8c45-41f62bdae24b','挽李縣丞','陳宓','宋','宋诗','song-poetry','','[]','文脈紹雲龕，儒酸味轉甘。',48,'全唐诗/poet.song.186000.json','["文脈紹雲龕，儒酸味轉甘。", "一官人謂晚，三邑政無慚。", "身健歸何早，孤賢道飽參。", "淵明生自祭，揮淚聽佳談。"]'),
('8c8ca995-0234-4c07-9033-1874f59311ee','挽吳太夫人  其一','陳宓','宋','宋诗','song-poetry','','[]','蚤出勳名裔，中年歷險巇。',48,'全唐诗/poet.song.186000.json','["蚤出勳名裔，中年歷險巇。", "事姑追孝婦，教子作儒師。", "獄爲平反喜，金緣賑貸施。", "魚軒歸去後，兩郡幾人悲。"]'),
('1754286c-375b-4332-bea9-f08eee6f203e','挽吳太夫人  其二','陳宓','宋','宋诗','song-poetry','','[]','昔在三山日，曾升孟母堂。',48,'全唐诗/poet.song.186000.json','["昔在三山日，曾升孟母堂。", "官寮同令子，箴訓出幽房。", "盛擬雙封國，俄驚一奠觴。", "新阡緣孝感，揮涕望高岡。"]'),
('59f06ffe-62b5-43fa-8c82-3524e8d4c630','挽陳外府丞','陳宓','宋','宋诗','song-poetry','','[]','孝友根天性，生平禮法循。',48,'全唐诗/poet.song.186000.json','["孝友根天性，生平禮法循。", "躬行皆古道，胸次鎮陽春。", "南國猶歌袴，中朝謾曳紳。", "最傷清苦節，海內幾何人。"]'),
('1eae1ceb-6d51-42de-adcd-652da14bb910','挽鄉守樓宗簿  其一','陳宓','宋','宋诗','song-poetry','','[]','漢代推循吏，周邦重魯儒。',48,'全唐诗/poet.song.186000.json','["漢代推循吏，周邦重魯儒。", "庭中無滯訟，身後有遺書。", "生爲忘家窘，形因治郡癯。", "天人同一理，好惡不應殊。"]'),
('21a145d5-51de-4c23-adf5-43f62c2230f6','挽鄉守樓宗簿  其二','陳宓','宋','宋诗','song-poetry','','[]','公來當赤立，節用以爲餘。',48,'全唐诗/poet.song.186000.json','["公來當赤立，節用以爲餘。", "垂橐無金帛，窮閻有袴襦。", "杜門蒙枉顧，易簀阻前趨。", "忍見歸雙旐，傷心豈獨莆。"]'),
('798d6ba8-953d-492b-a48f-12b180a5e0dc','挽楊尚書','陳宓','宋','宋诗','song-poetry','','[]','子雲新著述，伯起舊家聲。',48,'全唐诗/poet.song.186000.json','["子雲新著述，伯起舊家聲。", "孝友全天賦，文章與性成。", "平津期究業，疏傅已傳名。", "獨恨門闌士，無因泣絳旍。"]'),
('0b1dd6df-050c-4a4d-94eb-7dcb23ed4a2f','挽使相傅忠簡  其一','陳宓','宋','宋诗','song-poetry','','[]','中原文獻舊，四世煒相傳。',48,'全唐诗/poet.song.186000.json','["中原文獻舊，四世煒相傳。", "節操生來異，勳名晚更全。", "方哦衛武什，遽止太丘年。", "竟鬰經綸志，蒼黔敢扣天。"]'),
('a1e00dee-03f6-4bf1-afc1-1efdde2181d4','挽使相傅忠簡  其二','陳宓','宋','宋诗','song-poetry','','[]','先世論交舊，于今六十年。',48,'全唐诗/poet.song.186000.json','["先世論交舊，于今六十年。", "誤蒙摛薦牘，深嘆伏蒲篇。", "迅召辭何數，遺忠秘莫傳。", "空餘華髮像，雨泣拜貂蟬。"]'),
('deaf8050-519f-4c2f-99e0-8db0f942541b','挽龔知縣','陳宓','宋','宋诗','song-poetry','','[]','華族三台燁，名門八桂芳。',48,'全唐诗/poet.song.186000.json','["華族三台燁，名門八桂芳。", "才雖凌賈誼，官不至馮唐。", "晚歲逢奇蹇，平生只直方。", "青春陪笑語，一慟鬢成霜。"]'),
('49b23960-c4ed-4f8e-9b1f-2a57561f7e9a','挽黄總幹','陳宓','宋','宋诗','song-poetry','','[]','作邑古循吏，于今鮮與儔。',48,'全唐诗/poet.song.186000.json','["作邑古循吏，于今鮮與儔。", "有生持正直，不變是寬柔。", "食淡親常喜，官貧俸莫酬。", "嘗寮吾有愧，執綍淚交流。"]'),
('2e43f4c8-a02a-4da3-bd6a-e45240fe1fa4','東萊呂氏官箴以覓舉求上官保庇書爲第一戒今仕者往往十犯八九雖賢不免陷焉爲詩以謝兼用奉勉','陳宓','宋','宋诗','song-poetry','','[]','凡厥女子，號爲無知。',70,'全唐诗/poet.song.186000.json','["凡厥女子，號爲無知。", "十年不字，遲歸有時。", "正節必守，淑行懼虧。", "孰謂君子，身不自持。", "不艮其背，顧朵其頤。", "自鬻苟售，寧不忸怩。", "莫答盛意，聊贈鄙詞。"]'),
('f1a9eced-7ed7-48ae-8e3e-fa77620a9d08','贊梅溪王先生像','陳宓','宋','宋诗','song-poetry','','[]','先生之道，得天之全。',80,'全唐诗/poet.song.186000.json','["先生之道，得天之全。", "氣剛以和，如四時然。", "功在王室，惠留於泉。", "不怒而教，惡遏善遷。", "爲政以德，信哉格言。", "先生之逝，四十三年。", "有廟有祠，民奉益虔。", "紫帽可礪，清名不騫。"]'),
('4573731c-b981-4b15-ae1b-adc033faa099','贊文公朱先生像','陳宓','宋','宋诗','song-poetry','','[]','貌溫而嚴，德剛而粹。',60,'全唐诗/poet.song.186000.json','["貌溫而嚴，德剛而粹。", "春融秋肅，淵澄岳峙。", "道光二程，識高百氏。", "生遇明時，進難退易。", "天假之間，斯文大備。", "偉哉夫子，教垂萬禩。"]'),
('0e3b5be4-6e56-4045-961e-d23796784304','贊勉齋黄先生像','陳宓','宋','宋诗','song-poetry','','[]','貌之癯有顔之樂，氣之剛得軻之養。',36,'全唐诗/poet.song.186000.json','["貌之癯有顔之樂，氣之剛得軻之養。", "以身任道，老而益壯。", "仰止朱門，孰出其上。"]'),
('1dc946d8-5ac9-4931-9df7-8ac01d6d4f5b','城山松隠巖','陳宓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','穀城巖穴似飛來，十里湖光鏡面開。',64,'全唐诗/poet.song.186000.json','["穀城巖穴似飛來，十里湖光鏡面開。", "夜雨松窗僧榻靜，秋風柳岸釣船回。", "尋幽便扣生雲洞，乘興還登呼月臺。", "每對西湖吟咏處，令人偏憶故山梅。"]'),
('f9944767-bfa5-4ad9-8b4a-0e1ff8c9c9d4','詩一首','陳宓','宋','宋诗','song-poetry','','[]','藍水秋來八九月，芒花山瘴一齊發。',32,'全唐诗/poet.song.186000.json','["藍水秋來八九月，芒花山瘴一齊發。", "時人信巫紙多燒，病不求醫命自活。"]'),
('95ea7da7-07b5-431c-af1e-04994f6280bb','句','陳宓','宋','宋诗','song-poetry','','[]','君自成龍我成道。',8,'全唐诗/poet.song.186000.json','["君自成龍我成道。"]'),
('06340a20-c4b0-4a0a-832f-042af0e10bff','春日即事','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','人間閑日月，春後乍晴陰。',48,'全唐诗/poet.song.186000.json','["人間閑日月，春後乍晴陰。", "半夜雨聲急，一谿流水深。", "鳥啼花自發，詩就客能吟。", "短策西湖路，幽芳信意尋。"]'),
('eda54948-2af0-4440-b772-a7c67121008f','送別','高翥','宋','宋诗','song-poetry','','[]','老去情懷怕別離，年來不作送行詩。',32,'全唐诗/poet.song.186000.json','["老去情懷怕別離，年來不作送行詩。", "人前舉似終難信，問着垂楊便可知。"]'),
('4436c777-89de-46c5-a7b3-90805daa79b4','春日北山二首  其一','高翥','宋','宋诗','song-poetry','','[]','人緣白石溯清谿，手剝蒼苔認舊題。',32,'全唐诗/poet.song.186000.json','["人緣白石溯清谿，手剝蒼苔認舊題。", "春色滿山歸不去，拆桐花裏畫眉啼。"]'),
('79008e27-adde-4df9-aa3d-c5f7385a2525','春日北山二首  其二','高翥','宋','宋诗','song-poetry','','[]','插花吹笛兩山中，桃李尊前日日同。',32,'全唐诗/poet.song.186000.json','["插花吹笛兩山中，桃李尊前日日同。", "待得馬頭飛絮滿，更來沽酒看殘紅。"]'),
('fdc66eca-f930-44ee-9741-0c75680ae51b','僧房夜坐','高翥','宋','宋诗','song-poetry','','[]','萬枝松裏一篝鐙，知是山房第幾層。',32,'全唐诗/poet.song.186000.json','["萬枝松裏一篝鐙，知是山房第幾層。", "靜夜數聲清磬響，上方應有誦經僧。"]'),
('6625fcdb-c4ee-406a-9661-b3dd5c56adee','訪諸葛鍊師不遇','高翥','宋','宋诗','song-poetry','','[]','青銅留着布囊中，去謁人間小卧龍。',32,'全唐诗/poet.song.186000.json','["青銅留着布囊中，去謁人間小卧龍。", "久欲共君謀一醉，有錢却又不相逢。"]'),
('d89dfe65-79a8-4b92-916b-ff8a7c1ca1f3','雜興二首  其一','高翥','宋','宋诗','song-poetry','','[]','新分菊本自鉏山，手縛枯藤作矮闌。',32,'全唐诗/poet.song.186000.json','["新分菊本自鉏山，手縛枯藤作矮闌。", "比似著書空用力，種花猶得一年看。"]'),
('d8d25618-0133-461e-b2b2-f6a28fc7bf97','雜興二首  其二','高翥','宋','宋诗','song-poetry','','[]','二十年前欲住山，不禁寂寞掩柴關。',32,'全唐诗/poet.song.186000.json','["二十年前欲住山，不禁寂寞掩柴關。", "如今寂寞禁當得，欲掩柴關又却難。"]'),
('107bacd5-f46c-4880-8310-1bb68d08d006','秋日田父辭二首  其一','高翥','宋','宋诗','song-poetry','','[]','啄黍黄雞沒骨肥，繞籬綠橘綴枝垂。',32,'全唐诗/poet.song.186000.json','["啄黍黄雞沒骨肥，繞籬綠橘綴枝垂。", "新釀酒，旋裁衣，正是昏男嫁女時。"]'),
('a50f48b6-e597-47fe-b440-e2ab85b7a8fa','秋日田父辭二首  其二','高翥','宋','宋诗','song-poetry','','[]','少婦挼藍旋染裙，大兒敲葛自漿巾。',32,'全唐诗/poet.song.186000.json','["少婦挼藍旋染裙，大兒敲葛自漿巾。", "新摘摘，笑欣欣，相喚相呼看賽神。"]'),
('006ae046-eed2-47c7-9ac9-d3b85dd4c548','孤山雪後','高翥','宋','宋诗','song-poetry','','[]','雪後騎馿行步遲，孤山何似灞橋時。',32,'全唐诗/poet.song.186000.json','["雪後騎馿行步遲，孤山何似灞橋時。", "近來行輩無和靖，見說梅花不要詩。"]'),
('f3ea680e-f385-41bb-b8bd-19099461f797','天台曹園','高翥','宋','宋诗','song-poetry','','[]','蔡嶺桑麻地，曹家桃李莊。',48,'全唐诗/poet.song.186000.json','["蔡嶺桑麻地，曹家桃李莊。", "谿流春水滑，梅度晚風香。", "竹屋解留客，筍輿休俶裝。", "平生看花法，不學蜜蜂忙。"]'),
('0087d626-201b-44e6-a188-ff8e1ca6d263','西湖春雪','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','小艇沿湖看雪飛，正當騎馬蹋春時。',32,'全唐诗/poet.song.186000.json','["小艇沿湖看雪飛，正當騎馬蹋春時。", "是誰乞與楊花舞，先占東風一月期。"]'),
('44494f41-a6b5-4d1c-934b-37d9beb89832','閑居雜興三首  其一','高翥','宋','宋诗','song-poetry','','[]','開門遣蠻童，買花供銅佛。',48,'全唐诗/poet.song.186000.json','["開門遣蠻童，買花供銅佛。", "春風隨花來，爲我一披拂。", "風和花氣清，下簾休放出。", "回施佛因果，供此老詩骨。"]'),
('9cd616f2-cc84-4df6-bae4-ed1e35d05abc','閑居雜興三首  其二','高翥','宋','宋诗','song-poetry','','[]','點鐙酌春酒，襞紙題小詩。',48,'全唐诗/poet.song.186000.json','["點鐙酌春酒，襞紙題小詩。", "讀盡列仙傳，引調學語兒。", "自飲復自笑，不覺春漏遲。", "且了今日事，明日還任之。"]'),
('b6d2f50e-49bd-44be-a711-9bccbbe3138e','閑居雜興三首  其三','高翥','宋','宋诗','song-poetry','','[]','杜鵑休忉忉，布穀休聒聒。',48,'全唐诗/poet.song.186000.json','["杜鵑休忉忉，布穀休聒聒。", "無田不須耕，無家自能活。", "行藏莫非時，造化安可奪。", "更放心地寬，出門行路闊。"]'),
('6da50ee2-78c4-4188-b3f6-18cb62c43ee1','春日湖上','高翥','宋','宋诗','song-poetry','','[]','乘興行新路，凝情獨老翁。',48,'全唐诗/poet.song.186000.json','["乘興行新路，凝情獨老翁。", "馬蹄春草上，人影夕陽中。", "飛絮沿湖白，殘花染浪紅。", "晚歸雲氣合，雙槳破空濛。"]'),
('c2713b1b-e6ae-41bd-8e3c-a5a947c7c6db','春懷','高翥','宋','宋诗','song-poetry','','[]','江南春盡尚春寒，添盡征衣獨掩關。',32,'全唐诗/poet.song.186000.json','["江南春盡尚春寒，添盡征衣獨掩關。", "日暮酒醒聞謝豹，所歡多在水雲間。"]'),
('9987fab3-6f0a-45c5-9415-871e16a4d7e1','過臨平','高翥','宋','宋诗','song-poetry','','[]','征帆一似白鷗輕，起揭船篷看曉晴。',32,'全唐诗/poet.song.186000.json','["征帆一似白鷗輕，起揭船篷看曉晴。", "梅子着花霜壓岸，自披風帽過臨平。"]'),
('5a222c86-a533-4de8-832d-9a0ffdb07c76','古廟','高翥','宋','宋诗','song-poetry','','[]','古廟依喬木，開門對淺沙。',48,'全唐诗/poet.song.186000.json','["古廟依喬木，開門對淺沙。", "短籬紅槿樹，深徑碧苔花。", "屋破香煙濕，庭空日脚斜。", "山寒無賽鼓，鳴噪集神鴉。"]'),
('3d92d5b4-32e9-4380-930b-f3e7b2909a45','古寺','高翥','宋','宋诗','song-poetry','','[]','山路荒涼出小亭，土牆斑駁带枯藤。',64,'全唐诗/poet.song.186000.json','["山路荒涼出小亭，土牆斑駁带枯藤。", "欹斜古殿三尊佛，黯澹寒篝一點鐙。", "碣石半磨天寶字，禪房空老政和僧。", "頭陀禮拜迎人說，門外浮屠欠兩層。"]'),
('dbec2432-4ee8-4c71-b036-34e8eed562c9','卜居','高翥','宋','宋诗','song-poetry','','[]','結屋離黄道，開門對白沙。',48,'全唐诗/poet.song.186000.json','["結屋離黄道，開門對白沙。", "一莊千古月，三徑四時花。", "客至旋沽酒，身閑自煮茶。", "相聞蟲鳥外，不復聽喧譁。"]'),
('d331212f-d01c-4736-8fbc-66cab6cfb28b','秋日三首  其一','高翥','宋','宋诗','song-poetry','','[]','旋買扁舟載一翁，片帆吹下夕陽東。',32,'全唐诗/poet.song.186000.json','["旋買扁舟載一翁，片帆吹下夕陽東。", "西風欲織江頭錦，催染秋林葉葉紅。"]'),
('cf18c3e2-2818-49ea-b524-def6280af8e0','秋日三首  其二','高翥','宋','宋诗','song-poetry','','[]','庭草銜秋自短長，悲蛩傳響答寒螿。',32,'全唐诗/poet.song.186000.json','["庭草銜秋自短長，悲蛩傳響答寒螿。", "豆花似解通鄰好，引蔓殷勤遠過牆。"]'),
('bdcb9c92-d4a5-4982-bb7f-b62c21064245','秋日三首  其三','高翥','宋','宋诗','song-poetry','','[]','獨客飄然物外遊，江南江北總宜秋。',32,'全唐诗/poet.song.186000.json','["獨客飄然物外遊，江南江北總宜秋。", "芭蕉昨夜緣何事，和雨和風作許愁。"]'),
('76e6e7db-662f-4f2b-be18-ce57777768dc','松谿廟','高翥','宋','宋诗','song-poetry','','[]','廟自何年立，門深晝不扃。',48,'全唐诗/poet.song.186000.json','["廟自何年立，門深晝不扃。", "寒藤扶壞壁，秋草带疏櫺。", "谿接東西碧，山分遠近青。", "老巫逢客至，謾說有神靈。"]'),
('9b969cec-fc07-4438-a77f-e778d61d3cc2','蓮實','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','膩玉肌膚碧玉房，纍纍波面趁紅芳。',64,'全唐诗/poet.song.186000.json','["膩玉肌膚碧玉房，纍纍波面趁紅芳。", "坐忘佛土三生夢，來結人間一夏涼。", "青子綻時仙掌濕，綠包分處蜜脾香。", "尊前笑摘酬風露，猶記西湖古柳傍。"]'),
('e911669d-c1e9-41c5-8164-92b4a73e979d','無題二首  其一','高翥','宋','宋诗','song-poetry','','[]','獨展羅衾無夢成，寶香熏徹轉愁生。',32,'全唐诗/poet.song.186000.json','["獨展羅衾無夢成，寶香熏徹轉愁生。", "癡心不願郎思妾，只願郎今厭客情。"]'),
('87e773bd-3d4c-447c-abf3-ec90c0d4a976','無題二首  其二','高翥','宋','宋诗','song-poetry','','[]','風竹蕭蕭淡月明，孤眠真箇可憐生。',32,'全唐诗/poet.song.186000.json','["風竹蕭蕭淡月明，孤眠真箇可憐生。", "不知昨夜相思夢，去到伊行是幾更。"]'),
('031231f5-2867-4d11-9d33-e1ea772c50ac','秋興','高翥','宋','宋诗','song-poetry','','[]','數聲新鴈夜初長，曉起開門衣袂涼。',32,'全唐诗/poet.song.186000.json','["數聲新鴈夜初長，曉起開門衣袂涼。", "籬菊褪黄秋興嬾，瓦溝財試一痕霜。"]'),
('37e9fc8f-9dab-4f39-9caa-f4b18e211575','秋晚即事','高翥','宋','宋诗','song-poetry','','[]','江頭風葉舞低回，催得濃雲頃刻開。',32,'全唐诗/poet.song.186000.json','["江頭風葉舞低回，催得濃雲頃刻開。", "萬里碧天紅日晚，數聲新鴈送寒來。"]'),
('1a0655b2-8d32-4323-8a04-9121efc76580','毋自欺齋夜宴','高翥','宋','宋诗','song-poetry','','[]','毋自欺齋清更嚴，齋中人物斗之南。',64,'全唐诗/poet.song.186000.json','["毋自欺齋清更嚴，齋中人物斗之南。", "七朝宰相得瞻仰，四海詩人交笑談。", "古調喜聽琴再弄，深杯休惜酒重添。", "玉堂今夜無宣喚，且與江湖作小參。"]'),
('a239097a-e0f6-45a4-95d5-dfd0e63230a7','曉出黄山寺','高翥','宋','宋诗','song-poetry','','[]','曉上籃輿出寶坊，野塘山路盡春光。',64,'全唐诗/poet.song.186000.json','["曉上籃輿出寶坊，野塘山路盡春光。", "試穿松影登平陸，已覺鍾聲在上方。", "草色谿流高下碧，菜花楊柳淺深黄。", "杖藜切莫匆匆去，有伴行春不要忙。"]'),
('c7334b5c-54ec-49be-bc0b-734d3fac0fbe','育王寺','高翥','宋','宋诗','song-poetry','','[]','曉策烏藤上育王，入山隨處得徜徉。',64,'全唐诗/poet.song.186000.json','["曉策烏藤上育王，入山隨處得徜徉。", "碑頭龍護先皇字，塔下魚懸外國香。", "徧謁禪房嘗苦茗，閑聽社媼說豪光。", "山深日短行難盡，僧遣頭陀辦客牀。"]'),
('baebb81b-1daa-4ed3-ab0c-dcbf5975c2cb','春日湖上','高翥','宋','宋诗','song-poetry','','[]','清波門外放船時，盡日輕寒戀客衣。',64,'全唐诗/poet.song.186000.json','["清波門外放船時，盡日輕寒戀客衣。", "花下笑聲人共語，柳邊檣影燕初飛。", "曉風不定棠梨瘦，夜雨相連薺麥肥。", "最憶故山春更好，夜來先遣夢魂歸。"]'),
('e6383702-2f1b-445a-8bbf-3877cd16d5a7','黄居士山房','高翥','宋','宋诗','song-poetry','','[]','浮利浮名心已灰，三間茅屋白雲堆。',64,'全唐诗/poet.song.186000.json','["浮利浮名心已灰，三間茅屋白雲堆。", "先生自釀松精酒，侍女能持藤癭杯。", "養鹿曉隨原草去，放猿時摘野花來。", "近聞身口渾無累，槲葉黄菁繞宅栽。"]'),
('221d6451-fdc2-4b88-810b-a877890df48c','育王寺','高翥','宋','宋诗','song-poetry','','[]','精藍遊歷地，景物自情親。',48,'全唐诗/poet.song.186000.json','["精藍遊歷地，景物自情親。", "鶴引登山客，僧迎禮塔人。", "名花千佛供，喬木萬夫身。", "碑刻東坡作，重來爲拂塵。"]'),
('f9841c2a-e4dd-459f-b76e-edbfe4edfbb1','送春','高翥','宋','宋诗','song-poetry','','[]','韶光催去太無情，祇爲東君去住輕。',64,'全唐诗/poet.song.186000.json','["韶光催去太無情，祇爲東君去住輕。", "雖欲遲留芳草夢，如何禁得杜鵑聲。", "桐花快落春風老，梅子微酸晚雨晴。", "從此嬉遊時節少，不須日日報詩成。"]'),
('de62485b-8580-4fb6-92b6-8c4aed46bcc7','秋山散步','高翥','宋','宋诗','song-poetry','','[]','乍晴沙路軟於塵，新着芒鞋更可人。',32,'全唐诗/poet.song.186000.json','["乍晴沙路軟於塵，新着芒鞋更可人。", "誰道秋山不宜客，桂花多處勝行春。"]'),
('438663fb-f172-4763-8697-1fc958a95d84','即事','高翥','宋','宋诗','song-poetry','','[]','秋來高處不宜登，閑却西樓最上層。',32,'全唐诗/poet.song.186000.json','["秋來高處不宜登，閑却西樓最上層。", "讀罷黄庭窗戶晚，自敲清磬上香鐙。"]'),
('a36d09b7-6606-45a9-8c80-676f9cc4ad26','烏鎮普靜寺寺沈休文故居也','高翥','宋','宋诗','song-poetry','','[]','寂寞梁朝寺，深廊十數閒。',48,'全唐诗/poet.song.186000.json','["寂寞梁朝寺，深廊十數閒。", "碑存知殿古，香冷覺僧殘。", "斷岸舟橫浦，平坡樹補山。", "休文如好在，依舊带圍寬。"]'),
('9b0fb346-7aa1-4047-aef1-ab34079cf340','渡錢塘','高翥','宋','宋诗','song-poetry','','[]','小立晴江上，潮生落照邊。',48,'全唐诗/poet.song.186000.json','["小立晴江上，潮生落照邊。", "晚花低映水，春草暗迷煙。", "燕子飛官驛，鷗羣引客船。", "關情南浦別，相對獨依然。"]'),
('997fe1c3-2dc8-45f3-b8a0-9d166294c693','七夕','高翥','宋','宋诗','song-poetry','','[]','一枕新涼供醉眠，覺來風物已淒然。',64,'全唐诗/poet.song.186000.json','["一枕新涼供醉眠，覺來風物已淒然。", "山雲带雨重重合，宮樹鳴秋葉葉顛。", "滿進一杯酬好節，休看兩鬢換流年。", "雙星回施癡兒等，容我長齋繡佛前。"]'),
('2baafd07-3cf0-4610-b2df-537765b3c694','荆棘中見梅花','高翥','宋','宋诗','song-poetry','','[]','荆棘叢中數點春，春雲態度月精神。',32,'全唐诗/poet.song.186000.json','["荆棘叢中數點春，春雲態度月精神。", "依然竹屋茅簷下，靚女盈盈不嫁人。"]'),
('f806fa1b-1e29-4a96-ba52-b77136ecb414','感春','高翥','宋','宋诗','song-poetry','','[]','人事日紛紛，不知春已分。',48,'全唐诗/poet.song.186000.json','["人事日紛紛，不知春已分。", "問梅成綠葉，看杏落紅雲。", "燕向晴空語，蛙從夜靜聞。", "感時傷老大，孤坐對鑪熏。"]'),
('bc1c44fb-ab2e-40f8-8ee7-9768f09ff0b9','送劉允叔主簿歸山中','高翥','宋','宋诗','song-poetry','','[]','浮利浮名輓不來，故山歸去恰春回。',64,'全唐诗/poet.song.186000.json','["浮利浮名輓不來，故山歸去恰春回。", "馬蘭旋摘和菘煮，枸杞新生傍菊栽。", "庭樹夜留山鳥宿，洞門早爲野雲開。", "明年我亦天台寺，相伴芒鞋蹋古苔。"]'),
('b222e595-2d6b-4af3-8890-d58411bc96f1','江居曉詠','高翥','宋','宋诗','song-poetry','','[]','家住清江江上村，江雲山影自平分。',32,'全唐诗/poet.song.186000.json','["家住清江江上村，江雲山影自平分。", "幾回早起開門看，不見青山見白雲。"]'),
('678bbb3f-eacf-49cf-9380-cc0e5210b6ca','題二小姬扇二首  其一','高翥','宋','宋诗','song-poetry','','[]','慶娘顰翠眉，春瘦怯羅衣。',24,'全唐诗/poet.song.186000.json','["慶娘顰翠眉，春瘦怯羅衣。", "笑問采花蝶，如何成對飛。"]'),
('6edd9529-5624-41d4-be96-0a345d79fbbc','題二小姬扇二首  其二','高翥','宋','宋诗','song-poetry','','[]','湘湘未識羞，獨坐抱箜篌。',24,'全唐诗/poet.song.186000.json','["湘湘未識羞，獨坐抱箜篌。", "貪學耆婆舞，擡身拜部頭。"]'),
('d1e4e8a6-1749-4c48-8cf4-365a6a87d99c','小樓雨中','高翥','宋','宋诗','song-poetry','','[]','雲浮江雨暗，獨客苦淹留。',48,'全唐诗/poet.song.186000.json','["雲浮江雨暗，獨客苦淹留。", "白髮羞明鏡，青山對小樓。", "酒功書下下，心事付悠悠。", "安得并州翦，從頭翦斷愁。"]'),
('dc9b71b5-5669-4cb7-97ec-febb38a44046','首夏','高翥','宋','宋诗','song-poetry','','[]','漾漾池塘碧染衣，陰陰草樹綠成圍。',32,'全唐诗/poet.song.186000.json','["漾漾池塘碧染衣，陰陰草樹綠成圍。", "江村寂寞春歸後，一點楊花不見飛。"]'),
('39705ddc-58d4-4c79-a37a-a6b7b94a8f29','寄方巖','高翥','宋','宋诗','song-poetry','','[]','綠髮仙人山澤癯，出遊入息幾曾拘。',64,'全唐诗/poet.song.186000.json','["綠髮仙人山澤癯，出遊入息幾曾拘。", "種花甚少四時有，諫草不多千古無。", "閲世眼高磨日月，好賢名重滿江湖。", "行藏到得無心處，鐘鼎山林豈異塗。"]'),
('2f89422d-b11d-4eec-a949-1622769094f2','自賦','高翥','宋','宋诗','song-poetry','','[]','蝸角蠅頭總是虛，何須留戀市朝居。',64,'全唐诗/poet.song.186000.json','["蝸角蠅頭總是虛，何須留戀市朝居。", "老於親戚情當密，貧與公卿分合疏。", "小澗草荒元種菊，故山塵滿舊抄書。", "幾時歸去重料理，嘯月眠雲得自如。"]'),
('eac2cb14-3c5c-47c9-be4e-33a415118632','蕺山登高','高翥','宋','宋诗','song-poetry','','[]','醉眼橫斜看菊枝，又成客裏過佳期。',64,'全唐诗/poet.song.186000.json','["醉眼橫斜看菊枝，又成客裏過佳期。", "去年行路猶持酒，今日登高嬾賦詩。", "老淚怕從衣袖見，閑情但有帽簷知。", "阿髯故國才歸得，歲歲須來舉一巵。"]'),
('0e25cf83-e8e8-414c-8310-62e723b39a0b','戍婦吟二首  其一','高翥','宋','宋诗','song-poetry','','[]','將身托戰爭，世事百無情。',24,'全唐诗/poet.song.186000.json','["將身托戰爭，世事百無情。", "相對生離別，渾如落葉輕。"]'),
('77810b05-6acb-4d60-8741-4dac56fd2830','戍婦吟二首  其二','高翥','宋','宋诗','song-poetry','','[]','辭家出戍邊，北望隔青煙。',24,'全唐诗/poet.song.186000.json','["辭家出戍邊，北望隔青煙。", "怕作沙場夢，秋宵不敢眠。"]'),
('d6cbf55b-c067-45df-a506-580892f76117','重遊無量院','高翥','宋','宋诗','song-poetry','','[]','佛屋欹斜老翠微，小軒猶記昔遊時。',64,'全唐诗/poet.song.186000.json','["佛屋欹斜老翠微，小軒猶記昔遊時。", "江雲带雨凉生竹，野水迎潮暗入籬。", "門外風波僧自識，山中朝莫客曾知。", "眼明素壁關情久，十載財能寫此詩。"]'),
('73d7de43-779a-4b16-81e3-695991aff6db','春霽','高翥','宋','宋诗','song-poetry','','[]','積雨才收雲盡歸，長空一色碧琉璃。',64,'全唐诗/poet.song.186000.json','["積雨才收雲盡歸，長空一色碧琉璃。", "日移簾影臨書案，風颭缾花落研池。", "巢燕學飛猶戀母，籠鷄得食旋呼兒。", "眼看景物關情甚，喜爲新晴賦此詩。"]'),
('21383b42-3a07-476a-9d53-54ab3aa264e7','歲除登岝崿山精舍','高翥','宋','宋诗','song-poetry','','[]','蕭寺經行無盡情，倚闌長是眼增明。',64,'全唐诗/poet.song.186000.json','["蕭寺經行無盡情，倚闌長是眼增明。", "谿因宿雨十分急，山爲凝寒一味清。", "竹外飛花隨晚吹，樹頭幽鳥試春聲。", "重來又是明年事，臨出門猶款款行。"]'),
('989c26c8-f4b3-4e32-b97c-f7e98f3a567c','張氏曲江','高翥','宋','宋诗','song-poetry','','[]','一曲澄江兩派分，滿山脩竹綠齊雲。',64,'全唐诗/poet.song.186000.json','["一曲澄江兩派分，滿山脩竹綠齊雲。", "矮窗風月侵帆腹，小徑煙霞隠屐痕。", "白鷺夜依花影宿，清猨時共艣聲聞。", "主人與客心如水，同倚闌干得細論。"]'),
('a4471053-cceb-40e1-b4d8-8382b69acca2','登九華樓','高翥','宋','宋诗','song-poetry','','[]','高閣臨江可契心，興來時得一登臨。',64,'全唐诗/poet.song.186000.json','["高閣臨江可契心，興來時得一登臨。", "山雲浦樹重重合，野水汀蒲日日深。", "鴉背夕陽供晚哺，蟬迎涼吹試秋吟。", "倚闌盡見諸峰出，如對風流李翰林。"]'),
('09617c88-1050-4e61-a0ae-8bf81f16c409','趙仲莊都鈐山居','高翥','宋','宋诗','song-poetry','','[]','一官難換北山薇，結屋栽花度四時。',64,'全唐诗/poet.song.186000.json','["一官難換北山薇，結屋栽花度四時。", "果熟不妨禽摘盡，酒香惟恐客來遲。", "小蘋低唱花間曲，阿廣高吟李下詩。", "客久辦心分半隠，尚嫌風骨欠仙姿。"]'),
('49965c05-18e5-4259-b2fa-6223010c1278','船戶','高翥','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','盡將家具載輕舟，來往長江春復秋。',64,'全唐诗/poet.song.186000.json','["盡將家具載輕舟，來往長江春復秋。", "三世兒孫居柁尾，四方知識會沙頭。", "老翁曉起占風信，少婦晨粧照水流。", "自笑此生漂泊甚，愛渠生理付浮悠。"]'),
('fb9a26fc-819b-48ef-aab7-ce94da89d927','歸寓舍','高翥','宋','宋诗','song-poetry','','[]','門前流水碧粼粼，歲晚歸來亦可人。',64,'全唐诗/poet.song.186000.json','["門前流水碧粼粼，歲晚歸來亦可人。", "梅欲開時多是雨，草財生處便成春。", "嬌兒對面兩癡絕，老子關情一欠伸。", "快洗竹篘篘濁酒，舉杯先爲洗京塵。"]'),
('c2a7f88e-1915-4ad0-b587-12d11172f18e','憶西湖','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖春二月，結客少年遊。',48,'全唐诗/poet.song.186000.json','["西湖春二月，結客少年遊。", "駿馬黄金勒，長身紫綺裘。", "愛花論擔買，嗜酒滿船浮。", "兩載緣何事，台州又越州。"]'),
('8bc7c456-6258-414c-a24b-efee8999e195','小樓雨中','高翥','宋','宋诗','song-poetry','','[]','長安市上僦樓居，閑裏身心儘自如。',64,'全唐诗/poet.song.186000.json','["長安市上僦樓居，閑裏身心儘自如。", "十日雨聲春對酒，一窗鐙影夜觀書。", "茶經未展愁先醒，藥錄才看病已除。", "所欠短簷晴景好，拆桐花月共扶疏。"]'),
('04db8922-1c6e-4918-9964-fda108d3de14','喜鄉友來','高翥','宋','宋诗','song-poetry','','[]','蕭蕭春夜雨，有客渡江來。',48,'全唐诗/poet.song.186000.json','["蕭蕭春夜雨，有客渡江來。", "世事攢眉說，鄉談信口開。", "晚肴供苦筍，時果薦青梅。", "甚欲澆離恨，呼鐙撥酒醅。"]'),
('3d031cd4-9517-4a48-8c6f-fcd797f25879','春寒','高翥','宋','宋诗','song-poetry','','[]','料峭東風破客衣，春寒不比臘前時。',32,'全唐诗/poet.song.186000.json','["料峭東風破客衣，春寒不比臘前時。", "絕憐牆角櫻桃樹，全似梅花雪後枝。"]'),
('10b1b9ba-9e9c-43c2-aaae-2e35b7409233','昌國縣普濟寺小亭','高翥','宋','宋诗','song-poetry','','[]','鯨海中流地，龍峰小洞天。',48,'全唐诗/poet.song.186000.json','["鯨海中流地，龍峰小洞天。", "亭高先得月，樹老久忘年。", "大士居鄰境，閑僧指便船。", "若爲風浪息，更結補陀緣。"]'),
('31e2b0fa-eefd-4138-8cc2-5da5382b1608','春情四首  其一','高翥','宋','宋诗','song-poetry','','[]','樓頭上馬苦匆匆，百計相留無計從。',32,'全唐诗/poet.song.186000.json','["樓頭上馬苦匆匆，百計相留無計從。", "正好看花郎却去，江邊春色爲誰濃。"]'),
('8eb02ae5-b546-47d1-9ef3-f1b85b72b2b1','春情四首  其二','高翥','宋','宋诗','song-poetry','','[]','天涯海角水雲寬，人在吳頭楚尾間。',32,'全唐诗/poet.song.186000.json','["天涯海角水雲寬，人在吳頭楚尾間。", "彈徹箜篌難寄恨，海棠庭院獨凭闌。"]'),
('cf85c81e-75e8-4f22-9276-8793df688ac6','春情四首  其三','高翥','宋','宋诗','song-poetry','','[]','深院沈沈照落暉，寶香熏徹舊時衣。',32,'全唐诗/poet.song.186000.json','["深院沈沈照落暉，寶香熏徹舊時衣。", "一春行樂誰爲伴，羞見花前蛺蝶飛。"]'),
('90c4680b-e057-4a1a-b381-2b940a07e5bf','春情四首  其四','高翥','宋','宋诗','song-poetry','','[]','鬭草歸來上玉階，香塵微涴合歡鞋。',32,'全唐诗/poet.song.186000.json','["鬭草歸來上玉階，香塵微涴合歡鞋。", "全籌贏得無人賞，依舊春愁自滿懷。"]'),
('da9ac88d-1b62-4f74-83f2-c6e4f5bb0b09','晚春即事','高翥','宋','宋诗','song-poetry','','[]','輕煙終日鎖樓臺，細雨絲絲半濕苔。',32,'全唐诗/poet.song.186000.json','["輕煙終日鎖樓臺，細雨絲絲半濕苔。", "杜宇一聲青嶂外，谿流時送落花來。"]'),
('35edbc50-597b-4b6b-a54a-7e61f954b594','蕺山戒珠寺寺王右軍故居也','高翥','宋','宋诗','song-poetry','','[]','葉葉東風吹客衣，昌安寺裏晚遊時。',64,'全唐诗/poet.song.186000.json','["葉葉東風吹客衣，昌安寺裏晚遊時。", "欹斜竹屋羲之宅，磨滅經幢率府碑。", "佛化是誰留實相，鵝亡猶自見方池。", "逢僧小作煎茶供，略問源流笑不知。"]'),
('63804d6b-5cde-4382-ac76-763fdfd135ef','冬日即事','高翥','宋','宋诗','song-poetry','','[]','江上凝冰約水痕，門前殘雪綴谿雲。',32,'全唐诗/poet.song.186000.json','["江上凝冰約水痕，門前殘雪綴谿雲。", "杖藜獨立梅梢月，成就清寒到十分。"]'),
('57765011-6d7d-4a3d-8327-3d34bd4417b8','訪銛朴翁不遇二首  其一','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','亂花飛絮趁長髯，來訪西湖竹裏庵。',32,'全唐诗/poet.song.186000.json','["亂花飛絮趁長髯，來訪西湖竹裏庵。", "行盡白雲三十里，詩人又在白雲南。"]'),
('658f9ec8-3837-4327-9704-50467c2b2b13','訪銛朴翁不遇二首  其二','高翥','宋','宋诗','song-poetry','','[]','乘興尋僧入翠微，山中無限野薔薇。',32,'全唐诗/poet.song.186000.json','["乘興尋僧入翠微，山中無限野薔薇。", "主人不見從誰賞，折得繁枝自插歸。"]'),
('e6c97c8a-c4fe-4efb-bd2c-ac3cf7666c1b','聚景園口號二首  其一','高翥','宋','宋诗','song-poetry','','[]','淺碧池塘連路口，淡黄楊柳護簷牙。',32,'全唐诗/poet.song.186000.json','["淺碧池塘連路口，淡黄楊柳護簷牙。", "舊時歲歲春風裏，長見君王出看花。"]'),
('282a72cc-0c09-4241-9d03-3a77b2fdce8b','聚景園口號二首  其二','高翥','宋','宋诗','song-poetry','','[]','竹影參差臨斷岸，花陰歷寂浸清流。',32,'全唐诗/poet.song.186000.json','["竹影參差臨斷岸，花陰歷寂浸清流。", "遊人難到闌干角，盡日垂楊蓋御舟。"]'),
('8e2e1ea5-e53f-4da6-8280-25d6999f5f56','恭跋思陵宸翰拓本卷後','高翥','宋','宋诗','song-poetry','','[]','淡黄越紙打殘碑，盡是先皇御賜詩。',32,'全唐诗/poet.song.186000.json','["淡黄越紙打殘碑，盡是先皇御賜詩。", "白髮內人和淚讀，爲曾親見寫詩時。"]'),
('902da4a3-9d5d-40cd-8aed-f9743f6c1fa8','山行即事二首  其一','高翥','宋','宋诗','song-poetry','','[]','落盡桐花春已休，過牆新竹籜初抽。',32,'全唐诗/poet.song.186000.json','["落盡桐花春已休，過牆新竹籜初抽。", "山行步步黄泥滑，小立谿橋聽雨鳩。"]'),
('ce1b2be4-4f41-4345-8fb7-c0f2dc15a393','山行即事二首  其二','高翥','宋','宋诗','song-poetry','','[]','捲地東風晚更狂，櫻桃吹子落泥牆。',32,'全唐诗/poet.song.186000.json','["捲地東風晚更狂，櫻桃吹子落泥牆。", "谿雲自爲催詩黑，忙殺條桑窈窕娘。"]'),
('a2373bb1-59e5-47a2-88ea-54a566199e5e','寄林徵君','高翥','宋','宋诗','song-poetry','','[]','老無閑事上雙眉，問着窮通盡不知。',64,'全唐诗/poet.song.186000.json','["老無閑事上雙眉，問着窮通盡不知。", "兩鶴忽飛因客到，一牛方病得妻醫。", "案頭幾卷陰功錄，壁上諸家勸世詩。", "見說今年公八十，鬢邊財有數莖絲。"]'),
('e1fe76b2-bf97-4f2b-b51b-093c17a87210','曉行','高翥','宋','宋诗','song-poetry','','[]','跨馬登長路，聞鷄度遠關。',48,'全唐诗/poet.song.186000.json','["跨馬登長路，聞鷄度遠關。", "水光斜漾月，雲影倒薶山。", "人迹霜橋外，禽聲煙樹間。", "自慙林下客，清夢未曾還。"]'),
('2e49cffd-8b4c-40ac-a452-9b3a5df44bee','三峰廢寺','高翥','宋','宋诗','song-poetry','','[]','荒林依約舊山門，秋草離離故迹存。',64,'全唐诗/poet.song.186000.json','["荒林依約舊山門，秋草離離故迹存。", "雙瀑有聲傳宿雨，一龕無地住閑雲。", "蝸沿壞壁丹青古，龜負殘碑字畫昏。", "三歎廢興誰可問，亂鴉鳴噪自成羣。"]'),
('401af79a-de9c-4d74-8628-21068eeba90e','下塘','高翥','宋','宋诗','song-poetry','','[]','日出移船日又斜，蘆根時復見人家。',32,'全唐诗/poet.song.186000.json','["日出移船日又斜，蘆根時復見人家。", "水鄉占得秋多少，岸岸紅雲是蓼花。"]'),
('9a06ee31-7099-42ba-a5c2-9525b2dd5dd0','行淮','高翥','宋','宋诗','song-poetry','','[]','老翁八十鬢如絲，手縛黄蘆作短籬。',32,'全唐诗/poet.song.186000.json','["老翁八十鬢如絲，手縛黄蘆作短籬。", "勸客莫嗔無凳坐，去年今日是流移。"]'),
('51858e8c-d82a-423d-9393-9d4280f4b916','蘭亭','高翥','宋','宋诗','song-poetry','','[]','老來渾不愛春遊，來對蘭亭爛熳秋。',64,'全唐诗/poet.song.186000.json','["老來渾不愛春遊，來對蘭亭爛熳秋。", "亭下水非當日曲，山前竹似舊時脩。", "二三客子因懷古，八百餘年續勝流。", "試與山靈論往事，不知還肯點頭不。"]'),
('6976eba0-d90a-4a51-afa2-d496fa706161','贈丁子植撫幹','高翥','宋','宋诗','song-poetry','','[]','幙府歸來赴調時，清聲籍籍滿京師。',64,'全唐诗/poet.song.186000.json','["幙府歸來赴調時，清聲籍籍滿京師。", "真如白璧藏奇石，判得黄金博斷碑。", "借宅先尋籠鶴地，買盆權作養魚池。", "客中高致猶如此，明日還山樂可知。"]'),
('00732100-a7cd-4a22-9d88-bcbb382bf494','天章寺','高翥','宋','宋诗','song-poetry','','[]','地勝秋清人欲仙，倚闌時節月初圓。',64,'全唐诗/poet.song.186000.json','["地勝秋清人欲仙，倚闌時節月初圓。", "不知寺在煙霞表，但覺身臨星斗邊。", "寶墨舊歸天上去，高名今向世間傳。", "登臨莫作匆匆會，去後重來又幾年。"]'),
('9df30efe-4b8a-4d87-a4ba-baa60ea9daca','天衣寺','高翥','宋','宋诗','song-poetry','','[]','萬壑千巖非浪聞，十峰雙澗不須論。',64,'全唐诗/poet.song.186000.json','["萬壑千巖非浪聞，十峰雙澗不須論。", "袈裟旋化空王服，宮殿曾招帝子魂。", "山向馬頭回禹穴，谿分燕尾入雲門。", "秋行既了登臨願，草草題詩對綠尊。"]'),
('af462fc8-5882-4bbe-b598-6b5dafb10cae','毅齋鄭祕書道山領客','高翥','宋','宋诗','song-poetry','','[]','羣玉堂前春晝陰，主人領客步清深。',64,'全唐诗/poet.song.186000.json','["羣玉堂前春晝陰，主人領客步清深。", "上方圖畫無真贋，東壁詩書有古今。", "手轉玉璣看測日，指揮金井試爲霖。", "山翁不作蓬萊夢，但願時來洗此心。"]'),
('9676d9c2-da46-493e-bd2b-c428a6b58c1d','元日','高翥','宋','宋诗','song-poetry','','[]','長憶兒時二老傍，元正歲歲有風光。',64,'全唐诗/poet.song.186000.json','["長憶兒時二老傍，元正歲歲有風光。", "攙先禮數修人事，着好衣裳侍酒觴。", "回首不堪追日月，感情空歎換星霜。", "尚期我老如親老，却看兒童作節忙。"]'),
('8ac75998-336f-4843-869b-58627a732c03','重五日懷舊','高翥','宋','宋诗','song-poetry','','[]','獨守空庭日欲晡，滿斟濁酒不須沽。',64,'全唐诗/poet.song.186000.json','["獨守空庭日欲晡，滿斟濁酒不須沽。", "白頭兄弟三年別，青眼交遊一字無。", "醉看葵榴懷舊事，饞思櫻笋夢吾廬。", "向時癡絕今愁絕，自讀離騷些老夫。"]'),
('4acd21e9-3af6-46e1-8d4f-a2fff0b66102','贈番昜程克己','高翥','宋','宋诗','song-poetry','','[]','見說番昜有老程，與人懷抱亦分明。',64,'全唐诗/poet.song.186000.json','["見說番昜有老程，與人懷抱亦分明。", "一千里外未識面，二十年間長慕名。", "因聽酒邊談舊事，便從客裏定交情。", "他時我老君猶健，海內重逢即弟兄。"]'),
('053c8eef-7b16-425d-9bd3-23f3bc2b7118','初聞雷聲','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','二月寒猶在，春雲濕未開。',48,'全唐诗/poet.song.186000.json','["二月寒猶在，春雲濕未開。", "灑窗終夜雨，發軔數聲雷。", "薺麥綠生腦，棠梨紅拆腮。", "西湖花事動，從此日裴回。"]'),
('5dbceff4-11bf-40d7-b65a-14a3a627514c','靈巖寺','高翥','宋','宋诗','song-poetry','','[]','天柱峰高逼太清，靈巖端足擅高名。',64,'全唐诗/poet.song.186000.json','["天柱峰高逼太清，靈巖端足擅高名。", "人間有石皆奴僕，天下無山可弟兄。", "樵徑雪深多虎迹，清谿風暖盡猿聲。", "客身元是山林種，見此如何不動情。"]'),
('b7163947-14ad-4bbd-b00d-3a6ca7fec7d4','秋夜','高翥','宋','宋诗','song-poetry','','[]','小屏相對兩眉攢，長夜迢迢不肯殘。',64,'全唐诗/poet.song.186000.json','["小屏相對兩眉攢，長夜迢迢不肯殘。", "鼠向鐙前窺坐卧，人從夢裏說悲歡。", "故山無計行秋晚，客路從誰守歲寒。", "留得濁醪相慰藉，酒腸猶喜十分寬。"]'),
('e87baeaa-8f47-447f-8d9f-242e6d6e087d','寄王仲彝仲彝留三衢久不歸省因以箴之','高翥','宋','宋诗','song-poetry','','[]','別君三見鴈南飛，夢裏相逢覺又非。',64,'全唐诗/poet.song.186000.json','["別君三見鴈南飛，夢裏相逢覺又非。", "書去不知何日到，人來先問幾時歸。", "正堪鐙火親書卷，莫遣塵埃染客衣。", "二老倚門知已久，交情於此亦依依。"]'),
('774da1e6-ce3b-4856-a6a5-0ece01d736d6','李將','高翥','宋','宋诗','song-poetry','','[]','自小在行伍，得官因用兵。',48,'全唐诗/poet.song.186000.json','["自小在行伍，得官因用兵。", "籌邊頭髮豎，入陣骨毛輕。", "戰馬惜如命，寶刀都有名。", "酒酣常駡坐，嫌客話昇平。"]'),
('b6741d34-cc5e-4bea-a6b7-606bf3649349','無錫縣春日','高翥','宋','宋诗','song-poetry','','[]','吳楚新岐路，江湖舊散人。',48,'全唐诗/poet.song.186000.json','["吳楚新岐路，江湖舊散人。", "放船來古縣，沽酒供閑身。", "花卸一村雨，鳥啼千樹春。", "野塘風捲地，無復見芳塵。"]'),
('c750e763-4cc8-44c0-987c-58b0b5cae94f','常熟縣破山寺','高翥','宋','宋诗','song-poetry','','[]','古縣滄浪外，精藍縹渺間。',48,'全唐诗/poet.song.186000.json','["古縣滄浪外，精藍縹渺間。", "木枯曾閲世，龍老解分山。", "鳥道秋迷跡，禪房晝掩關。", "詩成遊子去，流水自潺潺。"]'),
('b537c731-f384-400c-86e6-f5a359f37d0c','曹娥浦泊舟','高翥','宋','宋诗','song-poetry','','[]','夜宿曹娥浦，停舟是幾更。',48,'全唐诗/poet.song.186000.json','["夜宿曹娥浦，停舟是幾更。", "聞鐘知寺近，聽艣信潮生。", "風向沙頭起，天從柁尾明。", "夢回無意緒，兩岸杜鵑聲。"]'),
('83c090fc-6757-4b79-822e-7b26bfdc9d91','拜林和靖墓','高翥','宋','宋诗','song-poetry','','[]','玉函香骨老雲根，占斷孤山水月村。',64,'全唐诗/poet.song.186000.json','["玉函香骨老雲根，占斷孤山水月村。", "薦菊泉清涵竹影，種梅地冷带苔痕。", "生前已自全名節，身後從誰問子孫。", "惟是年年寒食日，遊人來與酹清尊。"]'),
('56e78e6e-59f6-4eb5-99aa-c0babfad9e68','多景樓','高翥','宋','宋诗','song-poetry','','[]','一带青山欲盡頭，精藍深處着危樓。',64,'全唐诗/poet.song.186000.json','["一带青山欲盡頭，精藍深處着危樓。", "下無餘地容車馬，上有重簷接斗牛。", "鴉落野田長趁晚，鴈沉煙渚最宜秋。", "江南好景從來少，北望空多故國愁。"]'),
('a6eb8ab9-c495-430d-9f70-e32b39c54676','賞心亭','高翥','宋','宋诗','song-poetry','','[]','江亭如倚釣魚磯，面面雲簷勢欲飛。',64,'全唐诗/poet.song.186000.json','["江亭如倚釣魚磯，面面雲簷勢欲飛。", "西望汀洲依白鷺，東連巷陌接烏衣。", "六朝更代人何在，千古興亡事總非。", "客子獨憐風景好，倚闌長是欲忘歸。"]'),
('ad756ad7-d80e-4e36-8110-27855ebe2dc4','夜過馬當山','高翥','宋','宋诗','song-poetry','','[]','獨載詩書趁野航，自憐漂泊度時光。',64,'全唐诗/poet.song.186000.json','["獨載詩書趁野航，自憐漂泊度時光。", "殘年準擬登牛首，連夜勿忙過馬當。", "古廟荒寒江浸影，斷崖凄慘石凝霜。", "壯懷未分甘衰老，回首長淮恨更長。"]'),
('6c79d607-8879-425b-b506-8210c1a86de9','輓章朋舉','高翥','宋','宋诗','song-poetry','','[]','相逢便拜十年兄，自此交遊得盡情。',64,'全唐诗/poet.song.186000.json','["相逢便拜十年兄，自此交遊得盡情。", "草紙抄書傳遁甲，竹筩沽酒命添丁。", "他時結屋期來往，今日登門隔死生。", "從此苕溪明月夜，小舟不復爲君停。"]'),
('0c80ba81-5236-4638-8476-635551549dd1','雨中','高翥','宋','宋诗','song-poetry','','[]','霍地春歸喚不譍，客中容易鬢星星。',64,'全唐诗/poet.song.186000.json','["霍地春歸喚不譍，客中容易鬢星星。", "漫山風雨櫻桃紫，繞屋煙雲薜荔青。", "姑惡恨誰能自苦，子規催客厭人聽。", "閉門獨坐難拋酒，生怕離愁到短屏。"]'),
('9c1270c1-d06a-44a8-8452-0e4e18b57478','拜李謫仙墓','高翥','宋','宋诗','song-poetry','','[]','蕭蕭高塚占雲根，故老相傳太白墳。',64,'全唐诗/poet.song.186000.json','["蕭蕭高塚占雲根，故老相傳太白墳。", "白骨定隨風月冷，青山長共姓名存。", "平生出處猶如見，一死浮沈異所聞。", "客子開元書記後，故來澆酒些清魂。"]'),
('a00fe8c6-3032-464e-8e49-6557d828e6cd','舍姪來','高翥','宋','宋诗','song-poetry','','[]','自從清曉至黄昏，閒坐閒眠深閉門。',64,'全唐诗/poet.song.186000.json','["自從清曉至黄昏，閒坐閒眠深閉門。", "猶子雨中來息擔，老夫鐙下起開樽。", "故山墳墓何人守，舊宅園亭幾處存。", "問答恍然如隔世，若非沈醉定消魂。"]'),
('5ead228e-4da7-4750-b579-443834b1a4fc','丁卯冬送方巖','高翥','宋','宋诗','song-poetry','','[]','忠言歷歷未曾行，盡載圖書出帝城。',64,'全唐诗/poet.song.186000.json','["忠言歷歷未曾行，盡載圖書出帝城。", "餘子但知才可忌，先生當以去爲榮。", "門闌竹石關心久，部曲谿山照眼明。", "長嘯歸歟莫怊悵，浙江風定自潮平。"]'),
('20e2247a-4a04-420b-b94f-f80b1dd6a23d','春夜','高翥','宋','宋诗','song-poetry','','[]','小窗兀兀守更殘，案上詩書亦嬾觀。',64,'全唐诗/poet.song.186000.json','["小窗兀兀守更殘，案上詩書亦嬾觀。", "頻翦燭花聽夜雨，盡垂簾影隔春寒。", "破除夢幻從頭了，安置身心向下看。", "老子靜中消日月，全然不似客長安。"]'),
('84ed9479-46c4-4db0-895d-8d99347ad943','楊花','高翥','宋','宋诗','song-poetry','','[]','萬縷千絲拂水濱，盡催飛絮送殘春。',64,'全唐诗/poet.song.186000.json','["萬縷千絲拂水濱，盡催飛絮送殘春。", "風前輕薄佳人命，天外飄零宕子身。", "繞路鋪時成素毯，就泥沾處襯芳塵。", "江頭雨過遺蹤盡，留得柔條折贈人。"]'),
('a3d06efa-56e4-47aa-bff4-fb2e262859b2','清明日對酒','高翥','宋','宋诗','song-poetry','','["\u76f8\u601d", "\u6e05\u660e\u8282", "\u611f\u4f24"]','南北山頭多墓田，清明祭掃各紛然。',64,'全唐诗/poet.song.186000.json','["南北山頭多墓田，清明祭掃各紛然。", "紙灰飛作白胡蜨，淚血染成紅杜鵑。", "日落狐狸眠冢上，夜歸兒女笑鐙前。", "人生有酒須當醉，一滴何曾到九泉。"]'),
('29769312-b8be-452b-9b22-db4d70ceb6d1','秋興','高翥','宋','宋诗','song-poetry','','[]','老去無心世事輕，但從景物略關情。',64,'全唐诗/poet.song.186000.json','["老去無心世事輕，但從景物略關情。", "曉看鴈陣驚秋晚，夜聽鶴聲知月明。", "石鼎煮茶論水品，土牆題字記花名。", "出門更自有真樂，閒向通衢穩步行。"]'),
('2b0a2377-c095-49b6-ab79-1b114cc40a0a','山行即事','高翥','宋','宋诗','song-poetry','','[]','籃輿破曉入山家，獨木橋低小徑斜。',64,'全唐诗/poet.song.186000.json','["籃輿破曉入山家，獨木橋低小徑斜。", "屋角盡懸牛蒡菜，籬根多發馬蘭花。", "主人一笑先呼酒，勸客三杯便當茶。", "我已經年無此樂，爲憐身久在京華。"]'),
('f69f4732-0424-46e2-8b40-03f814e307e0','靈鷲寺','高翥','宋','宋诗','song-poetry','','[]','靈鷲名山萬古名，幾回無事繞廊行。',64,'全唐诗/poet.song.186000.json','["靈鷲名山萬古名，幾回無事繞廊行。", "殿前流水晴猶急，塔上春雲晚自生。", "鶴傍經牀聽梵語，鳥窺齋鉢候鍾聲。", "我來借得團蒲坐，歸去閒眠夢亦清。"]'),
('1cb8c3e9-1363-4fc0-87b2-4e6dfc738226','老將','高翥','宋','宋诗','song-poetry','','[]','垂頭終日坐當門，兩臂蒼龍隠墨紋。',64,'全唐诗/poet.song.186000.json','["垂頭終日坐當門，兩臂蒼龍隠墨紋。", "笑撚白須傳陣法，手攤黄紙說君恩。", "中年主帥皆爲鬼，晚歲虞兵見領軍。", "每勸兒孫學刀箭，解衣教看舊瘢痕。"]'),
('20f121ff-13cf-4edd-b9bd-1cef0d02798c','秋夜書懷','高翥','宋','宋诗','song-poetry','','[]','明滅孤鐙縹緲香，沈沈更漏隔宮牆。',64,'全唐诗/poet.song.186000.json','["明滅孤鐙縹緲香，沈沈更漏隔宮牆。", "秋風倦客家千里，夜雨懷人天一方。", "世事從他多鉏鋙，生涯如我亦淒涼。", "亟須喚酒消長夜，休夢黄華繞澗傍。"]'),
('b3b5f51b-97f4-49c0-88df-557a5977b4f9','投老','高翥','宋','宋诗','song-poetry','','[]','投老纔營一把茅，前臨官路後林坳。',64,'全唐诗/poet.song.186000.json','["投老纔營一把茅，前臨官路後林坳。", "最宜雞犬無鄰舍，好放牛羊有近郊。", "春韮採來勝市食，秋鱸留取續山肴。", "吾廬誰道難尋覓，古樹排門盡鵲巢。"]'),
('566f8746-4a4f-496c-bd65-cafbb00aca27','喜杜仲高移居清湖','高翥','宋','宋诗','song-poetry','','[]','笑携雞犬入城居，無復游從歎闊疏。',64,'全唐诗/poet.song.186000.json','["笑携雞犬入城居，無復游從歎闊疏。", "河水通船堪載酒，桐陰近屋可脩書。", "飯香休憶辛田米，羹美何慙丙穴魚。", "我亦買山湖上住，效芹時擬貢園蔬。"]'),
('5ca82f3f-ec9e-4f4d-960f-5ce35bbe915c','虎丘寺','高翥','宋','宋诗','song-poetry','','[]','西出吳門步屧輕，浮屠喚客入山行。',64,'全唐诗/poet.song.186000.json','["西出吳門步屧輕，浮屠喚客入山行。", "石從試劍何年裂，池自通泉盡日平。", "煙徑遠傳僧磬響，雲龕深鎖佛燈明。", "移舟更宿楓橋寺，要聽疎鍾半夜鳴。"]'),
('6a4759f7-fcab-490d-850f-b1c1af8b1eb6','焦山','高翥','宋','宋诗','song-poetry','','[]','山擁中流翠作堆，四圍竹樹鬰崔嵬。',64,'全唐诗/poet.song.186000.json','["山擁中流翠作堆，四圍竹樹鬰崔嵬。", "殿前雲向簷牙出，門外潮從海口來。", "乞食僧歸齋鼓動，打碑人去渡船開。", "焦公羽化將名迹，付與瞿曇亦壯哉。"]'),
('fa5cde86-ccb6-4672-b0bf-4c4eac20d039','蛾眉亭','高翥','宋','宋诗','song-poetry','','[]','千尺懸崖巨浪撞，危亭高峙對微茫。',64,'全唐诗/poet.song.186000.json','["千尺懸崖巨浪撞，危亭高峙對微茫。", "遠峰凝黛雙蛾澹，流水連雲一带長。", "日落江容難可盡，天寒山色不成妝。", "停舟欲試登臨眼，北望青煙欲斷腸。"]'),
('63abeee8-e64a-471b-83a7-c89493019543','凌歊臺','高翥','宋','宋诗','song-poetry','','[]','宋祖高臺山上頭，三閒破屋蔽層丘。',64,'全唐诗/poet.song.186000.json','["宋祖高臺山上頭，三閒破屋蔽層丘。", "離離荒草迷行殿，漠漠寒沙擁故洲。", "塔影遠招孤客恨，江聲長替古人愁。", "題詩自舊知多少，清絕難磨許郢州。"]'),
('f3df39d4-e4d8-4128-84d3-04b4ed465c57','三峽橋','高翥','宋','宋诗','song-poetry','','[]','倦游華髮冷蕭騷，長夏來登三峽橋。',64,'全唐诗/poet.song.186000.json','["倦游華髮冷蕭騷，長夏來登三峽橋。", "山吐溼雲何日盡，溪流凍雪幾時消。", "陸公泉在猶堪汲，五老峰高不易招。", "客子倚欄思羽化，未仙衣袂已飄飄。"]'),
('6a92a761-dc99-406b-8085-ba945824ed3a','雪堂','高翥','宋','宋诗','song-poetry','','[]','勝地從來迹易陳，東坡日月久尤新。',64,'全唐诗/poet.song.186000.json','["勝地從來迹易陳，東坡日月久尤新。", "小橋曾壓歸時雪，老柳長摇別後春。", "城郭寥寥懷獨鶴，江山歷歷見斯人。", "客生較晚空惆悵，夢想陳潘結舊隣。"]'),
('5bb07161-8451-446f-b5f2-bd5e9a97b8cb','竹樓','高翥','宋','宋诗','song-poetry','','[]','老竹平分當建瓴，小樓從此擅高名。',64,'全唐诗/poet.song.186000.json','["老竹平分當建瓴，小樓從此擅高名。", "地連雲堞登臨穩，欄俯晴江夢寐清。", "一記自能追正始，三閒誰與續咸平。", "濤音日日煙中落，依約焚香讀易聲。"]'),
('3b8e14b7-c6fc-4c65-a9ea-1b1bc9699f01','八月旦日永定寺作','高翥','宋','宋诗','song-poetry','','[]','蕭然一室坐清虛，又見西風到客居。',64,'全唐诗/poet.song.186000.json','["蕭然一室坐清虛，又見西風到客居。", "老去身心便嬾惰，人來情意任親疎。", "從僧借地秋移菊，與佛分鐙夜讀書。", "幽事復爲行計奪，去留端的合何如。"]'),
('1f955733-c98d-4243-8f0f-32099cca6b10','小樓','高翥','宋','宋诗','song-poetry','','[]','小樓終日脫冠巾，白髮蕭疎不受塵。',64,'全唐诗/poet.song.186000.json','["小樓終日脫冠巾，白髮蕭疎不受塵。", "雖是客身猶足樂，苦無世累未爲貧。", "家書遠寄憑游子，邸報頻看念故人。", "自歎此心清似水，爲他閒事惱天真。"]'),
('d0598650-d2fb-4f83-9e6e-fc7699792fcb','清明日約宋正甫黄行之兄弟爲東湖之集','高翥','宋','宋诗','song-poetry','','[]','自在嬉遊徧四方，不曾孤負獨春光。',64,'全唐诗/poet.song.186000.json','["自在嬉遊徧四方，不曾孤負獨春光。", "醉眠芳草衣裳冷，笑嚼名花齒頰香。", "既是煙霞令久任，豈應風月斷來章。", "故人尚有閒情不，相伴湖邊舉一觴。"]'),
('712c097d-fce0-4ee3-96f6-ca3099665fa7','過方孚若寺丞故廬','高翥','宋','宋诗','song-poetry','','[]','詩境園林萬柳閒，四圍秋草带愁顔。',64,'全唐诗/poet.song.186000.json','["詩境園林萬柳閒，四圍秋草带愁顔。", "樓臺寂寞鼠成穴，巖石崔嵬蚊負山。", "三徑昔嫌前輩窄，一區今欠此翁閒。", "客來莫怪匆匆去，萬感催人鬢易斑。"]'),
('86c81ff7-c001-4a17-a415-c59345f7c6e7','宿囊山寺','高翥','宋','宋诗','song-poetry','','[]','小泊囊山古化城，山林端足擅高名。',64,'全唐诗/poet.song.186000.json','["小泊囊山古化城，山林端足擅高名。", "樓臺影外秋風老，鍾磬聲中夜氣清。", "客子情懷宜淡薄，主人言語亦分明。", "只應海月堂前境，從此江湖有夢成。"]'),
('a23e8775-0b9f-4f4c-8809-110782c9cfdc','潛夫約中途遣詩相送至江山無耗寄詩督之','高翥','宋','宋诗','song-poetry','','[]','望詩十步九回頭，目斷江山望未休。',64,'全唐诗/poet.song.186000.json','["望詩十步九回頭，目斷江山望未休。", "所幸臨行曾舉似，僅能記憶可遮羞。", "碧雲漏日村村雨，紅樹吟風葉葉秋。", "不見夜光生歇處，客身却恨欠遲留。"]'),
('9126ba66-5824-44e0-80b2-97e9298fafa1','門徑','高翥','宋','宋诗','song-poetry','','[]','門徑蕭然獨自居，入無給侍出無車。',64,'全唐诗/poet.song.186000.json','["門徑蕭然獨自居，入無給侍出無車。", "江湖故舊音塵絕，里巷游從酒盞疎。", "豪舉已拋三尺劍，神交惟有一牀書。", "吾兄白髮家空谷，歲晚燈前最憶渠。"]'),
('a9aa7dab-5d65-4f7e-8e98-03909ed61ed4','破屋','高翥','宋','宋诗','song-poetry','','[]','破屋三間書五車，一翁醉髮老髿髿。',64,'全唐诗/poet.song.186000.json','["破屋三間書五車，一翁醉髮老髿髿。", "蕭牆甚窄難栽竹，草地雖平不種花。", "井淺自能供日用，樓高誰怕被雲遮。", "過門人問何人住，題扇橋西百姓家。"]'),
('ba1d0e8c-5eca-4379-855f-d6a2e6aace0e','清明日招社友','高翥','宋','宋诗','song-poetry','','[]','面皮如鐵鬢如絲，依舊粗豪似向時。',64,'全唐诗/poet.song.186000.json','["面皮如鐵鬢如絲，依舊粗豪似向時。", "嗜酒更拚三日醉，看花因費一春詩。", "生前富貴誰能必，身後聲名我不知。", "且趁酴醾對醽醁，共來相與一伸眉。"]'),
('2ff7d05a-57e9-42f6-9b25-108931f8c7d3','感懷二首  其一','高翥','宋','宋诗','song-poetry','','[]','漂泊南州又過年，恰如杜子客鄜川。',64,'全唐诗/poet.song.186000.json','["漂泊南州又過年，恰如杜子客鄜川。", "酒堪度日難爲醉，詩怕傷時未可傳。", "店舍無煙兵火後，街坊有月試燈前。", "荒涼古驛聞吹笛，老淚縱橫落枕邊。"]'),
('625ba191-076e-4692-a8e8-0d4b3796e5f7','感懷二首  其二','高翥','宋','宋诗','song-poetry','','[]','行遍千山復萬山，不應蜀道若爲難。',64,'全唐诗/poet.song.186000.json','["行遍千山復萬山，不應蜀道若爲難。", "數莖髮向殊方白，一寸心從故國丹。", "弓軟臂無三斗力，杯深量欠十分寬。", "粗豪到了非吾事，只盍家居度歲寒。"]'),
('a1ee75f2-09e0-4894-bb15-f42403bd02f6','挽陳復齋','高翥','宋','宋诗','song-poetry','','[]','憂世心勞鬢易斑，笑顰還與世相關。',64,'全唐诗/poet.song.186000.json','["憂世心勞鬢易斑，笑顰還與世相關。", "秋霜烈日君臣際，和氣春風母子閒。", "學道期傳千載統，獻言先辦一生閒。", "堂堂仰止人何在，獨有名如不動山。"]'),
('56d5357e-a2d8-49b7-9f74-80d1ecff2708','同劉潛夫登烏石山望海有懷方孚若柯東海陳復齋舊游','高翥','宋','宋诗','song-poetry','','[]','念念思歸身欲翰，舊題無暇徧尋看。',64,'全唐诗/poet.song.186000.json','["念念思歸身欲翰，舊題無暇徧尋看。", "故人盡入黄泉路，遠客空登烏石山。", "休起癡心乘九鯉，莫勞病眼望三韓。", "神仙未必知吾事，道在何妨兩鬢斑。"]'),
('51c31091-034c-41bd-aa42-6abad73cdd20','山中哭復齋','高翥','宋','宋诗','song-poetry','','[]','封章字少納忠多，袖疏前陳無柰何。',64,'全唐诗/poet.song.186000.json','["封章字少納忠多，袖疏前陳無柰何。", "但得中天行日月，不愁平地起風波。", "臺官論罪終投筆，山賊聞名亦倒戈。", "惆悵脊梁如鐵硬，天胡忍使閟山河。"]'),
('3fc17ba0-885c-44dd-9c2b-c39cf2856aa3','懷安王宰索得助詩奉題一首','高翥','宋','宋诗','song-poetry','','[]','亭在唐賢好句中，闌干六曲盡春風。',64,'全唐诗/poet.song.186000.json','["亭在唐賢好句中，闌干六曲盡春風。", "不知脚下是官府，但見面前如渚宮。", "江水逢潮音激切，山雲因雨思溟濛。", "主人雅興居詩外，花影琴聲事事工。"]'),
('88a6b5d9-96f5-4e02-b12c-f046a6184911','清明日延平道上','高翥','宋','宋诗','song-poetry','','[]','自從閩嶠至延平，試問歸塗第幾程。',64,'全唐诗/poet.song.186000.json','["自從閩嶠至延平，試問歸塗第幾程。", "人向煙嵐深處出，鳥依雲樹密邊鳴。", "潤沾破屐春泥滑，寒入征衫曉雨晴。", "多謝山家插楊柳，報儂今日是清明。"]'),
('27e668b6-1663-4ef6-bcdc-5b196b92244f','趙忠定公帥蜀時題雪錦樓有扁舟衡嶽問歸程之句後來人以爲讖題跋者甚多邵陽節使君以墨本見贈敬書其右','高翥','宋','宋诗','song-poetry','','[]','九鼎重安國勢牢，功名易辦謗難逃。',64,'全唐诗/poet.song.186000.json','["九鼎重安國勢牢，功名易辦謗難逃。", "手扶日月掃雲霧，身向江湖直羽毛。", "雪錦詩成如讖兆，金縢書啟見勤勞。", "紛紛論定知忠定，不負朝廷兩字褒。"]'),
('3c544d4e-1ac8-4805-931f-41a139335f3a','秋陰','高翥','宋','宋诗','song-poetry','','[]','冉冉日將莫，蕭蕭秋欲殘。',48,'全唐诗/poet.song.186000.json','["冉冉日將莫，蕭蕭秋欲殘。", "浮雲低閣雨，宿靄密藏山。", "扇覺輕蒲重，衣嫌細葛單。", "更交一寒暑，精進獨衰顔。"]'),
('0ef90b0c-3fe2-4ca2-95d0-720417fcae58','富陽縣秋日','高翥','宋','宋诗','song-poetry','','[]','古井梧桐老，平田䆉稏收。',48,'全唐诗/poet.song.186000.json','["古井梧桐老，平田䆉稏收。", "鷄豚百里社，砧杵十分秋。", "乾鵲催歸興，寒蟬喚客愁。", "銜杯憶霜蟹，沙尾暮停舟。"]'),
('e9982b00-3a4d-482c-9868-2c6ffdd999bb','秋日入無量院','高翥','宋','宋诗','song-poetry','','[]','僧閒甘寂寞，寺古絕紛華。',48,'全唐诗/poet.song.186000.json','["僧閒甘寂寞，寺古絕紛華。", "鳥摘過牆棗，猿爭守樹樝。", "雨多谿沒井，藤老蔓緣笆。", "莫坐庭前石，怕傷苔蘚花。"]'),
('213db6c6-1c52-45f8-8a1b-cfb0fba4deef','小樓夜雨','高翥','宋','宋诗','song-poetry','','[]','心嬾緣忘世，身閒爲不才。',48,'全唐诗/poet.song.186000.json','["心嬾緣忘世，身閒爲不才。", "客愁隨病散，老眼共書開。", "嗜酒有天戒，愛花無地栽。", "小樓風雨夜，還我鼻如雷。"]'),
('32f25a6c-08aa-4a41-a15d-8ec8aa28a8f2','夜過西興','高翥','宋','宋诗','song-poetry','','[]','宵濟向西興，鍾聲隔岸聽。',48,'全唐诗/poet.song.186000.json','["宵濟向西興，鍾聲隔岸聽。", "淺灘淘落月，遠樹納殘星。", "客路悠悠去，征橈在在停。", "明朝故山近，不必問郵亭。"]'),
('aabe906e-42b4-46b1-9930-c877128913b4','度仙霞嶺','高翥','宋','宋诗','song-poetry','','[]','盡日度僊霞，西風吹鬢華。',48,'全唐诗/poet.song.186000.json','["盡日度僊霞，西風吹鬢華。", "乍寒拋白苧，臨晚見黄花。", "山險全無路，溪晴半是沙。", "嶺頭逢宿處，斜月带棲鴉。"]'),
('2bde19ca-74bc-4d8a-b060-692309809701','建昌道上','高翥','宋','宋诗','song-poetry','','[]','凜凜北風勁，行行西路賒。',48,'全唐诗/poet.song.186000.json','["凜凜北風勁，行行西路賒。", "客情甘淡薄，世事苦參差。", "酒易逢知己，詩難遇作家。", "林閒數點雪，錯認是梅花。"]'),
('078a4080-3c74-4101-b0df-73dad27796bc','隆興借東湖驛度夏雜題','高翥','宋','宋诗','song-poetry','','[]','西風來幾日，荷柳早衰容。',48,'全唐诗/poet.song.186000.json','["西風來幾日，荷柳早衰容。", "百感聞秋笛，孤吟答晚鍾。", "事能如意少，酒不教愁濃。", "憶著蓴鱸美，家山隔幾重。"]'),
('ad0b20cf-60fa-461b-8020-43b85ffa1bfc','春日雜興二首  其一','高翥','宋','宋诗','song-poetry','','[]','簷鈴奏曲響珊珊，盡日重門不啟關。',32,'全唐诗/poet.song.186000.json','["簷鈴奏曲響珊珊，盡日重門不啟關。", "多插缾花供宴坐，爲渠消受一春閒。"]'),
('4760a1e7-2e59-4e03-b3c6-c7ad5e41201d','春日雜興二首  其二','高翥','宋','宋诗','song-poetry','','[]','春歸門巷靜深深，老去無情不彊吟。',32,'全唐诗/poet.song.186000.json','["春歸門巷靜深深，老去無情不彊吟。", "風絮入簾晴晝永，自燒香餠試花沈。"]'),
('27eaa744-ca06-48be-a5f1-482430c818a6','雨中','高翥','宋','宋诗','song-poetry','','[]','濃雲漠漠雨飛飛，不放東風取次吹。',32,'全唐诗/poet.song.186000.json','["濃雲漠漠雨飛飛，不放東風取次吹。", "先自一春晴意少，那堪梅子欲黄時。"]'),
('87353ec4-676f-407c-966f-365da5e0df0f','山堂即事','高翥','宋','宋诗','song-poetry','','[]','杜鵑聲裏桐花落，山館無人晝掩扃。',32,'全唐诗/poet.song.186000.json','["杜鵑聲裏桐花落，山館無人晝掩扃。", "老去未能忘結習，自調濃墨寫黄庭。"]'),
('6ffd6705-a17c-4f8b-9cf9-04a45abfc404','秋夜','高翥','宋','宋诗','song-poetry','','[]','老去驚秋白髮添，不禁涼吹逼疏簾。',32,'全唐诗/poet.song.186000.json','["老去驚秋白髮添，不禁涼吹逼疏簾。", "樓高幸自蛩聲遠，爭柰梧桐又傍簷。"]'),
('f3f57513-94f6-4cdb-b45c-92474c204774','孺子祠堂','高翥','宋','宋诗','song-poetry','','[]','三間官屋老湖濱，孺子名聲日日新。',32,'全唐诗/poet.song.186000.json','["三間官屋老湖濱，孺子名聲日日新。", "下榻本非天上事，後人空自愧前人。"]'),
('72bc7254-2f4b-4429-ab57-30ad414d4edf','西湖二首  其一','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','淺水摇船冷戛沙，平林暝色接棲鴉。',32,'全唐诗/poet.song.186000.json','["淺水摇船冷戛沙，平林暝色接棲鴉。", "湖邊老樹垂垂白，半是梅花半雪花。"]'),
('05e0fc12-fd04-459a-8064-916f41e0deb0','西湖二首  其二','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老鶴無蹤野鴨飛，鳴琴聲裏畫船歸。',32,'全唐诗/poet.song.186000.json','["老鶴無蹤野鴨飛，鳴琴聲裏畫船歸。", "傷心舊日經行地，不獨人非物亦非。"]'),
('3d56d168-4a62-4bd1-9a17-244bda8a5e9d','鬰孤臺  其一','高翥','宋','宋诗','song-poetry','','[]','十年重上鬰孤臺，带得江湖白髮來。',32,'全唐诗/poet.song.186000.json','["十年重上鬰孤臺，带得江湖白髮來。", "滿眼青山舊相識，晚鴉羣噪莫驚猜。"]'),
('9cd634d7-e0a8-4a0d-9f29-1252a3af324f','鬰孤臺  其二','高翥','宋','宋诗','song-poetry','','[]','登臨猶覺酒邊豪，往事新愁付一陶。',32,'全唐诗/poet.song.186000.json','["登臨猶覺酒邊豪，往事新愁付一陶。", "深淺不常章貢水，崆峒只似舊時高。"]'),
('09394824-61af-4597-96de-090bc6c53fae','澗傍菊花','高翥','宋','宋诗','song-poetry','','[]','歷寂黄花老澗傍，不因風雨減清芳。',32,'全唐诗/poet.song.186000.json','["歷寂黄花老澗傍，不因風雨減清芳。", "從教衰謝隨秋草，到了能全晚節香。"]'),
('352f5d34-bd63-455f-a9f0-b743760ea4c1','看弄潮回','高翥','宋','宋诗','song-poetry','','[]','弄罷江潮晚入城，紅旗颭颭白旗輕。',32,'全唐诗/poet.song.186000.json','["弄罷江潮晚入城，紅旗颭颭白旗輕。", "不因會吃翻頭浪，爭得天街鼓樂迎。"]'),
('0ac55b2d-d0d5-4db0-a454-2505f3538b12','西湖暮歸','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風荷百頃占漣漪，烟樹溟濛乳鴨飛。',32,'全唐诗/poet.song.186000.json','["風荷百頃占漣漪，烟樹溟濛乳鴨飛。", "買斷小舟休喚客，時穿萍葉載詩歸。"]'),
('f8ae4931-0e65-40d1-aa5a-ecf2e66f78f0','西湖雜興二首  其一','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','城中無處聽蟬鳴，短策輕鞋晚出城。',32,'全唐诗/poet.song.186000.json','["城中無處聽蟬鳴，短策輕鞋晚出城。", "行到柳陰松影下，恰纔聞得兩三聲。"]'),
('6c04884f-0f4d-4d96-ba24-f444e31e791f','西湖雜興二首  其二','高翥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十三樓寺早餐飯，六一泉寺晚詠歌。',32,'全唐诗/poet.song.186000.json','["十三樓寺早餐飯，六一泉寺晚詠歌。", "坐斷竹風無暑氣，乳禽鳴處綠陰多。"]'),
('75990504-5798-4bc5-b1f7-b1360a403318','夜步天街書所見','高翥','宋','宋诗','song-poetry','','[]','賽罷祠山賽二郎，酒行明日欲祠張。',32,'全唐诗/poet.song.186000.json','["賽罷祠山賽二郎，酒行明日欲祠張。", "愚民可是都忘本，香火何曾到杜康。"]'),
('4b52261f-4ea7-4b51-aa64-28583b6fd209','吳山絕句','高翥','宋','宋诗','song-poetry','','[]','拂曉官來簿錄時，未曾吹徹玉參差。',32,'全唐诗/poet.song.186000.json','["拂曉官來簿錄時，未曾吹徹玉參差。", "旁人不忍聽鸚鵡，猶向金籠喚太師。"]'),
('f2048a5a-25d1-454a-be51-a6fcb182a4ca','菊花  其一','高翥','宋','宋诗','song-poetry','','[]','白白黄黄自歲寒，詩人但作菊花看。',32,'全唐诗/poet.song.186000.json','["白白黄黄自歲寒，詩人但作菊花看。", "牡丹茉莉非吾事，自是時人被眼瞞。"]'),
('422a26b1-b4b6-4484-92cb-d421250dfbef','菊花  其二','高翥','宋','宋诗','song-poetry','','[]','親向東籬手自栽，夕陽小徑重徘徊。',32,'全唐诗/poet.song.186000.json','["親向東籬手自栽，夕陽小徑重徘徊。", "花應得似人乖角，過了重陽爛漫開。"]'),
('62b204fd-4989-4d2d-b11d-7ba722dcc08d','菊花  其三','高翥','宋','宋诗','song-poetry','','[]','愛花千古說淵明，肯把秋光不似春。',32,'全唐诗/poet.song.186000.json','["愛花千古說淵明，肯把秋光不似春。", "我重此花全晚節，賸栽三徑伴閒身。"]'),
('ea3ed354-9ac0-4e0c-ab3c-2bb366a31b20','巖桂花','高翥','宋','宋诗','song-poetry','','[]','玉蕊琅玕樹，天香知意薰。',24,'全唐诗/poet.song.186000.json','["玉蕊琅玕樹，天香知意薰。", "露寒清透骨，風定遠含芬。"]'),
('84e9c176-3287-4f96-8fa2-d497b26fa697','兄壽弟','高翥','宋','宋诗','song-poetry','','[]','再歲佳辰捧壽巵，今年清夢浙江湄。',64,'全唐诗/poet.song.186000.json','["再歲佳辰捧壽巵，今年清夢浙江湄。", "鶺鴒地冷真堪□，鴻雁雲飛會有時。", "芍藥泛杯猶共醉，梅花照座可重期。", "直須千歲州成日，銅狄摩挲世自知。"]'),
('56491aca-2e71-4040-9470-e2bcde11d3e4','賀楊東山休致','高翥','宋','宋诗','song-poetry','','[]','莫言納祿尋常事，試讀唐人夢謁賦。',64,'全唐诗/poet.song.186000.json','["莫言納祿尋常事，試讀唐人夢謁賦。", "騎馿徑上東山椒，九州四海風蕭蕭。", "大瓢貯雲杓斟月，却跨陰崖聽冰柝。", "松蘿影薄寒花妍，白鷗飛來亦欣然。"]'),
('f6c3b83d-9897-4a95-8f1c-39b7d595a3ce','寂上人禪房','高翥','宋','宋诗','song-poetry','','[]','俗塵浮垢閉禪關，百歲身心幾日閑。',32,'全唐诗/poet.song.186000.json','["俗塵浮垢閉禪關，百歲身心幾日閑。", "安得此生同草木，無營長在四時閒。"]'),
('6873c8b6-c801-4810-aaab-b67b5be9b363','崇聖寺斌公房','高翥','宋','宋诗','song-poetry','','["\u8861\u5c71"]','近來唯一食，樹下掩禪扉。',48,'全唐诗/poet.song.186000.json','["近來唯一食，樹下掩禪扉。", "落日寒山磬，多年壞衲衣。", "白鬚長更剃，青靄遠還歸。", "仍說游南嶽，經行是息機。"]'),
('f6ec2b64-4575-4ccc-a8a9-557a85a850f6','下塘','高翥','宋','宋诗','song-poetry','','[]','河水新添三尺高，河邊蘆葦有龜巢。',32,'全唐诗/poet.song.186000.json','["河水新添三尺高，河邊蘆葦有龜巢。", "波流夜夜飄漁箔，空點籃燈照樹梢。"]'),
('17e2260a-f82d-411b-8274-df45c9256a1b','題信天巢集','高翥','宋','宋诗','song-poetry','','[]','信天巢小僅容身，中有圖書障俗塵。',64,'全唐诗/poet.song.186000.json','["信天巢小僅容身，中有圖書障俗塵。", "不與世爭閑意氣，且隨時養老精神。", "破鐺安穩齊鐘鼎，短褐參差比縉紳。", "渴飲三杯饑二飯，主人日用未爲貧。"]'),
('773aa050-b790-4952-a2e7-10ffd6a642a8','靜對','高翥','宋','宋诗','song-poetry','','[]','靜對爐煙一縷霞，謝天成就澹生涯。',64,'全唐诗/poet.song.186000.json','["靜對爐煙一縷霞，謝天成就澹生涯。", "安排瓦硯臨章草，收拾甆瓶插鄭花。", "莫問家儲無擔石，休嫌人事似團沙。", "三杯竟醉醒時晚，卧看春雲送日斜。"]'),
('83ede941-f6c1-4bd2-88b2-97448b035a4c','無計','高翥','宋','宋诗','song-poetry','','[]','無計留連日，爭來斷送春。',48,'全唐诗/poet.song.186000.json','["無計留連日，爭來斷送春。", "落花終日雨，流水一溪雲。", "山鳥呼名急，林梢著色新。", "詩成真謾興，吾懶事因循。"]'),
('4ba1953d-f05f-4a82-8603-5a207d3223a6','客枕','高翥','宋','宋诗','song-poetry','','[]','客枕眠僧舍，巍然鶴髮翁。',48,'全唐诗/poet.song.186000.json','["客枕眠僧舍，巍然鶴髮翁。", "事如前日異，心與少年同。", "一夜送春雨，五更臨曉風。", "夢回思往事，愁在不言中。"]'),
('ab102a47-e200-49eb-9fa9-d42a359240c4','廬山道中','高翥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','沿路梅花管送迎，廬山初別雪初晴。',32,'全唐诗/poet.song.186000.json','["沿路梅花管送迎，廬山初別雪初晴。", "若無急事相驅役，有酒人家便不行。"]'),
('b3b9742f-d670-4ac3-9cb4-45421eda896c','采石','高翥','宋','宋诗','song-poetry','','[]','采石興亡地，聲名宇宙齊。',48,'全唐诗/poet.song.186000.json','["采石興亡地，聲名宇宙齊。", "山眉間吳楚，江口折東西。", "今古多遺恨，英雄幾噬臍。", "征塵何日盡，北望轉悲悽。"]'),
('54175f6d-d840-4925-aec6-e4070230b856','歎息','高翥','宋','宋诗','song-poetry','','[]','歎息閑身不自如，長年借屋客中居。',64,'全唐诗/poet.song.186000.json','["歎息閑身不自如，長年借屋客中居。", "事多只爲人情熟，貧甚還因世法疎。", "兄弟候歸應有夢，交遊散去更無書。", "攢心萬感爭催老，白髮蕭騷欲滿梳。"]'),
('fe5d7109-a331-4289-8bd6-aef9ed23111a','拜尹和靖先生墓','高翥','宋','宋诗','song-poetry','','[]','和靖祠堂在半村，敬瞻遺像憶師門。',64,'全唐诗/poet.song.186000.json','["和靖祠堂在半村，敬瞻遺像憶師門。", "洛中雖去名猶重，吳下曾來道益尊。", "言立豈徒規後學，書存端可識真源。", "瓣香再拜公應鑒，自愧傳衣忝嫡孫。"]'),
('61c2b722-8627-4640-a707-ddac5549fe24','重陽述懷','高翥','宋','宋诗','song-poetry','','[]','年年客裏過佳期，時節難逢莫皺眉。',64,'全唐诗/poet.song.186000.json','["年年客裏過佳期，時節難逢莫皺眉。", "酒量且爲重九盡，杯行不必再三辭。", "登高興懶詩仍賦，懷古情深淚自垂。", "縱使西風落烏帽，黄花猶戀鬢邊絲。"]'),
('464823f2-e046-48f8-93c8-d42d4b4e69d8','歸來','高翥','宋','宋诗','song-poetry','','[]','歸來成倦客，隨分樂閑居。',48,'全唐诗/poet.song.186000.json','["歸來成倦客，隨分樂閑居。", "供佛換新水，課兒溫舊書。", "已荒三逕菊，且種一園蔬。", "來往多鄰舍，餘無長者車。"]'),
('3a16916b-c410-4fa4-884a-dc61fdb100d6','雜興','高翥','宋','宋诗','song-poetry','','[]','短帽輕盈出晚巒，兒童夾道競來看。',32,'全唐诗/poet.song.186000.json','["短帽輕盈出晚巒，兒童夾道競來看。", "老夫何足驚人眼，爲有猿猴把釣竿。"]'),
('3d19f236-7e36-4509-96f8-cab7967eca12','冬日書懷用正甫韵','高翥','宋','宋诗','song-poetry','','[]','慣將雙手託虛空，歲事雖窮道不窮。',64,'全唐诗/poet.song.186000.json','["慣將雙手託虛空，歲事雖窮道不窮。", "身健不知行路遠，心安還與在家同。", "客携酒至一樽綠，兄寄書來三印紅。", "看罷兄書斟客酒，閑愁無事置胸中。"]'),
('717fc40a-3b7b-48d1-b6d4-355f1403b07a','同周晉仙夜宿','高翥','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',32,'全唐诗/poet.song.186000.json','["□□□□□□□，□□□□□□□。", "更有詩人窮似我，夜深來共紙衾眠。"]'),
('f9edf47b-b94c-481a-b954-b4754bfdd6a0','句','高翥','宋','宋诗','song-poetry','','[]','早知花木今無主，不把豐碑累放翁。',16,'全唐诗/poet.song.186000.json','["早知花木今無主，不把豐碑累放翁。"]'),
('d412ce71-c35e-43a2-881a-c5c1536c6805','偈頌一百三十三首  其一','釋法薰','宋','宋诗','song-poetry','','[]','雲門一棒，高峰三拜。',24,'全唐诗/poet.song.186000.json','["雲門一棒，高峰三拜。", "一家不知一家，各自保守疆界。"]'),
('a59f35cc-c393-4603-b46d-70492aeeffbe','偈頌一百三十三首  其二','釋法薰','宋','宋诗','song-poetry','','[]','高峰方丈，內外皆空。',20,'全唐诗/poet.song.186000.json','["高峰方丈，內外皆空。", "垂鈎四海，只釣獰龍。"]'),
('e35385b8-fcb9-48be-b063-8acc7fdb567b','偈頌一百三十三首  其三','釋法薰','宋','宋诗','song-poetry','','[]','衲僧公驗，突出難辨。',20,'全唐诗/poet.song.186000.json','["衲僧公驗，突出難辨。", "手眼通身，只得一半。"]'),
('7426a6ad-0aa3-41b4-acdb-78379ac78720','偈頌一百三十三首  其四','釋法薰','宋','宋诗','song-poetry','','[]','有大聖人，出現世間。',46,'全唐诗/poet.song.186000.json','["有大聖人，出現世間。", "不言而化，無爲而治。", "節逢瑞慶，萬國歡聲。", "金輪永御三千界，玉葉長敷億萬春。"]'),
('1f00fabe-f56d-4a41-9620-f909fd37805d','偈頌一百三十三首  其五','釋法薰','宋','宋诗','song-poetry','','[]','晷運推移，日南長至。',34,'全唐诗/poet.song.186000.json','["晷運推移，日南長至。", "佛法世法，因行掉臂。", "高峰更囑諸人，第一莫眠冷地。"]'),
('e06e8531-28d6-45d8-962d-743bc10e68e4','偈頌一百三十三首  其六','釋法薰','宋','宋诗','song-poetry','','[]','一徑直，二周遮。',38,'全唐诗/poet.song.186000.json','["一徑直，二周遮。", "衲僧會得，萬別千差。", "庭前閑放目，春盡尚餘花，老胡不合過流沙。"]'),
('15b0f730-afc3-472f-9386-a78ac18babf8','偈頌一百三十三首  其七','釋法薰','宋','宋诗','song-poetry','','[]','善財採，文殊用。',34,'全唐诗/poet.song.186000.json','["善財採，文殊用。", "殺人活人，臨機變弄。", "直須親看海龍宮，莫看目前波浪湧。"]'),
('a76a05fb-df1b-421f-9531-d82357b55c7c','偈頌一百三十三首  其八','釋法薰','宋','宋诗','song-poetry','','[]','蓮花荷葉，意在言前。',20,'全唐诗/poet.song.186000.json','["蓮花荷葉，意在言前。", "神僊妙訣，父子不傳。"]'),
('39649ec7-64d8-467d-bb48-11cf1cbab9af','偈頌一百三十三首  其九','釋法薰','宋','宋诗','song-poetry','','[]','大道體寬，無易無難。',20,'全唐诗/poet.song.186000.json','["大道體寬，無易無難。", "相頭買帽，此土西天。"]'),
('a0c7ea68-fa3b-4cbd-b295-9a06609d4f7a','偈頌一百三十三首  其一○','釋法薰','宋','宋诗','song-poetry','','[]','五祖鵓鳩啼，當機直下提。',24,'全唐诗/poet.song.186000.json','["五祖鵓鳩啼，當機直下提。", "隔山尋蟻跡，能有幾人知。"]'),
('479c3664-767c-4b8d-9f00-6f52408f5003','偈頌一百三十三首  其一一','釋法薰','宋','宋诗','song-poetry','','[]','八月秋，何處熱。',30,'全唐诗/poet.song.186000.json','["八月秋，何處熱。", "杜衲僧，猶未瞥。", "三更半夜眼聞，天上如何揀月。"]'),
('498334ae-c27f-4058-81e0-f907e18aa9fc','偈頌一百三十三首  其一二','釋法薰','宋','宋诗','song-poetry','','[]','一日日，一時時，口如鼻，眼似眉。',32,'全唐诗/poet.song.186000.json','["一日日，一時時，口如鼻，眼似眉。", "左搓芒繩縛鬼子，倒將蒿箭射須彌。"]'),
('7b3cfb04-34f6-4011-80d2-72a0193ce255','偈頌一百三十三首  其一三','釋法薰','宋','宋诗','song-poetry','','[]','新年佛法，一切成現。',40,'全唐诗/poet.song.186000.json','["新年佛法，一切成現。", "明去暗來，三頭兩面。", "靈利衲僧，猶隔一線。", "更問如何，腦後拔箭。"]'),
('8a2f0ec4-c2e9-4688-82e9-97c0b3540811','偈頌一百三十三首  其一四','釋法薰','宋','宋诗','song-poetry','','[]','指天指地，小兒子戲。',20,'全唐诗/poet.song.186000.json','["指天指地，小兒子戲。", "無可慇懃，澆杓惡水。"]'),
('31d32d17-e9a8-4f9e-82b0-0b430f608758','偈頌一百三十三首  其一五','釋法薰','宋','宋诗','song-poetry','','[]','九夏安居，眉毛廝結。',24,'全唐诗/poet.song.186000.json','["九夏安居，眉毛廝結。", "一人發真歸源，十方虛空迸裂。"]'),
('75aa21a1-f884-48f9-bf98-9071287fca8d','偈頌一百三十三首  其一六','釋法薰','宋','宋诗','song-poetry','','[]','佛祖真機，曾無準的。',50,'全唐诗/poet.song.186000.json','["佛祖真機，曾無準的。", "鈎鎖連環，刀挑不出。", "石田有箇道處，未必諸人委悉。", "摩訶般若波羅蜜，甚深般若波羅蜜。"]'),
('f595fef2-07cb-41d2-96d8-7866655ad922','偈頌一百三十三首  其一七','釋法薰','宋','宋诗','song-poetry','','[]','東弗于逮，西瞿耶尼。',20,'全唐诗/poet.song.186000.json','["東弗于逮，西瞿耶尼。", "清清之水，遊鱼自迷。"]'),
('0b9198c7-e7e0-4b37-b88a-f89adf33841d','偈頌一百三十三首  其一八','釋法薰','宋','宋诗','song-poetry','','[]','庭開金菊宿根生，來雁新聞一兩聲。',32,'全唐诗/poet.song.186000.json','["庭開金菊宿根生，來雁新聞一兩聲。", "猶握金鞭問歸客，夜深誰共御街行。"]'),
('90364191-7b8b-4ec0-80e4-fc54450638ff','偈頌一百三十三首  其一九','釋法薰','宋','宋诗','song-poetry','','[]','東去亦是上座，西去亦是上座。',50,'全唐诗/poet.song.186000.json','["東去亦是上座，西去亦是上座。", "提水放火，看風使舵。", "七出八沒，儒雅風流。", "幾度黑風翻大海，何曾覆却釣魚舟。"]'),
('4a71cf02-919c-403c-9fc5-bfe907efd6e3','偈頌一百三十三首  其二○','釋法薰','宋','宋诗','song-poetry','','[]','老倒慈明爲指迷，釣絲絞水出群機。',32,'全唐诗/poet.song.186000.json','["老倒慈明爲指迷，釣絲絞水出群機。", "時人貪看蘆花白，不見沙鷗隔岸飛。"]'),
('75f02dd1-766c-4999-ad43-bd6c004334ea','偈頌一百三十三首  其二一','釋法薰','宋','宋诗','song-poetry','','[]','棒喝齊施，雷奔電掣。',36,'全唐诗/poet.song.186000.json','["棒喝齊施，雷奔電掣。", "本參事中，總沒交涉。", "沒交涉，有來由，昨夜三更失却牛。"]'),
('25c2d15d-a2be-4e5c-843e-5df714c2803c','偈頌一百三十三首  其二二','釋法薰','宋','宋诗','song-poetry','','[]','乳源言中藏劍戟，這僧姦裏放癡憨。',28,'全唐诗/poet.song.186000.json','["乳源言中藏劍戟，這僧姦裏放癡憨。", "西來的的意，斫額望扶桑。"]'),
('7e570e1e-cbf2-4fd7-b8da-97e532251325','偈頌一百三十三首  其二三','釋法薰','宋','宋诗','song-poetry','','[]','去却一，拈得七。',52,'全唐诗/poet.song.186000.json','["去却一，拈得七。", "通天大路，萬重鐵壁。", "楓橋心肝五臟，一時剖出。", "臭骨頭，信彩擲。", "百千萬種神通，只消道箇不必。"]'),
('15cd4cd1-7133-43dc-a93a-d9143fb06287','偈頌一百三十三首  其二四','釋法薰','宋','宋诗','song-poetry','','[]','雲月是同，溪山各異。',50,'全唐诗/poet.song.186000.json','["雲月是同，溪山各異。", "拽新羅與占波闘額，跛脚阿師猶落第二。", "東西南北，甚處得來。", "好是明明說，從教鴨聽雷。"]'),
('2cf4b634-52ff-4e42-bc9d-2f1fde3f64ce','偈頌一百三十三首  其二五','釋法薰','宋','宋诗','song-poetry','','[]','識得心，山岳沉。',38,'全唐诗/poet.song.186000.json','["識得心，山岳沉。", "握金成土，握土成金。", "脚後脚前，見成行貨。", "少室峰前，交點不過。"]'),
('e8e3e5aa-c670-4204-94b1-9c727c64dc47','偈頌一百三十三首  其二六','釋法薰','宋','宋诗','song-poetry','','[]','解語非干舌，能言不是聲。',24,'全唐诗/poet.song.186000.json','["解語非干舌，能言不是聲。", "斬新提活句，冬後一陽生。"]'),
('9f9eb705-4f69-4316-8a24-9b6a17084199','偈頌一百三十三首  其二七','釋法薰','宋','宋诗','song-poetry','','[]','一言道盡，却成兩橛。',20,'全唐诗/poet.song.186000.json','["一言道盡，却成兩橛。", "擊鼓陞堂，子承父業。"]'),
('7b8fcc14-dbd9-434f-abc0-a84a7531a5f3','偈頌一百三十三首  其二八','釋法薰','宋','宋诗','song-poetry','','[]','出一叢林，入一叢林。',22,'全唐诗/poet.song.186000.json','["出一叢林，入一叢林。", "不具參方眼，難透祖師心。"]'),
('0060c81e-c1f5-463d-a7d5-adab3b48c9b7','偈頌一百三十三首  其二九','釋法薰','宋','宋诗','song-poetry','','[]','秋風高，秋葉脫。',18,'全唐诗/poet.song.186000.json','["秋風高，秋葉脫。", "亂走衲僧，天涯海角。"]'),
('97511e35-fc42-4376-b4d8-58dbfb9f64e4','偈頌一百三十三首  其三○','釋法薰','宋','宋诗','song-poetry','','[]','觸目不會道，運足焉知步。',48,'全唐诗/poet.song.186000.json','["觸目不會道，運足焉知步。", "倒腹傾腸，翻成露布。", "石田頂戴諸人，爭敢絲毫錯悞。", "却憶王老師，不打這破鼓。"]'),
('bd343422-0f18-49ea-9f8f-6a714cee7638','偈頌一百三十三首  其三一','釋法薰','宋','宋诗','song-poetry','','[]','坦老勾賊破家，羅山就窠打劫。',26,'全唐诗/poet.song.186000.json','["坦老勾賊破家，羅山就窠打劫。", "勘證將來，未免髑髏敲磕。"]'),
('52f8cc0f-4ce8-4036-bef9-85ae77bee454','偈頌一百三十三首  其三二','釋法薰','宋','宋诗','song-poetry','','[]','達磨不會禪，夫子不識字。',24,'全唐诗/poet.song.186000.json','["達磨不會禪，夫子不識字。", "第一莫將來，將來不相似。"]'),
('b25d2463-3b82-4ee7-9b94-3f4b6471769b','偈頌一百三十三首  其三三','釋法薰','宋','宋诗','song-poetry','','[]','不是世間法，亦非西祖意。',36,'全唐诗/poet.song.186000.json','["不是世間法，亦非西祖意。", "晷運推移，日南長至。", "幽州江口石人，不道光陰虛棄。"]'),
('49b92610-0044-4fc1-a4a4-5d241c4e8643','偈頌一百三十三首  其三四','釋法薰','宋','宋诗','song-poetry','','[]','一不成一，二不成二。',30,'全唐诗/poet.song.186000.json','["一不成一，二不成二。", "喝水成水，敲骨出髓。", "眼有瞳人，色斯舉矣。"]'),
('6bb75e3b-2460-41e0-84ec-b061a8782e58','偈頌一百三十三首  其三五','釋法薰','宋','宋诗','song-poetry','','[]','無心亦無法，非法亦非心。',24,'全唐诗/poet.song.186000.json','["無心亦無法，非法亦非心。", "大勳不豎賞，柴扉草自深。"]'),
('c1fd2a13-3eeb-4e2b-8e34-3da7eceb7902','偈頌一百三十三首  其三六','釋法薰','宋','宋诗','song-poetry','','[]','通身無覓處，遍界不曾藏。',24,'全唐诗/poet.song.186000.json','["通身無覓處，遍界不曾藏。", "閉目中秋坐，却笑月無光。"]'),
('f3d74ae4-338a-4c2b-8ab9-54c658678a2e','偈頌一百三十三首  其三七','釋法薰','宋','宋诗','song-poetry','','[]','大地人人具眼，明星夜夜流輝。',42,'全唐诗/poet.song.186000.json','["大地人人具眼，明星夜夜流輝。", "瞿曇不著便，失却一雙眉。", "後代兒孫那得知，一年一度亂針錐。"]'),
('b50059a1-abe0-46bd-aac6-ae1f08c57795','偈頌一百三十三首  其三八','釋法薰','宋','宋诗','song-poetry','','[]','院無大小，衆無多寡。',42,'全唐诗/poet.song.186000.json','["院無大小，衆無多寡。", "有箇折脚鐺兒，要人提上挈下。", "不墮功勳，不觸風化，千里追風看良馬。"]'),
('0daa77de-f201-4eca-b641-4ca3f713ec47','偈頌一百三十三首  其三九','釋法薰','宋','宋诗','song-poetry','','[]','透過牢關，縱橫獨步。',24,'全唐诗/poet.song.186000.json','["透過牢關，縱橫獨步。", "脚頭到處生涯，誰道此山無路。"]'),
('d7dd4100-d4e2-4d58-8687-87dae0ad4e8f','偈頌一百三十三首  其四○','釋法薰','宋','宋诗','song-poetry','','[]','鍾山乍住，百事隨宜。',34,'全唐诗/poet.song.186000.json','["鍾山乍住，百事隨宜。", "無可不可，左之右之。", "些子不通方處，料想諸人未知。"]'),
('7d70fbf4-2a1a-48a4-a051-84ab1ff34bbd','偈頌一百三十三首  其四一','釋法薰','宋','宋诗','song-poetry','','[]','舉古舉今，和泥合水。',20,'全唐诗/poet.song.186000.json','["舉古舉今，和泥合水。", "說心說性，畫虎成狸。"]'),
('daa4b465-49a3-4776-8fa4-6aec5d683bf5','偈頌一百三十三首  其四二','釋法薰','宋','宋诗','song-poetry','','[]','石中有玉，沙裏無油。',32,'全唐诗/poet.song.186000.json','["石中有玉，沙裏無油。", "德山臨濟，未出常流。", "却憶寒山子，時臨古渡頭。"]'),
('3daac732-1d7b-434e-af77-e7dffa444e2c','偈頌一百三十三首  其四三','釋法薰','宋','宋诗','song-poetry','','[]','法爾不爾，如何指南。',34,'全唐诗/poet.song.186000.json','["法爾不爾，如何指南。", "古佛露柱，晝夜交參。", "蔣山雖恁麽道，西天有人不甘。"]'),
('d220a37e-90d1-445d-8f1d-af5b41c65f87','偈頌一百三十三首  其四四','釋法薰','宋','宋诗','song-poetry','','[]','四月十五結，虛空遭火爇。',32,'全唐诗/poet.song.186000.json','["四月十五結，虛空遭火爇。", "此土與西天，同途不同轍，鎮州蘿蔔并州鐵。"]'),
('dc6d9dae-a414-4ed2-9514-f07252822538','偈頌一百三十三首  其四五','釋法薰','宋','宋诗','song-poetry','','[]','今朝五月五，石田無剩語。',32,'全唐诗/poet.song.186000.json','["今朝五月五，石田無剩語。", "打破鬼門關，三更日卓午，明眼衲僧迷却路。"]'),
('e2f0d65d-5eb4-425a-ba03-4b81166eb714','偈頌一百三十三首  其四六','釋法薰','宋','宋诗','song-poetry','','[]','深山巖崖中，迥絕無人處。',48,'全唐诗/poet.song.186000.json','["深山巖崖中，迥絕無人處。", "箇事分明，十成顯露。", "擬著便乖張，不擬成差互。", "趙州親見南泉，百丈曾參馬祖。"]'),
('dcdeceeb-3931-489a-abc3-de8e1d4cb60a','偈頌一百三十三首  其四七','釋法薰','宋','宋诗','song-poetry','','[]','田地穩密，關竅玲瓏。',32,'全唐诗/poet.song.186000.json','["田地穩密，關竅玲瓏。", "識得無寒暑處，任他寒暑相攻，箇裏同途轍不同。"]'),
('ba666308-0537-449c-a816-97ba960343ae','偈頌一百三十三首  其四八','釋法薰','宋','宋诗','song-poetry','','[]','長沙見處雖親用處粗，仰山口裏相呼肚裏狡。',34,'全唐诗/poet.song.186000.json','["長沙見處雖親用處粗，仰山口裏相呼肚裏狡。", "灼然好箇大蟲，可惜已傷牙爪。"]'),
('1acae909-e642-4794-8131-85aa01bb0bcc','偈頌一百三十三首  其四九','釋法薰','宋','宋诗','song-poetry','','[]','焦磚打著連底凍，赤眼撞著火柴頭。',32,'全唐诗/poet.song.186000.json','["焦磚打著連底凍，赤眼撞著火柴頭。", "將軍但得嘉聲在，何必榮封萬戶侯。"]'),
('58964e98-5f99-4cb3-8e39-0398b173cf1d','偈頌一百三十三首  其五○','釋法薰','宋','宋诗','song-poetry','','[]','見聞覺知，行住坐卧。',32,'全唐诗/poet.song.186000.json','["見聞覺知，行住坐卧。", "眨上眉毛，早已蹉過。", "赤脚唱山歌，路上無人和。"]'),
('4b67ed8e-9486-4666-9266-4c18fb38591d','偈頌一百三十三首  其五一','釋法薰','宋','宋诗','song-poetry','','[]','直下是，直下是。',20,'全唐诗/poet.song.186000.json','["直下是，直下是。", "鈍鳥不離窠，良駒千萬里。"]'),
('101eeab3-d6bb-433c-8bbb-0e1f70c10562','偈頌一百三十三首  其五二','釋法薰','宋','宋诗','song-poetry','','[]','身心一如，身外無餘。',20,'全唐诗/poet.song.186000.json','["身心一如，身外無餘。", "長安雖樂，不是久居。"]'),
('7889177f-69ad-4ea8-9abb-c9af52a5a154','偈頌一百三十三首  其五三','釋法薰','宋','宋诗','song-poetry','','[]','禪非意想，道絕功勳。',20,'全唐诗/poet.song.186000.json','["禪非意想，道絕功勳。", "青天白日，有迷路人。"]'),
('ffb0695e-fde2-470f-8719-b6659142a399','偈頌一百三十三首  其五四','釋法薰','宋','宋诗','song-poetry','','[]','兩日晴，三日雨。',18,'全唐诗/poet.song.186000.json','["兩日晴，三日雨。", "衲僧皮草，無曬㫰處。"]'),
('846ec187-ac17-48c9-a6f3-20286766f452','偈頌一百三十三首  其五五','釋法薰','宋','宋诗','song-poetry','','[]','言詮不及處，文彩未生時。',38,'全唐诗/poet.song.186000.json','["言詮不及處，文彩未生時。", "電光石火，猶尚遲遲。", "直下橫身擔荷得，藕絲牽動五須彌。"]'),
('b4a87ef4-080f-4494-8923-a559fdd968c4','偈頌一百三十三首  其五六','釋法薰','宋','宋诗','song-poetry','','[]','以大圓覺，無繩自縛。',56,'全唐诗/poet.song.186000.json','["以大圓覺，無繩自縛。", "爲我伽藍，凡聖交參。", "身心安居，換水養魚。", "平等性智，落在第二。", "莫教辜負兩莖眉，九十日從今日始。"]'),
('0ae883cd-cbc2-4a89-94e3-7e6efff41c5c','偈頌一百三十三首  其五七','釋法薰','宋','宋诗','song-poetry','','[]','明如日，黑如漆。',56,'全唐诗/poet.song.186000.json','["明如日，黑如漆。", "一犬吠虛，千猱啀寶。", "山僧有口，多時掛壁。", "却煩拄杖子，與諸人通箇消息。", "東土衲子心粗，西天蠟人淚滴。"]'),
('bf2db94f-ba69-4160-9ecf-eab819298ec1','偈頌一百三十三首  其五八','釋法薰','宋','宋诗','song-poetry','','[]','今朝端午節，鍾山强饒舌。',38,'全唐诗/poet.song.186000.json','["今朝端午節，鍾山强饒舌。", "家無白澤之圖，妖怪自然消滅。", "滅，滅，夜行一任貪明月。"]'),
('4120e1a0-e3e0-430d-84c0-737f4a55b9c2','偈頌一百三十三首  其五九','釋法薰','宋','宋诗','song-poetry','','[]','有祖以來，無人奈何。',28,'全唐诗/poet.song.186000.json','["有祖以來，無人奈何。", "德山臨濟，特地干戈。", "水到滄溟不是波。"]'),
('5f50ab3d-ef66-478b-98c6-89720db4a7ca','偈頌一百三十三首  其六○','釋法薰','宋','宋诗','song-poetry','','[]','未過蔣山關，須過蔣山關。',62,'全唐诗/poet.song.186000.json','["未過蔣山關，須過蔣山關。", "過得蔣山關，呼喚不回，牢籠不住。", "平地鼓洪波，青天撒白雨。", "石田笑嘻嘻，未敢輕相許。", "射虎不真，徒勞沒羽。"]'),
('a4e40d5c-70d8-4767-82a0-1a5afa37ed1a','偈頌一百三十三首  其六一','釋法薰','宋','宋诗','song-poetry','','[]','平如鏡，爛如泥。',32,'全唐诗/poet.song.186000.json','["平如鏡，爛如泥。", "迷則迷於悟，悟則悟於迷。", "禹力不到處，河聲流向西。"]'),
('d332a7a3-50ef-4128-b38d-a6703ac66172','偈頌一百三十三首  其六二','釋法薰','宋','宋诗','song-poetry','','[]','江南成橘，江北成枳。',23,'全唐诗/poet.song.186000.json','["江南成橘，江北成枳。", "還有優劣也無，具眼者辨取。"]');
